INSERT INTO `wp_comments` (`comment_ID`, `comment_post_ID`, `comment_author`, `comment_author_email`, `comment_author_url`, `comment_author_IP`, `comment_date`, `comment_date_gmt`, `comment_content`, `comment_karma`, `comment_approved`, `comment_agent`, `comment_type`, `comment_parent`, `user_id`) VALUES
(1, 1, '一位WordPress评论者', 'wapuu@wordpress.example', 'https://wordpress.org/', '', '2017-04-27 15:43:00', '2017-04-27 07:43:00', '嗨，这是一条评论。\n要开始审核、编辑及删除评论，请访问仪表盘的“评论”页面。\n评论者头像来自<a href="https://gravatar.com">Gravatar</a>。', 0, '1', '', '', 0, 0),
(2, 213, '老杨', 'i@yangyongquan.com', 'http://yangyongquan.com', '211.64.154.95', '2017-05-04 09:18:11', '2017-05-04 01:18:11', '保密检查中，图片如果不是中文的应该如何处理？', 0, '1', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/58.0.3029.81 Safari/537.36', '', 0, 0),
(3, 243, 'baomi', 'i@yangyongquan.com', '', '211.64.154.248', '2019-10-16 10:58:58', '2019-10-16 02:58:58', '这些信息都是保密的吗？', 0, '1', 'Mozilla/5.0 (Windows NT 10.0; WOW64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/61.0.3163.79 Safari/537.36 Maxthon/5.2.7.3000', '', 0, 1),
(4, 241, 'baomi', 'i@yangyongquan.com', '', '211.64.154.248', '2019-10-16 10:59:50', '2019-10-16 02:59:50', '安全保密是大事', 0, '1', 'Mozilla/5.0 (Windows NT 10.0; WOW64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/61.0.3163.79 Safari/537.36 Maxthon/5.2.7.3000', '', 0, 1);
