INSERT INTO `wp_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES
(1, 1, '2017-04-27 15:43:00', '2017-04-27 07:43:00', '欢迎使用WordPress。这是您的第一篇文章。编辑或删除它，然后开始写作吧！', '世界，您好！', '', 'publish', 'open', 'open', '', 'hello-world', '', '', '2017-04-27 15:43:00', '2017-04-27 07:43:00', '', 0, 'http://bm.yangyongquan.com/?p=1', 0, 'post', '', 1),
(2, 1, '2017-04-27 15:43:00', '2017-04-27 07:43:00', '这是一个范例页面。它和博客文章不同，因为它的页面位置是固定的，同时会显示于您的博客导航栏（大多数主题中）。大多数人会新增一个“关于”页面向访客介绍自己。它可能类似下面这样：\n\n<blockquote>我是一个很有趣的人，我创建了工厂和庄园。并且，顺便提一下，我的妻子也很好。</blockquote>\n\n……或下面这样：\n\n<blockquote>XYZ装置公司成立于1971年，公司成立以来，我们一直向市民提供高品质的装置。我们位于北京市，有超过2,000名员工，对北京市有着相当大的贡献。</blockquote>\n\n作为一个新的WordPress用户，您可以前往<a href="http://bm.yangyongquan.com/wp-admin/">您的仪表盘</a>删除这个页面，并建立属于您的全新内容。祝您使用愉快！', '示例页面', '', 'publish', 'closed', 'open', '', 'sample-page', '', '', '2017-04-27 15:43:00', '2017-04-27 07:43:00', '', 0, 'http://bm.yangyongquan.com/?page_id=2', 0, 'page', '', 0),
(7, 1, '2017-04-27 16:24:57', '2017-04-27 08:24:57', '<div id="newest" class="right_cont" data-pjax-container="">\r\n<div class="right_cont_body" tabindex="1">\r\n<div class="news_description ">\r\n<div class="description markdown_views">\r\n\r\n虚拟现实 (VR) 游戏成为了游戏开发的一个新趋势，唤起了每位创新型开发人员的热情。 在这个全新的领域中，独一无二的游戏机制具有无限的可能。 然而，随着越来越多的游戏开发人员由传统游戏开发迁移至虚拟现实，有一个问题正日益限制创新的自由。 恶心，业内称之为“虚拟现实眩晕” (VRS)，是目前虚拟现实游戏开发人员面临的最大障碍，这一点并不奇怪：它是技术新手掌握该技术的最大障碍之一。\r\n\r\n作为独立开发人员，我们在 Well Told Entertainment* 公司时发现，用户体验设计是创建令人满意的虚拟现实体验的重中之重。 不管是需要保持稳定的帧速率，还是提高用户在虚拟世界中的舒适度，我们的目标是，确保所有人——从虚拟现实领域的新手到经验丰富的玩家——都有极致的体验。 但是该领域缺少专家。 在虚拟现实游戏设计公司工作一年后，我们开始逐渐了解如何帮助各种用户掌握虚拟现实技术基础，我们想和大家分享一些代码、着色技术和设计原则，让更多的人体验制作精良的虚拟现实技术。\r\n<strong>Well Told Entertainment* 和虚拟现实学习</strong>\r\n我们对虚拟现实的探索源于对远距传动中的交替运动方案非常好奇。 除了严格的空间定位体验，虚拟现实用户过去和现在都在追求通过更独特更智能的方式逃离空间定位，不必“自杀”或忍受仿佛漂在海上似的眩晕感。 在 2016 年年初，我们有幸见证了新一轮的虚拟现实游戏浪潮，但是，当在查看了 VRS 报告后，我们和其他虚拟现实新手一样充满了怀疑。 当我们通过论坛得知远距传动可以解决这个问题时，非常期待能够试玩 The Lab*、Rec Room* 和 Budget Cuts*等游戏。 尽管这些游戏本身提供出色的虚拟现实体验，而且远距传动对 VRS 比较有效，但是我们仍旧觉得有什么不对。 最后，问题可以归结为虚拟现实中的远距传动破坏了浸入式体验（尤其和故事情节不相关时）。 当我们了解了虚拟现实最卓越的品质就是真实的浸入式体验后，我们开始研究如何为动态解决方案添砖加瓦。\r\n\r\n和其他有强烈求知欲的开发人员一样，我们通过详细了解 Reddit* 论坛开始入门。 （r/vive、r/virtualreality 和 r/oculus 中有许多卓越开发人员分享他们在独立开发领域取得的进步。 在我们看来，这是调查、寻找创新型解决方案的最佳起点。） 2016 年夏天，动作方案成为了最热门的话题，我们注意到许多开发人员开始在线分享他们的意见和演示。 我阅读了一些技术，如攀登方案，该方案通过控制器移动角色，挥动手臂时角色前进，甚至可以将控制器放置于腰带环上，当您跳跃时，人物也会跟着前进（相当于一台计步器）。 基于调查，我们找到了解决问题的独特方法，并形成了自己的假设。 经过一个月的随机测试后（测试由 Vincent Wing 执行，他是一名可靠的开发人员），我们开始取得进展。 基于研究，我们找到了在不影响动态移动和交互式游戏体验的同时，对抗 VRS 的几个最佳实践，如下所示。\r\n<strong>注重虚拟现实中的用户体验</strong>\r\n六月底，我和我的联合创始人 Sam Warner 赶往 Playa Vista 参加了由交互设计协会举办的虚拟现实活动。 尽管活动的主题是虚拟现实，但是在众多参会者中，我们是唯一的非专业 UX 设计师，这对我们之间的交流造成了一点阻碍。 但是，我们非常高兴能在 Andrew Cochrane 的演示中发现极大的价值，Andrew Cochrane 是一名演讲嘉宾，也是一名新媒体总监。 Cochrane 专注于分享他在虚拟现实内容创新方面的见解，当晚，我们根据他的见解强化了我们的虚拟现实设计方法。\r\n\r\n大多数研究虚拟现实的开发人员都有游戏开发或电影制作背景，或来自主要围绕故事叙述的媒体。 Cochrane 详细虚拟现实技术不需要叙述故事， 相反，虚拟现实是一个体验性媒体，身处其中的每个人都是体验设计师。 在游戏或电影中，设计师能够根据用户的需求更改故事， 他们遵循故事表演的结构，使用剪辑和特效吸引用户的注意，并能激起他们的情绪响应。 但是，虚拟现实的目标是为观众提供完全的浸入式体验，以激起他们的情绪响应， 因此，必须确保用户在虚拟空间中有较强的临场感，这点非常重要。 和传统介质相比，开发虚拟现实要求浸入式体验效果越强越好，这个要求使开发人员承担了更大的责任。 根据我们的移动设计经验，如果您想减少浸入式体验中断、避免虚拟现实眩晕，我们的建议是为玩家提供强大的可视参考。\r\n<strong>空间定向</strong>\r\n为了在虚拟现实中创建出色的临场感，第一步需要让玩家熟悉周围的环境。 尽管移动被认为是引起 VRS 的主要原因，但是戴上头盔后，便会产生眩晕，因为玩家实际戴上了一个眼罩。 遮住双眼对人的平衡性会产生很大的影响。 请您试试这个：站起来并闭上眼睛。 尽管最初看起来非常简单，但是许多人在短时间内便开始站不稳， 有人甚至摔倒了。 这是因为平衡极度依赖视觉参考和深度感知。 视觉消失后，身体便开始通过主体感觉维持平衡，每个人主体感觉的能力各不相同。 人们在虚拟世界中开启奇妙的游戏体验前，较强的空间感知是必不可少的。\r\n</div>\r\n</div>\r\n</div>\r\n</div>', '利用用户体验设计对抗虚拟现实眩晕', '', 'publish', 'open', 'open', '', '%e5%88%a9%e7%94%a8%e7%94%a8%e6%88%b7%e4%bd%93%e9%aa%8c%e8%ae%be%e8%ae%a1%e5%af%b9%e6%8a%97%e8%99%9a%e6%8b%9f%e7%8e%b0%e5%ae%9e%e7%9c%a9%e6%99%95', '', '', '2017-04-27 16:24:57', '2017-04-27 08:24:57', '', 0, 'http://bm.yangyongquan.com/?p=7', 0, 'post', '', 0),
(8, 1, '2017-04-27 16:24:57', '2017-04-27 08:24:57', '<div id="newest" class="right_cont" data-pjax-container="">\r\n<div class="right_cont_body" tabindex="1">\r\n<div class="news_description ">\r\n<div class="description markdown_views">\r\n\r\n虚拟现实 (VR) 游戏成为了游戏开发的一个新趋势，唤起了每位创新型开发人员的热情。 在这个全新的领域中，独一无二的游戏机制具有无限的可能。 然而，随着越来越多的游戏开发人员由传统游戏开发迁移至虚拟现实，有一个问题正日益限制创新的自由。 恶心，业内称之为“虚拟现实眩晕” (VRS)，是目前虚拟现实游戏开发人员面临的最大障碍，这一点并不奇怪：它是技术新手掌握该技术的最大障碍之一。\r\n\r\n作为独立开发人员，我们在 Well Told Entertainment* 公司时发现，用户体验设计是创建令人满意的虚拟现实体验的重中之重。 不管是需要保持稳定的帧速率，还是提高用户在虚拟世界中的舒适度，我们的目标是，确保所有人——从虚拟现实领域的新手到经验丰富的玩家——都有极致的体验。 但是该领域缺少专家。 在虚拟现实游戏设计公司工作一年后，我们开始逐渐了解如何帮助各种用户掌握虚拟现实技术基础，我们想和大家分享一些代码、着色技术和设计原则，让更多的人体验制作精良的虚拟现实技术。\r\n<strong>Well Told Entertainment* 和虚拟现实学习</strong>\r\n我们对虚拟现实的探索源于对远距传动中的交替运动方案非常好奇。 除了严格的空间定位体验，虚拟现实用户过去和现在都在追求通过更独特更智能的方式逃离空间定位，不必“自杀”或忍受仿佛漂在海上似的眩晕感。 在 2016 年年初，我们有幸见证了新一轮的虚拟现实游戏浪潮，但是，当在查看了 VRS 报告后，我们和其他虚拟现实新手一样充满了怀疑。 当我们通过论坛得知远距传动可以解决这个问题时，非常期待能够试玩 The Lab*、Rec Room* 和 Budget Cuts*等游戏。 尽管这些游戏本身提供出色的虚拟现实体验，而且远距传动对 VRS 比较有效，但是我们仍旧觉得有什么不对。 最后，问题可以归结为虚拟现实中的远距传动破坏了浸入式体验（尤其和故事情节不相关时）。 当我们了解了虚拟现实最卓越的品质就是真实的浸入式体验后，我们开始研究如何为动态解决方案添砖加瓦。\r\n\r\n和其他有强烈求知欲的开发人员一样，我们通过详细了解 Reddit* 论坛开始入门。 （r/vive、r/virtualreality 和 r/oculus 中有许多卓越开发人员分享他们在独立开发领域取得的进步。 在我们看来，这是调查、寻找创新型解决方案的最佳起点。） 2016 年夏天，动作方案成为了最热门的话题，我们注意到许多开发人员开始在线分享他们的意见和演示。 我阅读了一些技术，如攀登方案，该方案通过控制器移动角色，挥动手臂时角色前进，甚至可以将控制器放置于腰带环上，当您跳跃时，人物也会跟着前进（相当于一台计步器）。 基于调查，我们找到了解决问题的独特方法，并形成了自己的假设。 经过一个月的随机测试后（测试由 Vincent Wing 执行，他是一名可靠的开发人员），我们开始取得进展。 基于研究，我们找到了在不影响动态移动和交互式游戏体验的同时，对抗 VRS 的几个最佳实践，如下所示。\r\n<strong>注重虚拟现实中的用户体验</strong>\r\n六月底，我和我的联合创始人 Sam Warner 赶往 Playa Vista 参加了由交互设计协会举办的虚拟现实活动。 尽管活动的主题是虚拟现实，但是在众多参会者中，我们是唯一的非专业 UX 设计师，这对我们之间的交流造成了一点阻碍。 但是，我们非常高兴能在 Andrew Cochrane 的演示中发现极大的价值，Andrew Cochrane 是一名演讲嘉宾，也是一名新媒体总监。 Cochrane 专注于分享他在虚拟现实内容创新方面的见解，当晚，我们根据他的见解强化了我们的虚拟现实设计方法。\r\n\r\n大多数研究虚拟现实的开发人员都有游戏开发或电影制作背景，或来自主要围绕故事叙述的媒体。 Cochrane 详细虚拟现实技术不需要叙述故事， 相反，虚拟现实是一个体验性媒体，身处其中的每个人都是体验设计师。 在游戏或电影中，设计师能够根据用户的需求更改故事， 他们遵循故事表演的结构，使用剪辑和特效吸引用户的注意，并能激起他们的情绪响应。 但是，虚拟现实的目标是为观众提供完全的浸入式体验，以激起他们的情绪响应， 因此，必须确保用户在虚拟空间中有较强的临场感，这点非常重要。 和传统介质相比，开发虚拟现实要求浸入式体验效果越强越好，这个要求使开发人员承担了更大的责任。 根据我们的移动设计经验，如果您想减少浸入式体验中断、避免虚拟现实眩晕，我们的建议是为玩家提供强大的可视参考。\r\n<strong>空间定向</strong>\r\n为了在虚拟现实中创建出色的临场感，第一步需要让玩家熟悉周围的环境。 尽管移动被认为是引起 VRS 的主要原因，但是戴上头盔后，便会产生眩晕，因为玩家实际戴上了一个眼罩。 遮住双眼对人的平衡性会产生很大的影响。 请您试试这个：站起来并闭上眼睛。 尽管最初看起来非常简单，但是许多人在短时间内便开始站不稳， 有人甚至摔倒了。 这是因为平衡极度依赖视觉参考和深度感知。 视觉消失后，身体便开始通过主体感觉维持平衡，每个人主体感觉的能力各不相同。 人们在虚拟世界中开启奇妙的游戏体验前，较强的空间感知是必不可少的。\r\n</div>\r\n</div>\r\n</div>\r\n</div>', '利用用户体验设计对抗虚拟现实眩晕', '', 'inherit', 'closed', 'closed', '', '7-revision-v1', '', '', '2017-04-27 16:24:57', '2017-04-27 08:24:57', '', 7, 'http://bm.yangyongquan.com/2017/04/27/7-revision-v1/', 0, 'revision', '', 0),
(9, 1, '2017-04-27 16:28:18', '2017-04-27 08:28:18', '<div id="container" class="area">\r\n<div class="content-wrapper grid-675">\r\n<div class="content-box clear">\r\n<div id="contentText" class="text clear">\r\n<div>\r\n\r\n新华社北京4月26日电 中共中央政治局4月25日下午就维护国家金融安全进行第四十次集体学习。中共中央总书记习近平在主持学习时强调，金融安全是国家安全的重要组成部分，是经济平稳健康发展的重要基础。维护金融安全，是关系我国经济社会发展全局的一件带有战略性、根本性的大事。金融活，经济活；金融稳，经济稳。必须充分认识金融在经济发展和社会生活中的重要地位和作用，切实把维护金融安全作为治国理政的一件大事，扎扎实实把金融工作做好。\r\n\r\n这次中央政治局集体学习，由有关负责同志结合各自业务领域和工作实际介绍情况。中国人民银行行长周小川就加强宏观调控、保障金融安全，中国银监会主席郭树清就化解银行体系风险、维护金融稳定，中国证监会主席刘士余就资本市场发展与风险管理，中国保监会副主席陈文辉就回归风险保障、强化保险监督、守住维护金融安全底线谈了认识和体会。\r\n\r\n中央政治局各位同志听取了他们的发言，并就有关问题进行了讨论。\r\n\r\n习近平在主持学习时发表了讲话。他指出，金融是现代经济的核心。保持经济平稳健康发展，一定要把金融搞好。改革开放以来，我们对金融工作和金融安全始终是高度重视的，我国金融业发展取得巨大成就，金融成为资源配置和宏观调控的重要工具，成为推动经济社会发展的重要力量。党的十八大以来，我们反复强调要把防控金融风险放到更加重要的位置，牢牢守住不发生系统性风险底线，采取一系列措施加强金融监管，防范和化解金融风险，维护金融安全和稳定，把住了发展大势。随着金融改革不断深化，金融体系、金融市场、金融监管和调控体系日益完善，金融机构实力大大增强，我国已成为重要的世界金融大国。\r\n\r\n习近平强调，准确判断风险隐患是保障金融安全的前提。总体看，我国金融形势是良好的，金融风险是可控的。同时，在国际国内经济下行压力因素综合影响下，我国金融发展面临不少风险和挑战。在经济全球化深入发展的今天，金融危机外溢性突显，国际金融风险点仍然不少。一些国家的货币政策和财政政策调整形成的风险外溢效应，有可能对我国金融安全形成外部冲击。对存在的金融风险点，我们一定要胸中有数，增强风险防范意识，未雨绸缪，密切监测，准确预判，有效防范，不忽视一个风险，不放过一个隐患。\r\n\r\n习近平指出，维护金融安全，要坚持底线思维，坚持问题导向，在全面做好金融工作基础上，着力深化金融改革，加强金融监管，科学防范风险，强化安全能力建设，不断提高金融业竞争能力、抗风险能力、可持续发展能力，坚决守住不发生系统性金融风险底线。发展金融业需要学习借鉴外国有益经验，但必须立足国情，从我国实际出发，准确把握我国金融发展特点和规律，不能照抄照搬。\r\n\r\n习近平就维护金融安全提出6项任务。一是深化金融改革，完善金融体系，推进金融业公司治理改革，强化审慎合规经营理念，推动金融机构切实承担起风险管理责任，完善市场规则，健全市场化、法治化违约处置机制。二是加强金融监管，统筹监管系统重要性金融机构，统筹监管金融控股公司和重要金融基础设施，统筹负责金融业综合统计，确保金融系统良性运转，确保管理部门把住重点环节，确保风险防控耳聪目明，形成金融发展和监管强大合力，补齐监管短板，避免监管空白。三是采取措施处置风险点，着力控制增量，积极处置存量，打击逃废债行为，控制好杠杆率，加大对市场违法违规行为打击力度，重点针对金融市场和互联网金融开展全面摸排和查处。四是为实体经济发展创造良好金融环境，疏通金融进入实体经济的渠道，积极规范发展多层次资本市场，扩大直接融资，加强信贷政策指引，鼓励金融机构加大对先进制造业等领域的资金支持，推进供给侧结构性改革。五是提高领导干部金融工作能力，领导干部特别是高级干部要努力学习金融知识，熟悉金融业务，把握金融规律，既要学会用金融手段促进经济社会发展，又要学会防范和化解金融风险，强化监管意识，提高监管效率。六是加强党对金融工作的领导，坚持党中央集中统一领导，完善党领导金融工作的体制机制，加强制度化建设，完善定期研究金融发展战略、分析金融形势、决定金融方针政策的工作机制，提高金融决策科学化水平。金融部门要按照职能分工，负起责任。地方各级党委和政府要按照党中央决策部署，做好本地区金融发展和稳定工作，做到守土有责，形成全国一盘棋的金融风险防控格局。（完）\r\n\r\n<script type="text/javascript">// <![CDATA[\r\nmedia_span_url(''http://news.xinhuanet.com/politics/2017-04/26/c_1120879349.htm'')\r\n//]]></script></div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>', '习近平：做好金融工作 维护金融安全', '', 'publish', 'open', 'open', '', '%e4%b9%a0%e8%bf%91%e5%b9%b3%ef%bc%9a%e5%81%9a%e5%a5%bd%e9%87%91%e8%9e%8d%e5%b7%a5%e4%bd%9c-%e7%bb%b4%e6%8a%a4%e9%87%91%e8%9e%8d%e5%ae%89%e5%85%a8', '', '', '2017-04-27 16:28:18', '2017-04-27 08:28:18', '', 0, 'http://bm.yangyongquan.com/?p=9', 0, 'post', '', 0),
