(237, 1, '2019-10-16 10:22:50', '2019-10-16 02:22:50', '<!-- wp:paragraph -->\n<p><strong>西北大学研究生招生考试试题保密责任书</strong><strong></strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>（命题教师）</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:table -->\n<table class="wp-block-table"><tbody><tr><td>姓名</td><td>&nbsp;</td><td>性别</td><td>&nbsp;</td><td>出生年月</td><td>&nbsp;</td></tr><tr><td>职称</td><td>&nbsp;</td><td>政治面貌</td><td>&nbsp;</td><td>手机号码</td><td>&nbsp;</td></tr><tr><td>单位名称</td><td>&nbsp;</td><td>职务</td><td>&nbsp;</td></tr><tr><td>家庭住址</td><td>&nbsp;</td></tr><tr><td>参与本次命题的科目代码及名称</td><td>&nbsp;科目代码：&nbsp;科目名称： &nbsp;</td></tr><tr><td>本人对保密工作要求的确认</td><td>本人作为研究生招生考试命题教师，对所命制科目试题安全负主要责任。在学习国家教育考试的有关保密规定后，已知晓《2019年全国硕士研究生招生工作管理规定》中关于试题的<strong>“过失泄密和故意泄密行为均须承担刑事责任”</strong>。本人愿意并保证遵守国家有关保密工作的要求，承诺不泄露该科目试题有关的任何内容。<strong></strong><strong>&nbsp;</strong>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;本人签字： &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;年 &nbsp;&nbsp;月 &nbsp;&nbsp;日</td></tr><tr><td>试题命制领导小组组长意见</td><td><strong>同意聘任</strong><strong></strong>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;组长签字： &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;年 &nbsp;&nbsp;月 &nbsp;&nbsp;日</td></tr></tbody></table>\n<!-- /wp:table -->\n\n<!-- wp:paragraph -->\n<p><strong>西北大学研究生招生考试试题保密责任书</strong><strong></strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>（试题命制领导小组组长）</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:table -->\n<table class="wp-block-table"><tbody><tr><td>姓名</td><td>&nbsp;</td><td>性别</td><td>&nbsp;</td><td>出生年月</td><td>&nbsp;</td></tr><tr><td>职称</td><td>&nbsp;</td><td>政治面貌</td><td>&nbsp;</td><td>手机号码</td><td>&nbsp;</td></tr><tr><td>单位名称</td><td>&nbsp;</td><td>职务</td><td>&nbsp;</td></tr><tr><td>家庭住址</td><td>&nbsp;</td></tr><tr><td>本人对保密工作要求的确认</td><td>本人作为本单位研究生招生考试试题命制领导小组组长，对自命题试题安全负领导责任。在学习国家教育考试的有关保密规定后，已知晓《2019年全国硕士研究生招生工作管理规定》中关于试题的<strong>“过失泄密和故意泄密行为均须承担刑事责任”</strong>。本人愿意并保证遵守国家有关保密工作的要求，承诺不泄露该科目试题有关的任何内容。&nbsp;本人签字： &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;年 &nbsp;&nbsp;月 &nbsp;&nbsp;日</td></tr><tr><td>学校意见</td><td><strong>&nbsp;</strong><strong>同意聘任</strong><strong></strong><strong>&nbsp;</strong>研究生院负责人签章： &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;年 &nbsp;&nbsp;月 &nbsp;&nbsp;日</td></tr></tbody></table>\n<!-- /wp:table -->', '保密责任书', '', 'publish', 'open', 'open', '', '%e4%bf%9d%e5%af%86%e8%b4%a3%e4%bb%bb%e4%b9%a6', '', '', '2019-10-16 10:22:50', '2019-10-16 02:22:50', '', 0, 'http://bm.yangyongquan.com/?p=237', 0, 'post', '', 0);
INSERT INTO `wp_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES
(156, 1, '2017-04-27 16:40:40', '2017-04-27 08:40:40', '保密法律法规知识竞赛试题\r\n\r\n&nbsp;\r\n\r\n一、单项选择题（共20题，每题1.5分）\r\n\r\n1、《中华人民共和国保守国家秘密法》由中华人民共和国第十一届全国人民代表大会常务委员会第十四次会议于2010年4月29日修订通过，自（ C ）起施行。\r\n\r\nA、2008年10月1日\r\n\r\nB、2009年10月1日\r\n\r\nC、2010年10月1日\r\n\r\nD、2011年10月1日\r\n\r\n&nbsp;\r\n\r\n2、 国家秘密是（  B ），依照法定程序确定，在一定时间内只限一定范围的人员知悉的事项。\r\n\r\nA、关系企业安全和利益\r\n\r\nB、关系国家安全和利益\r\n\r\nC、关系单位安全和利益\r\n\r\nD、关系公民个人安全和利益\r\n\r\n&nbsp;\r\n\r\n3、机密级国家秘密是重要的国家秘密，泄露会使国家安全和利益（  C  ）。\r\n\r\nA、遭受损害\r\n\r\nB、遭受一般损害\r\n\r\nC、遭受严重的损害\r\n\r\nD、遭受特别严重的损害\r\n\r\n&nbsp;\r\n\r\n4、 国家秘密的知悉范围以外的人员，因工作需要知悉国家秘密的，应当经过（ D ）批准。\r\n\r\nA、上级主管部门\r\n\r\nB、保密行政管理部门\r\n\r\nC、办公室主任\r\n\r\nD、机关、单位负责人\r\n\r\n&nbsp;\r\n\r\n5、机关、单位定密工作的直接依据是（  A  ）。\r\n\r\nA、国家秘密及其密级的具体范围\r\n\r\nB、国家秘密事项一栏表\r\n\r\nC、上级文件的密级、保密期限和知悉范围\r\n\r\nD、保密法及有关规定\r\n\r\n&nbsp;\r\n\r\n6、《中华人民共和国保守国家秘密法实施条例》，自（ D  ）起施行。\r\n\r\nA、2011年3月1日\r\n\r\nB、2012年3月1日\r\n\r\nC、2013年3月1日\r\n\r\nD、2014年3月1日\r\n\r\n7、涉密人员不得在手机中存储涉及国家秘密的信息，不得在手机通话中涉及国家秘密事项，不得（  C  ）。\r\n\r\nA、用手机发送涉及工作秘密的信息\r\n\r\nB、用手机发送涉及商业秘密的信息\r\n\r\nC、用手机发送涉及国家秘密的信息\r\n\r\nD、用手机发送涉及个人隐私的信息\r\n\r\n&nbsp;\r\n\r\n8、涉密人员保密宣传教育一般应采取经常性保密教育和专门保密培训相结合方式，根据核心、重要和一般涉密人员的岗位特点和管理要求，采取相应的形式抓好（   A  ）各环节的保密宣传教育。\r\n\r\nA、上岗、在岗和离岗\r\n\r\nB、初任、任职和在职\r\n\r\nC、招聘、录用和解聘\r\n\r\nD、长职、晋级\r\n\r\n&nbsp;\r\n\r\n9、机关、单位发现国家秘密已经泄露或者可能泄露的，应当立即采取补救措施，并在（ B ）小时内向同级保密行政管理部门和上级主管部门报告。\r\n\r\nA、12\r\n\r\nB、24\r\n\r\nC、36\r\n\r\nD、48\r\n\r\n&nbsp;\r\n\r\n10、涉密网络中介质交叉使用的风险是指（  C  ）。\r\n\r\nA、硬盘等磁介质存在数据丢失的可能\r\n\r\nB、移动存储介质易发生丢失，导致泄密\r\n\r\nC、在涉密计算机上使用非涉密移动存储介质或在非涉密计算机上使用涉密移动存储介质，导致涉密信息极易被窃取\r\n\r\nD、利用移动存储介质在不同涉密机上拷贝信息，易导致病毒木马传播\r\n\r\n&nbsp;\r\n\r\n11、下列涉及国家安全和利益的事项，泄露后可能损害（  D  ）应当确定为国家秘密。\r\n\r\nA、保密工作责任制落实情况\r\n\r\nB、保密制度建设情况\r\n\r\nC、国家秘密载体管理情况\r\n\r\nD、国家在政治、经济、国防、外交等领域的安全和利益\r\n\r\n&nbsp;\r\n\r\n12、国家秘密及其密级的具体范围由（ A  ）规定。\r\n\r\nA、国家保密行政管理部门分别会同外交、公安、国家安全和其他中央有关机关\r\n\r\nB、科研单位\r\n\r\nC、各单位主要领导\r\n\r\nD、机关、单位负责人其指定人员\r\n\r\n&nbsp;\r\n\r\n13、机关、单位对是否属于国家秘密或者属于何种密级不明确或者有争议的，由（  D  ）确定。\r\n\r\nA、单位主要领导\r\n\r\nB、单位领导班子\r\n\r\nC、县（市）领导\r\n\r\nD、国家保密行政管理部门或者省、自治区、直辖市保密行政管理部门\r\n\r\n&nbsp;\r\n\r\n14、国家秘密的本质属性是（  B ）。\r\n\r\nA、依照法律程序确定\r\n\r\nB、关系国家安全和利益\r\n\r\nC、在一定时间内保密\r\n\r\nD、只限一定范围的人员知悉\r\n\r\n&nbsp;\r\n\r\n15、机关、单位公开发布信息应当坚持“谁公开，谁审查”，事前审查和依法审查的原则。在工作程序上，一般可分为（ A ）。\r\n\r\nA、信息提供部门自审、信息公开工作机构专门审查、主管领导审核批准三个环节\r\n\r\nB、信息提供部门请第三方代审、信息公开工作机构专门审查、主管领导审核批准三个环节\r\n\r\nC、信息提供部门自审、信息提供部门复审、主管领导审核批准三个环节\r\n\r\nD、信息提供部门自审、主管领导审核批准两个环节\r\n\r\n&nbsp;\r\n\r\n16、公民、法人或其他组织认为行政机关不依法履行政府信息公开义务的，可能性向上级行政机关、（ C ）举报，收到举报的机关应予调查处理。\r\n\r\nA、公安机关或政府信息公开工作主管部门\r\n\r\nB、组织部门或政府信息公开工作主管部门\r\n\r\nC、监察机关或政府信息公开工作主管部门\r\n\r\nD、司法部门或政府信息公开工作主管部门\r\n\r\n&nbsp;\r\n\r\n17、涉密信息系统应当由（ D ）设立或者授权的保密测评机构进行检测评估，并经设区的市、自治州以上保密行政管理部门审查合格，方可投入使用。\r\n\r\nA、县级国家保密行政管理部门\r\n\r\nB、当地政府行政管理部门\r\n\r\nC、中央、国务院\r\n\r\nD、国家保密行政管理部门\r\n\r\n&nbsp;\r\n\r\n18、机关、单位对符合保密法的规定，但保密事项范围没有规定的不明确事项，应当先行拟定密级、保密期限和知悉范围，采取相应的保密措施，并自拟定之日起（ A ）日内报有关部门审定。\r\n\r\nA、10\r\n\r\nB、15\r\n\r\nC、20\r\n\r\nD、5\r\n\r\n&nbsp;\r\n\r\n19、涉密人员分为（  D ）人员、重要涉密人员、一般涉密人员。\r\n\r\nA、非常重要\r\n\r\nB、十分重要\r\n\r\nC、特别重要\r\n\r\nD、核心涉密\r\n\r\n&nbsp;\r\n\r\n20、一般涉密人员的脱密期为（ A ）。\r\n\r\nA、1-2年\r\n\r\nB、2-3年\r\n\r\nC、3-5年\r\n\r\nD、10年\r\n\r\n&nbsp;\r\n\r\n21、涉密载体是指经文字、数据符号、图形、声音为方式记载国家秘密信息的纸介质、光介质、（ C ）等各类物品。\r\n\r\nA、U盘\r\n\r\nB、移动硬盘\r\n\r\nC、电磁介质\r\n\r\nD、磁盘\r\n\r\n&nbsp;\r\n\r\n22、机关、单位对需要销毁的涉密载体，应当认真履行清点、登记手续，报（ A  ）审核批准，并在送销前存放在符合安全保密的专门场所。\r\n\r\nA、本机关、本单位主管领导\r\n\r\nB、本单位办公室主任\r\n\r\nC、本级保密行政管理部门\r\n\r\nD、上级业务主管部门\r\n\r\n&nbsp;\r\n\r\n23、保密行政管理部门对公民举报、机关和单位报告、保密检查发现、有关部门移送的涉嫌泄露国家秘密的线索和案件，应当依法（  C  ）或者组织、督促有关机关、单位调查处理。\r\n\r\nA、及时上报\r\n\r\nB、及时处罚\r\n\r\nC、及时调查\r\n\r\nD、及时通报\r\n\r\n&nbsp;\r\n\r\n24、机关、单位发生泄露国家秘密案件不按照规定报告或者未采取补救措施的，对直接负责的主管人员和（  C  ）依法给予处分。\r\n\r\nA、分管领导\r\n\r\nB、单位主要负责人\r\n\r\nC、其他直接责任人\r\n\r\nD、文秘人员\r\n\r\n&nbsp;\r\n\r\n25、国家秘密的保密期限，除另有规定外，绝密级不超过（ D  ）。\r\n\r\nA、十年\r\n\r\nB、十五年\r\n\r\nC、二十年\r\n\r\nD、三十年\r\n\r\n&nbsp;\r\n\r\n26、设区的市、自治州一级的机关及其授权的机关、单位可能确定（ B ）国家秘密。\r\n\r\nA、绝密级和机密级\r\n\r\nB、机密级和秘密级\r\n\r\nC、机密级\r\n\r\nD、秘密级\r\n\r\n&nbsp;\r\n\r\n27、（ B  ）、行政学院、干部学院、保密学院和各级培训机构在保密宣传教育工作中发挥阵地作用，是开展保密宣传的重要平台。\r\n\r\nA、保密教育培训基地\r\n\r\nB、各级党校\r\n\r\nC、大学\r\n\r\nD、保密学院\r\n\r\n&nbsp;\r\n\r\n28、地方各级保密行政管理部门接到泄密报告的，应当在24小时内（ C ）。\r\n\r\nA、报至上级保密行政管理部门\r\n\r\nB、逐级报至中央\r\n\r\nC、逐级报至国家保密行政管理部门\r\n\r\nD、逐级报至国务院\r\n\r\n&nbsp;\r\n\r\n29、保密法制的作用从方式看，主要有引导作用、规范作用、调节作用、（  C  ）。\r\n\r\nA、推动作用\r\n\r\nB、实际作用\r\n\r\nC、制裁作用\r\n\r\nD、激励作用\r\n\r\n&nbsp;\r\n\r\n30、《中国人产党纪律处分条例》、《中共中央保密委员会关于党政领导干部保密工作责任制的规定》明确规定，对不认真发行保密工作领导责任制、疏于保密管理或在保密工作方面失职的领导干部（  A  ）。\r\n\r\nA、实行责任追究制\r\n\r\nB、降级处分\r\n\r\nC、党内警告处分\r\n\r\nD、通报批评\r\n\r\n&nbsp;\r\n\r\n31．国家秘密变更的内容，包括密级的(B)、保密期限的(B)、知悉范围的(B)，三者即可以单独变更，也可以同时变更。\r\n\r\nA降低  缩短  缩小\r\n\r\nB降低或提高  缩短或延长  缩小或扩大\r\n\r\nC提高  延长  扩大    D降低  缩短或延长  缩小\r\n\r\n&nbsp;\r\n\r\n32．涉密岗位，是指在日常工作中(C)或者(C)接触、知悉国家秘密事项的岗位。\r\n\r\nA产生  经常        B经管  偶尔\r\n\r\nC产生  经管  经常  D产生  经管  偶尔\r\n\r\n&nbsp;\r\n\r\n33．确因工作需要，且目的地不通外交信使，携带(A)国家秘密载体出境的，应当经中央和国家机关保密工作机构或地市级（含）以上地方保密行政管理部门批准。\r\n\r\nA秘密级  B机密级绝密级\r\n\r\nC机密级  D秘密级机密级\r\n\r\n34．绝密级国家秘密载体(C)携带出境。\r\n\r\nA按需要   B可以    C不得    D审查后\r\n\r\n&nbsp;\r\n\r\n35．设有机要文件交换站的城市，在市内传递(B)涉密载体，可以通过机要交换站进行。\r\n\r\nA绝密级、机密级、秘密级   B机密级、秘密级\r\n\r\nC机密级                   D秘密级\r\n\r\n&nbsp;\r\n\r\n36．摘录、引用国家秘密内容形成的涉密载体，应(B)。\r\n\r\nA  按新生成密件管理，重新确定密级、保密期限和知悉范围\r\n\r\nB按原件密级、保密期限和知悉范围管理\r\n\r\nC按秘密级密件管理\r\n\r\nD按机密级密件管理\r\n\r\n37．管理绝密级涉密载体，未经原定密机关、单位或者其上级机关批准，(C)。\r\n\r\nA也可复制、摘抄  B可适度摘抄\r\n\r\nC不得复制、摘抄  D只能复制一份\r\n\r\n3．处理绝密级信息的计算机，应采用(D)\r\n\r\nA多种字符和数字混合编制的口令\r\n\r\nB IC卡或USB Key与口令相结合方式\r\n\r\nC自己喜欢且容易记住的话来设定口令，并进行个性化改造\r\n\r\nD指纹、虹膜等强身份鉴别方式\r\n\r\n&nbsp;\r\n\r\n38．某商业银行支行原行长李某因工作调动，按要求对文件、资料进行清理，李某应该(B)\r\n\r\nA只将“红头文件”整理归档即可\r\n\r\nB将个人使用和管理的涉密载体全部清理，退还原工作单位\r\n\r\nC整理后的各类资料可以与报纸一起出售\r\n\r\nD将个人使用和管理的各类载体全部清理，退还原工作单位\r\n\r\n&nbsp;\r\n\r\n39．涉密计算机改作非涉密计算机使用，应当经过机关、单位批准，并采取(A)的安全技术处理措施。\r\n\r\nA拆除信息存储部件  B删除涉密文件\r\n\r\nC格式化硬盘        D硬盘分区\r\n\r\n&nbsp;\r\n\r\n40．(D)可真正保障涉密计算机及信息系统不受来自公共信息网络的黑客攻击，同时也为涉密计算机及信息系统划定了明确的安全边界。\r\n\r\nA隔离卡               B安全保密防护设备\r\n\r\nC安全保密防护软件     D物理隔离\r\n\r\n&nbsp;\r\n\r\n41．涉密计算机可以使用(C)。\r\n\r\nA  无线网卡  B无线键盘  C打印机    D蓝牙传输器\r\n\r\n&nbsp;\r\n\r\n42．机关、单位应建立互联网接入审批和登记制度。中央和国家机关各部门互联网接入口数量原则上不超过(A)，省级以下党政机关逐步实现互联网(A)接入。\r\n\r\nA两个    集中      B三个    集中\r\n\r\nC两个    分部门    D三个    分部门\r\n\r\n43．机关、单位应建立健全互联网信息发布保密审查制度，指定机构和人员负责拟在互联网发布信息的保密审查，并建立(A)。审查应坚持(A)、全面审查，并综合分析信息关联性，防止因数据汇聚涉及国家秘密。\r\n\r\nA审查记录档案  一事一审  B信息发布档案  集中审查\r\n\r\nC审查记录档案  一周二审  D信息发布档案  一月一审\r\n\r\n&nbsp;\r\n\r\n44．涉密人员不得在手机中存储(C)的工作单位、职务等敏感信息，不得启用手机的远程数据同步功能。\r\n\r\nA一般涉密人员     B重要涉密人员\r\n\r\nC核心涉密人员     D各级涉密人员\r\n\r\n&nbsp;\r\n\r\n45．核心涉密人员、重要涉密人员的手机出现故障或发现异常情况时应立即(B)，并在指定地点维修，无法恢复使用的应按涉密器材销毁。\r\n\r\nA关机    B报告   C停机  D更换号码\r\n\r\n&nbsp;\r\n\r\n46．普通电话、专网电话、公网电话等与公共信息网络连接，其通信内容可通过串音、搭线或电磁辐射进行窃听。铺设保密电话线路时，应与普通电话、专网电话、公网电话线路(A)，可以避免()泄密。\r\n\r\nA不靠近、不平行  串音   B不靠近、不平行  搭线\r\n\r\nC平行铺设  串音         D不靠近、不平行  电磁辐射\r\n\r\n&nbsp;\r\n\r\n47．传真涉密信息，必须使用(D)批准使用的加密传真机，只能传输(D)信息，绝密级信息应送当地机要部门译发。\r\n\r\nA保密行政管理部门  秘密级\r\n\r\nB国家密码管理部门  秘密级\r\n\r\nC保密行政管理部门  机密级和秘密级\r\n\r\nD国家密码管理部门  机密级和秘密级\r\n\r\n&nbsp;\r\n\r\n48．中央国家机关下属单位和省级以下机关、单位确定保密要害部门部位，应报(B)审核确认。\r\n\r\nA  国家保密行政管理部门\r\n\r\nB  中央国家机关保密工作机构或省级保密行政管理部门\r\n\r\nC  国家保密行政管理部门或中央国家机关保密工作机构\r\n\r\nD  中央国家机关保密工作机构\r\n\r\n&nbsp;\r\n\r\n49．下列(A)可能定为保密要害部门。\r\n\r\nA科技处  B保密室  C档案室  D涉密信息系统机房\r\n\r\n&nbsp;\r\n\r\n50．涉密会议、活动的保密工作实行(D)的原则。\r\n\r\nA谁监督，谁负责  B谁主管，谁负责\r\n\r\nC谁承办，谁负责  D谁主办，谁负责\r\n\r\n&nbsp;\r\n\r\n51．涉密网络建设完成后，应当经(C)审批，方可报项目审批部门组织峻工验收。\r\n\r\nA本单位信息中心     B公安机关\r\n\r\nC保密行政管理部门   D本单位保密委\r\n\r\n&nbsp;\r\n\r\n52．机关、单位涉密网络使用管理，应依据(D)严格设定用户权限，按照(D)原则，控制国家秘密信息知悉范围。\r\n\r\nA行政级别  最高密级防护和最小授权管理\r\n\r\nB岗位职责  适当密级防护和适当授权管理\r\n\r\nC行政级别  最高密级防护和适当授权管理\r\n\r\nD岗位职责  最高密级防护和最小授权管理\r\n<ol start="53">\r\n 	<li>5 机关、单位确定保密要害部门部位属于（B）。</li>\r\n</ol>\r\nA 资源行为   B 法定义务   C 社会义务   D 自主活动\r\n\r\n&nbsp;\r\n\r\n54．重大涉密会议、活动应当请(A)对保密工作进行监督和指导，并提供必要的(A)。\r\n\r\nA保密行政管理部门  安全保密技术服务保障\r\n\r\nB保密行政管理部门  技术检查设备\r\n\r\nC主办单位保密工作机构  安全保密技术服务保障\r\n\r\nD主办单位保密工作机构  技术检查设备\r\n\r\n55．涉密视频会议系统应当按照(C)有关要求进行建设和管理。\r\n\r\nA涉密通信及办公自动化设备    B涉密移动存储介质\r\n\r\nC涉密网络                    D内部网络\r\n\r\n&nbsp;\r\n\r\n56．国家统一考试保密管理工作由(C)负责。\r\n\r\nA教育部                B保密行政管理部门\r\n\r\nC组织考试的主管部门    D人力资源和社会保障部\r\n\r\n57．测绘成果资料由(A)提供。\r\n\r\nA测绘管理部门  B测绘队  C借领单位  D档案部门\r\n\r\n&nbsp;\r\n\r\n58．提出借领绝密级测绘成果资料的申请，应报(C)部门或(C)批准。\r\n\r\nA省级测绘行政主管  省级保密行政管理部门\r\n\r\nB省级保密行政管理  国家测绘行政主管部门\r\n\r\nC省级测绘行政主管  国家测绘行政主管部门\r\n\r\nD省级保密行政管理  国家保密局\r\n\r\n&nbsp;\r\n\r\n59．国家秘密技术出口，由申请单位或个人按照行政隶属关系报省、自治区、直辖市、计划单列市科技工作主管部门审查后，报科技部审批的是(B)。\r\n\r\nA秘密级技术    B机密级技术\r\n\r\nC绝密级技术    D各类秘密技术\r\n\r\n&nbsp;\r\n\r\n60．保密法第四十八条是对十二项严重违规行为法律责任的规定，这一规定表明(A)，应依法追究责任。\r\n\r\nA不论是否产生泄密实际后果，只要发生所列举的严重违规行为之一的\r\n\r\nB发生所列举的严重违规行为任何一项，且产生泄密实际后果的\r\n\r\nC不论是否产生泄密实际后果，发生两项以上严重违规行为的\r\n\r\nD产生泄密实际后果的违规行为\r\n\r\n&nbsp;\r\n<ol start="61">\r\n 	<li>6 共产党员丢失秘密文件资料或者泄露党和国家秘密，情节严重的，给予(C)处分。</li>\r\n</ol>\r\nA撤销党内职务    B严重警告\r\n\r\nC开除党籍        D留党察看\r\n\r\n&nbsp;\r\n\r\n62．保密法自(B)起施行。\r\n\r\nA 2010年4月29日    B 2010年10月1日\r\n\r\nC 2010年10月7日    D 2010年4月30日\r\n\r\n63．国家秘密区别于其他秘密的关键是(A)\r\n\r\nA关系国家安全和利益    B依照法定程序确定\r\n\r\nC在一定时间内保密      D只限一定范围的人员知悉\r\n\r\n&nbsp;\r\n\r\n64．我国保密工作体制的核心是(A)。\r\n\r\nA党管保密    B一个机构，两块牌子\r\n\r\nC依法管理    D依法行政\r\n\r\n65．保密工作是为维护国家安全和利益，将(C)控制在一定范围和时间内，防止泄露或被非法利用，由国家专门机构组织实施的活动。\r\n\r\nA秘密         B敏感信息\r\n\r\nC国家秘密     D国家秘密、工作秘密等\r\n<ol start="66">\r\n 	<li>6 (D)是党中央统一领导党政军保密工作的领导机构。</li>\r\n</ol>\r\nA国家保密局               B国家安全委员会\r\n\r\nC中央保密委员会办公室     D中央保密委员会\r\n\r\n&nbsp;\r\n\r\n67．业务工作接受上级业务部门垂直管理的单位，保密工作(A)。\r\n\r\nA以上级业务部门管理为主，同时接受地方保密行政管理部门的指导\r\n\r\nB以地方保密行政管理部门为主，同时接受上级业务部门的指导\r\n\r\nC接受上级业务部门和地方保密行政管理部门的双重管理\r\n\r\nD自主管理，同时接受上级业务部门的指导\r\n\r\n&nbsp;\r\n\r\n68．1997年印发的(D)，高度概括了新中国建立以来，特别是改革开放以来保密工作的基本经验，提出了新时期保密工作的基本任务，指明了新形势下保密工作的发展方向。\r\n\r\nA《中华人民共和国保守国家秘密法》\r\n\r\nB《关于加强保密工作的通知》\r\n\r\nC《高级干部保守党和国家秘密的规定》\r\n\r\nD《中共中央关于加强新形势下保密工作的决定》\r\n\r\n&nbsp;\r\n\r\n69．在保密工作手段上，要积极建立(D)的综合防范体系，不断提高发现和消除泄密隐患和风险的能力。\r\n\r\nA攻防一体    B专兼结合\r\n\r\nC知己知彼    D“人防、物防、技防”三位—体\r\n\r\n70．(D)是“一个机构，两块牌子”。\r\n\r\nA各级党委保密委员会办公室与保密工作机构\r\n\r\nB各级党委保密委员会与保密工作机构\r\n\r\nC各级党委保密委员会与各级保密行政管理部门\r\n\r\nD各级党委保密委员会办公室与各级保密行政管理部门\r\n\r\n&nbsp;\r\n\r\n71．我国最早的保密立法始予(A)。\r\n\r\nA西周    B秦汉    C隋唐    D明清\r\n\r\n72．下列(D)不属于保密法制的功能。\r\n\r\nA规范功能  B引导功能  C制裁功能  D参考功能\r\n<ol start="5">\r\n 	<li>随着信息时代特别是网络代的到来，(B)被称为“第五空间”。</li>\r\n</ol>\r\nA领土  B信息空间  C领空   D领海\r\n\r\n&nbsp;\r\n\r\n&nbsp;\r\n\r\n73．中国共产党建党以来第一份关于保密工作的专门文件是(B)。\r\n\r\nA《中国共产党第—个纲领》\r\n\r\nB《加强党的秘密工作通告》\r\n\r\nC《关于秘书工作技术问题的通知》\r\n\r\nD《中共中央关于建立保密工作通告》\r\n\r\n&nbsp;\r\n\r\n74．下列不属于我国保密法律制度体系的是(B)\r\n\r\nA保密法        B公司法\r\n\r\nC国家保密标准  D相关司法解释\r\n\r\n75．我国保密法律制度体系以(C)为核心。\r\n\r\nA宪法    B刑法    C保密法    D中国共产党章程\r\n\r\n&nbsp;\r\n\r\n76．一份保密期限为10年的机密级文件，正确的密级标注为(C)。\r\n\r\nA机密10年      B 10年★机密\r\n\r\nC机密★10年     D机密●10年\r\n\r\n&nbsp;\r\n\r\n77．国家秘密的保密期限届满时，应(C)。\r\n\r\nA适当延长保密期限  B自行公开\r\n\r\nC自行解密          D作为工作秘密管理\r\n\r\n&nbsp;\r\n\r\n78．(C)不可以确定绝密级国家秘密。\r\n\r\nA国家体育总局      B司法部\r\n\r\nC济南市人民政府    D重庆市人民改府\r\n\r\n&nbsp;\r\n<ol start="79">\r\n 	<li>7 机关、单位定密工作的直接依据是（A）。</li>\r\n</ol>\r\nA国家秘密及其密级的具体范围   B国家保密事项一览表\r\n\r\nC上级文件的密级期限和知悉范围 D保密法及有关规定\r\n\r\n&nbsp;\r\n<ol start="80">\r\n 	<li>80.定密工作程序为：由（A）对照保密事项范围提出国家秘密确定、变更和解除的具体意见，再由（）审核批准并承担（）。</li>\r\n</ol>\r\nA承办人  定密责任人  法律责任\r\n\r\nB定密责任人  定密小组组长  行政责任\r\n\r\nC承办人  定密小组组长  法律责任\r\n\r\nD承办人  定密责任人  行政责任\r\n\r\n&nbsp;\r\n\r\n81.（D）专业正式列入《普通高等学校本科专业目录（2012）》，实现了保密学历教育的历史性突破。\r\n\r\nA保密技术    B信息安全\r\n\r\nC保密法学    D保密管理\r\n\r\n&nbsp;\r\n<ol start="82">\r\n 	<li>8 核心涉密场所禁止带入手机，重要涉密场所禁止使用手机，一般涉密场所（B）。</li>\r\n</ol>\r\nA禁止使用手机     B限制使用手机\r\n\r\nC可以使用手机     D定时使用手机\r\n\r\n&nbsp;\r\n<ol start="83">\r\n 	<li>8 机关、单位定密工作的直接依据是（A）。</li>\r\n</ol>\r\nA国家秘密及其密级的具体范围   B国家保密事项一览表\r\n\r\nC上级文件的密级期限和知悉范围 D保密法及有关规定\r\n\r\n&nbsp;\r\n<ol start="84">\r\n 	<li>8 定密工作程序为：由（A）对照保密事项范围提出国家秘密确定、变更和解除的具体意见，再由（）审核批准并承担（）。</li>\r\n</ol>\r\nA承办人  定密责任人  法律责任\r\n\r\nB定密责任人  定密小组组长  行政责任\r\n\r\nC承办人  定密小组组长  法律责任\r\n\r\nD承办人  定密责任人  行政责任\r\n\r\n&nbsp;\r\n\r\n85.（D）专业正式列入《普通高等学校本科专业目录（2012）》，实现了保密学历教育的历史性突破。\r\n\r\nA保密技术    B信息安全\r\n\r\nC保密法学    D保密管理\r\n\r\n&nbsp;\r\n<ol start="86">\r\n 	<li>8 核心涉密场所禁止带入手机，重要涉密场所禁止使用手机，一般涉密场所（B）。</li>\r\n</ol>\r\nA禁止使用手机     B限制使用手机\r\n\r\nC可以使用手机     D定时使用手机\r\n\r\n&nbsp;\r\n<ol start="87">\r\n 	<li>8 安全保密产品的检测证书有效期通常（B ）。</li>\r\n</ol>\r\nA 2年     B 3年     C 5年\r\n\r\nD在产品形态不改变的前提下，终身有效\r\n\r\n&nbsp;\r\n<ol start="88">\r\n 	<li>8 《报告涉露国家秘密事件的规定》第三条规定，发生泄密事件的机关、单位，应当在发现后的（A）内，书面向有关保密工作部门或机构报告。</li>\r\n</ol>\r\nA 24小时    B 12小时    C 36小时    D 48小时\r\n\r\n&nbsp;\r\n<ol start="89">\r\n 	<li>8 以下不属于保密违法行为的是（D）。</li>\r\n</ol>\r\nA 私自买卖涉密地图\r\n\r\nB 利用连接互联网计算机存储、处理绝密信息\r\n\r\nC 将涉密计算机连接互联网\r\n\r\nD 按照国家有关规定对涉密载体进行销毁\r\n\r\n&nbsp;\r\n\r\n90．给受检单位的检查通知一般应当（D）。\r\n\r\nA不发通知             B提前7个工作日发出\r\n\r\nC提前3个工作日发出   D提前1—2个工作日发出\r\n\r\n&nbsp;\r\n<ol start="91">\r\n 	<li>9 涉密信息系统测评中属于一票否决项的是（A）。</li>\r\n</ol>\r\nA物理隔离、信息传输密码保护\r\n\r\nB密级标识、用户口令强度\r\n\r\nC访问控制、使用移动存储介质\r\n\r\nD使用移动存储介质、用户身份鉴别\r\n\r\n&nbsp;\r\n\r\n92． 关于国家秘密载体销毁的程序及有关规定正确的是（D）。\r\n\r\nA只要通过本单位主管部门审核批准，要立即进行销毁\r\n\r\nB确因工作需要，自行销毁少量国家秘密载体时，应严格履行清点、登记和审批手续，使用本单位具备的销毁设备和方法进行了销毁\r\n\r\nC送销国家秘密载体，应当分类封装，安全运送，如无特殊情况，无需派专人现场监销\r\n\r\nD应将需要销毁的国家秘密载体送交保密行政管理部门设立的销毁工作机构或者保密行政管理部门指定的单位\r\n\r\n&nbsp;\r\n<ol start="93">\r\n 	<li>9 领导同志处、核心涉密部门场所选设备应符合（）标准，优先考虑（C）设备。</li>\r\n</ol>\r\nA IS09001   进口    B国内信息安全认证   功能齐全\r\n\r\nC国家保密  国产    D国办认证  性能好\r\n\r\n&nbsp;\r\n<ol start="94">\r\n 	<li>9 保密行政管理部门确定重点区域应当按照（A）原则，以（A）为最小单位。</li>\r\n</ol>\r\nA最小化  县级行政区划\r\n\r\nB积极防范  县级行政区划\r\n\r\nC最小化   市级行政区划\r\n\r\nD积极防范  市级行政区划\r\n\r\n&nbsp;\r\n<ol start="95">\r\n 	<li>9 （D）承担国家秘密教育培训规划制定，保密教育培训组织实施，保密教育培训教材、师资建设，保密学科建设等重要职责。</li>\r\n</ol>\r\nA国家保密学院    B国家行政学院\r\n\r\nC中央党校        D国家保密教育培训基地\r\n\r\n&nbsp;\r\n\r\n&nbsp;\r\n\r\n96．非密事项需发传真、电报的（B）。\r\n\r\nA可以使用密码传真、密码电报\r\n\r\nB不得使用密码传真、密码电报\r\n\r\nC有时可以使用密码传真、密码电报\r\n\r\nD使用密码传真、密码电报应当严格遵守规定\r\n\r\n&nbsp;\r\n<ol start="97">\r\n 	<li>97. 涉密打印机与涉密计算机之间（D）。</li>\r\n</ol>\r\nA采用无线连接方式应当严格遵守规定\r\n\r\nB可以采用无线连接方式\r\n\r\nC有时采用无线连接方式\r\n\r\nD不能采用无线连接方式\r\n\r\n&nbsp;\r\n\r\n98 保放结合，是指在开展保密工作时，要正确处理保密与信息公开的关系，做到（C）。\r\n\r\nA保要害 保重点   B保中心 保重点\r\n\r\nC保核心 保重点   D保核心 保要害\r\n\r\n&nbsp;\r\n\r\n99．定密授权机关在作出定密授权决定时，应当明确一定的授权期限。一般而言，定密授权期限最长不超过(C)。\r\n\r\nA 1年    B 3年    C 5年    D 10年\r\n\r\n&nbsp;\r\n\r\n100．《国家秘密定密管理暂行规定》第九条规定：没有定密权但经常产生国家秘密事项的机关、单位，或者虽有定密权但经常产生超出其定密权限的国家秘密事项的机关、单位，可以向授权机关申请定密授权。这里“经常”是指(C)。\r\n\r\nA 3年来年均产生5件以上国家秘密事项\r\n\r\nB 2年来年均产生6件以上国家秘密事项\r\n\r\nC 3年来年均产生6件以上国家秘密事项\r\n\r\nD 2年来年均产生5件以上国家秘密事项\r\n\r\n&nbsp;\r\n<ol start="101">\r\n 	<li>101. 法宝的定密责任人，是指法律明确规定作为定密责任人的人员，即机关、单位负责人。机关、单位负责人一般是指机关、单位的（A）。</li>\r\n</ol>\r\nA正职负责人         B领导班子\r\n\r\nC保密委员会主任     D纪委书记\r\n\r\n&nbsp;\r\n\r\n102． 承办人，是指根据机关、单位内部职责分工，负责具体处理、办理涉及国家秘密事项的工作人员。承办人是（B）。\r\n\r\nA定密业务培训的组织者\r\n\r\nB定密流程中第一个环节工作的执行者\r\n\r\nC拟公开发布信息的保密审查者\r\n\r\nD定密异议的受理者\r\n\r\n&nbsp;\r\n<ol start="103">\r\n 	<li>103. 下列哪一个选项不能确定为保密期限（D）。</li>\r\n</ol>\r\nA 10年                    B 2015年5月1日之前\r\n\r\nC外交部发言人公开宣布前   D《大公报》的公开报道前\r\n\r\n&nbsp;\r\n\r\n104． 在（D）情况下，机关单位定密时才可以将有关事项的保密期限确定为长期。\r\n\r\nA法定定密责任人认为有必要的\r\n\r\nB绝密级已满三十年保密期的\r\n\r\nC知悉范围很小的\r\n\r\nD保密事项范围明确规定某一项国家秘密事项保密期限为长期的\r\n\r\n&nbsp;\r\n<ol start="105">\r\n 	<li>105. 在实际工作中，一些单位存在党、政各有一把手的情况。这些单位在确定法定定密责任人时，（C）。</li>\r\n</ol>\r\nA只能确定党委一把手作为法定定密责任人\r\n\r\nB从两人中选举产生一位法定定密切责任人\r\n\r\nC可以确定两人同时为法定定密责任人\r\n\r\nD应报请上级主管部门确定法定定密责任人\r\n\r\n&nbsp;\r\n<ol start="106">\r\n 	<li>106. 国有企业虽然一定行政级别，但不属于保密法规定的具有法定定密权的机关范畴。金融机构应向（A）申请授权。</li>\r\n</ol>\r\nA银监会   B中国银行   C国资会   D国家保密局\r\n\r\n&nbsp;\r\n<ol start="107">\r\n 	<li>107. 下列说法正确的是（A）。</li>\r\n</ol>\r\nA无论机关单位是否具有相应的定密权限，都可以进行派生定密\r\n\r\nB派生定密需要定密授权\r\n\r\nC涉及绝密级国家秘密事项的派生定密需要定密授权\r\n\r\nD派生定密无需定密授权，介只能确定密级\r\n\r\n&nbsp;\r\n<ol start="108">\r\n 	<li>108. 定密的根本依据是（C）。</li>\r\n</ol>\r\nA保密事项范围    B定密目录\r\n\r\nC保密法          D国家秘密定密管理暂行规定\r\n\r\n&nbsp;\r\n<ol start="109">\r\n 	<li>109. 国家秘密标志不正确的是（A）。</li>\r\n</ol>\r\nA秘密★15年         B机密★2015年12月31日\r\n\r\nC秘密★会议开始前    D绝密★长期\r\n\r\n&nbsp;\r\n<ol start="110">\r\n 	<li>110. 机关单位应当每（B）对所确定的国家秘密进行审核。</li>\r\n</ol>\r\nA半年     B一年     C两年    D五年\r\n\r\n&nbsp;\r\n<ol start="111">\r\n 	<li>111. 机关单位对不明确事项，应当先行拟定密级、保密期限和知悉范围，采取相应的保密措施，并自拟定之日起（B）个工作日内报有关部门确定。</li>\r\n</ol>\r\nA  5      B  10     C  15      D  20\r\n\r\n&nbsp;\r\n\r\n112 对已经移交各级国家档案馆的涉密档案，应由（B）组织进行解密审核。\r\n\r\nA移交部门               B档案馆\r\n\r\nC同级保密行政管理部门   D上级档案行政管理部门\r\n\r\n&nbsp;\r\n<ol start="113">\r\n 	<li>113. 机关单位延长所确定的国家秘密的保密期限，累计超过保密事项范围规定的期限，应当（C）。</li>\r\n</ol>\r\nA报同级保密行政管理部门批准\r\n\r\nB报本单位保密委员会批准\r\n\r\nC报规定该保密事项范围的中央有关机关批准\r\n\r\nD解密\r\n\r\n&nbsp;\r\n\r\n114．突出重点是保密检查的原则之一，关于突出重点，下列说法错误的是(C)。\r\n\r\nA把服从服务党和国家中心工作作为重点\r\n\r\nB把关系政治、经济、外交、国防等战略性、全局性核心国家秘密作为重点\r\n\r\nC把所有机关单位和涉密人员作为重点\r\n\r\nD把发生重大泄密事件的机关、单位，以及工作中容易发生泄密的薄弱环节作为重点\r\n\r\n&nbsp;\r\n\r\n115．党政机关和涉密单位对需要维修维护的设备产品，应当认真履行(B)手续，并存放在(B)的专门场所。\r\n\r\nA清点、登记  处级以上办公\r\n\r\nB清点、登记、审批符合安全保密要求\r\n\r\nC清点、登记  符合安全保密要求\r\n\r\nD清点、登记、审批  处级以上办公\r\n\r\n&nbsp;\r\n\r\n116．中央和国家机关各部门发生泄密事件，应向(B)报告。\r\n\r\nA国务院办公厅    B国家保密局\r\n\r\nC公安部          D北京市保密局\r\n\r\n&nbsp;\r\n\r\n117．涉密人员不得在手机中存储涉及国家秘密的信息，不得在手机通话中涉及国家秘密事项，不得 (C)\r\n\r\nA用手机发送涉及工作秘密的信息\r\n\r\nB用手机发送涉及商业秘密的信息\r\n\r\nC用手机发送涉及国家秘密的信息\r\n\r\nD用手机发送涉及个人隐私的信息\r\n\r\n&nbsp;\r\n<ol start="118">\r\n 	<li>118. 下列不属于违反保密法律应承担的责任的是(C)。</li>\r\n</ol>\r\nA行政责任    B刑事责任   C民事责任    D党纪处分\r\n\r\n&nbsp;\r\n\r\n119.国家秘密的变更是指(A)的变更。\r\n\r\nA密级、保密期限、知悉范围\r\n\r\nB 保密期限、知悉范围、涉密内容\r\n\r\nC保密期限、知悉范围\r\n\r\nD密级、保密期限、知悉范围、涉密内容\r\n\r\n&nbsp;\r\n\r\n120.某机密级文件保密期限为20年。8年后，该文件根据工作需要降低为秘密级国家秘密，其保密期限最长还有(C)年。\r\n\r\nA  10年  B 12年  C  2年   D  5年\r\n\r\n&nbsp;\r\n\r\n&nbsp;\r\n\r\n121．机关单位执行中央下发的机密级文件，执行过程中产生的文件资料，应当确定为(B)。\r\n\r\nA秘密级国家秘密    B机密级国家秘密\r\n\r\nC绝密级国家秘密    D内部事项\r\n\r\n&nbsp;\r\n\r\n122．保密行政管理部门受理鉴定申请后，应当(A)出具鉴定结论；不能按期出具鉴定结论的，经保密行政管理部门负责众批准，可以(  )。\r\n\r\nA自受理之日起30日内  延长30日\r\n\r\nB 自受理之日起15日内  延长15日\r\n\r\nC自提出鉴定申请之日起30日内   延长30日\r\n\r\nD 自提出签定申请之日起15日内  延长1 5日\r\n\r\n&nbsp;\r\n\r\n二、多项选择题\r\n\r\n1、政府信息公开的原则包括（ABD）\r\n\r\nA、公正、公平、便民原则\r\n\r\nB、及时、准确原则\r\n\r\nC、服务领导原则\r\n\r\nD、保障公共利益原则\r\n\r\n&nbsp;\r\n\r\n2、各级政府应当建立健全政府信息公开（ABC），定期对政府信息公开工作进行考核、评议。\r\n\r\nA、考核制度\r\n\r\nB、社会评议制度\r\n\r\nC、责任追究制度\r\n\r\nD、审查制度\r\n\r\n&nbsp;\r\n\r\n3、1997年，党中央下发《中共中央关于加强新形势下保密工作的决定》明确提出，要全面提高保密干部的政治思想和业务素质，努力做好（ABCD）。\r\n\r\nA、业务精\r\n\r\nB、政治强\r\n\r\nC、作风正\r\n\r\nD、纪律严\r\n\r\n&nbsp;\r\n\r\n4、涉密人员上岗前需进行（ ACD ）。\r\n\r\nA、任前审查\r\n\r\nB、交接手续\r\n\r\nC、上岗培训\r\n\r\nD、上岗保密承诺\r\n\r\n&nbsp;\r\n\r\n5、涉密人员所签订的保密承诺书的主要内容包括（ABCD）等。\r\n\r\nA、了解并遵守各项保密制度\r\n\r\nB、知悉并履行保密义务\r\n\r\nC、自愿接受保密审查\r\n\r\nD、承担法律责任\r\n\r\n&nbsp;\r\n\r\n6、涉密载体可分为（ABC）\r\n\r\nA、纸介质涉密载体\r\n\r\nB、光介质涉密载体\r\n\r\nC、电磁介质涉密载体\r\n\r\nD、移动存储介质涉密载体\r\n\r\n&nbsp;\r\n\r\n7、机关、单位保密承诺书签订人员范围包括（ABCD）。\r\n\r\nA、领导干部，即现任地方各级各部门、各涉密单位副科级以上领导干部\r\n\r\nB、在岗涉密人员，包括在职、新任、借调、聘用等人员\r\n\r\nC、离岗涉密人员，包括退休、调离、辞职、辞退等人员\r\n\r\nD、其他可能接触、知悉国家秘密的人员\r\n\r\n&nbsp;\r\n\r\n8、保密法制的作用从方式看，主要有（ABCD）。\r\n\r\nA、引导作用\r\n\r\nB、规范作用\r\n\r\nC、制裁作用\r\n\r\nD、调节作用\r\n\r\n&nbsp;\r\n\r\n9、举办会议或者其他活动涉及国家秘密的，主办单位应当采取下列哪几项保密措施？（ABCD）\r\n\r\nA、根据会议、活动的内容确定密级，制定保密方案，限定参加人员范围\r\n\r\nB、按照国家保密规定管理国家秘密载体\r\n\r\nC、对参加人员提出具体保密要求\r\n\r\nD、使用符合国家保密规定和标准的场所、设施、设备\r\n\r\n&nbsp;\r\n\r\n10、保密宣传教育是一项长期性工作，要达到工作目标，取得实际效果，必须按照坚持正确方向、坚持联系实际、（ ABC）的基本要求开展工作。\r\n\r\nA、坚持分类施教\r\n\r\nB、坚持持之以恒\r\n\r\nC、坚持改革创新\r\n\r\nD、坚持务求实效\r\n\r\n&nbsp;\r\n\r\n11、信息公开保密审查应当依照下列程序（ABD）。\r\n\r\nA、信息产生机构提出是否公开信息的审查意见\r\n\r\nB、信息公开保密审查人员提出审核意见\r\n\r\nC、已确定为涉密或不宜公开的信息\r\n\r\nD、机关、单位负责人或被授权人审批\r\n\r\n&nbsp;\r\n\r\n12、下列哪几项是《政府信息公开条例》的有关规定。（ABCD）\r\n\r\nA、各级政府应当建立健全政府信息公开工作考核制度、社会评议制度和责任追究制度，定期限对政府信息公开工作进行考核、评议\r\n\r\nB、监察机关对信息公开保密审查情况监督检查\r\n\r\nC、各级行政机关定期公布本行政机关政府信息公开工作年度报告\r\n\r\nD、公民、法人或其他组织认为行政机关不依法履行政府信息公开义务的，可以向上级行政机关、监察机关或政府信息公开工作主管部门举报，收到举报的应予调查处理\r\n\r\n&nbsp;\r\n\r\n13、根据保密法和《报告泄露国家秘密事件的规定》，泄密案件报告可分为（ABC）。\r\n\r\nA、发现泄密案件的人员向有关机关、单位报告\r\n\r\nB、有关机关、单位向保密行政管理部门报告\r\n\r\nC、下级保密行政管理部门或保密工作机构向上级保密行政管理部门报告\r\n\r\nD、上级保密行政管理部门向国家保密行政管理部门报告\r\n\r\n&nbsp;\r\n\r\n14、保密违法案件查处的主要内容有（ABCD）。\r\n\r\nA、查明案情\r\n\r\nB、及时补救\r\n\r\nC、责任追究\r\n\r\nD、保密整改\r\n\r\n&nbsp;\r\n\r\n15、保密违法案件查处的基本原则有（ ABC）。\r\n\r\nA、国家安全和利益至上\r\n\r\nB、实事求是\r\n\r\nC、依法办案\r\n\r\nD、责任追究\r\n\r\n&nbsp;\r\n\r\n16、保密违法行为与侵犯国家秘密犯罪行为之间的区别有（BCD）。\r\n\r\nA、查处对象不同\r\n\r\nB、法律后果不同\r\n\r\nC、查处主体不同\r\n\r\nD、查处依据不同\r\n\r\n&nbsp;\r\n\r\n17、报告泄密案件，应当包括被泄露国家秘密事项的内容、密级、数量及载体形式；泄密案件的发现经过；泄密责任人的基本情况及（ABCD）。\r\n\r\nA、泄密案件发生的时间、地点及经过\r\n\r\nB、泄密案件造成或可能千万的危害\r\n\r\nC、已进行或拟进行的查处工作情况\r\n\r\nD、已采取或拟采取的补救措施\r\n\r\n&nbsp;\r\n\r\n18、保密教育培训的主要种类有（ABC）。\r\n\r\nA、岗前培训、在岗培训和离岗教育\r\n\r\nB、综合培训和专题培训\r\n\r\nC、资格培训和非资格培训\r\n\r\nD、专业培训和非专业培训\r\n\r\n&nbsp;\r\n\r\n19、下列应当确定为国家秘密的是（ABCD）。\r\n\r\nA、国家事务重大决策中的秘密事项\r\n\r\nB、国防建设和武装力量活动中的秘密事项\r\n\r\nC、外交和外事活动中的秘密事项以及对外承担保密义务的秘密事项\r\n\r\nD、科学技术中的秘密事项\r\n\r\n&nbsp;\r\n\r\n20、从事涉密业务的企业事业单位应当具备下列哪些条件？（ABCD）\r\n\r\nA、在中华人民共和国境内依法成立3年以上的法人，无违法犯罪记录及从事涉密业务的人员具有中华人民共和国国籍\r\n\r\nB、保密制度完善，有专门的机构或者人员负责保密工作\r\n\r\nC、用于涉密业务的场所、设施、设备符合国家保密规定和标准及具有从事涉密业务的专业能力\r\n\r\nD、法律、行政法规和国家保密行政管理部门规定的其他条件\r\n\r\n&nbsp;\r\n\r\n21、从事涉密业务企事业单位发生（ABCD）变更的，应当在变更后30个工作日内向省级保密行政管理部门书面报告。\r\n\r\nA、法定代表人\r\n\r\nB、单位名称\r\n\r\nC、注册地址、生产经营场所\r\n\r\nD、资本构成、经营范围、单位性质发生重大变化\r\n\r\n&nbsp;\r\n\r\n22、申报涉密项目的机关、单位（以下简称申报单位）应当提交（ABCD）及拟采取的保密管理和技术材料，其他与涉密项目申报相关的材料。\r\n\r\nA、申报审查确认的公文\r\n\r\nB、立项申请文件\r\n\r\nC、涉密项目的基本情况，包括名称、来源、背景、规模、实施计划以及主管单位等\r\n\r\nD、项目涉密的论证报告，包括项目密级、定密依据、涉密内容等。\r\n\r\n&nbsp;\r\n\r\n23、主办涉密会议、活动的单位需采取的保密管理措施包括严格参加人员审查、（ABD）、严格新闻报道。\r\n\r\nA、严格场所设备检查\r\n\r\nB、严格保密要求\r\n\r\nC、严格会议内容\r\n\r\nD、严格涉密载体管理\r\n\r\n&nbsp;\r\n\r\n24、对于非涉密网络，要坚持源头控制原则，确保（ AB）。\r\n\r\nA、上非涉密网络的信息不涉密\r\n\r\nB、涉密信息不上非涉密网络\r\n\r\nC、信息内容严格审查\r\n\r\nD、信息发布规范程序\r\n\r\n&nbsp;\r\n\r\n25、涉密人员的具体脱必期限由机关、单位保密工作机构会同有关业务主管部门根据其接触、知悉国家秘密的（ABD）等情况审查确定。\r\n\r\nA、密级\r\n\r\nB、数量\r\n\r\nC、工作年限\r\n\r\nD、时间\r\n\r\n&nbsp;\r\n\r\n26、对发生下列行为之一的档案服务机构，应撤销其云南省档案数字化服务机构备案证书。（ABCD）\r\n\r\nA、不接受档案、保密行政管理部门监督以及被要求限期整改，逾期不改的\r\n\r\nB、发生严重档案安全事故的及发生泄密事件的\r\n\r\nC、未按期限进行复查或未通过复查的\r\n\r\nD、两年内没有承接档案数字化工作的\r\n\r\n&nbsp;\r\n\r\n27、秘密可分为（ABCD）。\r\n\r\nA、个人隐私\r\n\r\nB、国家秘密\r\n\r\nC、工作秘密\r\n\r\nD、商业秘密\r\n\r\n&nbsp;\r\n\r\n28、国家秘密必须具备的基本要素有（ ABC）。\r\n\r\nA、关系国家利益\r\n\r\nB、依照法定程序确定\r\n\r\nC、在一定时间内只限一定范围的人员知悉\r\n\r\nD、受法律保护\r\n\r\n&nbsp;\r\n\r\n29、国家秘密与工作秘密的区别在于（ABCD）。\r\n\r\nA、关系的利益主体不同\r\n\r\nB、确定方式不同\r\n\r\nC、秘密标志不同\r\n\r\nD、管理方式和法律责任不同\r\n\r\n&nbsp;\r\n\r\n30、现行泄密案件报告制度实行（AC ）。\r\n\r\nA、一事一报制度\r\n\r\nB、半年报告制度\r\n\r\nC、年度综合报告制度\r\n\r\nD、季度报告制度\r\n\r\n&nbsp;\r\n<ol start="31">\r\n 	<li>31. 针对涉密网络存在的主要安全保密隐患，可采取的技术监管措施包扎（ABC）。</li>\r\n</ol>\r\nA网络终端监管    B存储介质监管\r\n\r\nC网络行为监管    D涉密文件特征检测监管\r\n<ol start="32">\r\n 	<li>3 磁介质载体的销毁包括（ABC），且必须满足国家保密标准《涉及国家秘密的载体销毁与信息消除安全保密要求》。</li>\r\n</ol>\r\nA物理粉碎      B强磁场消磁\r\n\r\nC数据写覆盖    D涂层防护\r\n\r\n&nbsp;\r\n\r\n33．具有法定定密权的机关包括(ABC)。\r\n\r\nA中央国家机关                 B省级机关\r\n\r\nC设区的市和自治州一级的机关   D县级机关\r\n\r\n&nbsp;\r\n\r\n34．《党政机关和涉密单位网络保密管理规定》对涉密网络(ABCD)等环节的保密管理提出明确要求。\r\n\r\nA密集确定、方案论证   B建设实施、测评审批\r\n\r\nC风险评估、重大变化   D 废止\r\n\r\n35.当前，非涉密网络是(ACD)。\r\n\r\nA 网络泄密的重灾区\r\n\r\nB 网络保密管理的“命根子”\r\n\r\nC 境外情报机构获取涉密信息的主渠道\r\n\r\nD 境外情报机构实施网络攻击窃密的“跳板”\r\n\r\n&nbsp;\r\n\r\n36．根据保密法实施条例的规定，定密授权的方式包括(BC)。\r\n\r\nA定时授权   B主动授权   C依申请授权   D单项授权\r\n\r\n&nbsp;\r\n\r\n37．关于国家秘密的变更，以下说法正确的是（ABD）。\r\n\r\nA 国家秘密“谁确定，谁变更，谁解除”\r\n\r\nB 国家秘密的变更应当由确定该国家秘密的主体负责\r\n\r\nC 国家秘密的变更应当由使用该国家秘密的主体负责\r\n\r\nD 国家秘密的变更可以由原定密机关单位的上级机关决定\r\n\r\n&nbsp;\r\n\r\n38．定密监督的方式主要包括(ABCD)。\r\n\r\nA定密检查    B法定定密责任人的监督\r\n\r\nC定密统计    D定密核查\r\n\r\n2．保密技术装备配备方式，包括(AC)。\r\n\r\nA强制配备  B自主配备  C指导配备  D统一配备\r\n\r\n&nbsp;\r\n<ol start="39">\r\n 	<li>3 下列事项中，（ABCD）不得确定为国家秘密。</li>\r\n</ol>\r\nA需要社会公众广泛知晓或者参与的\r\n\r\nB属于工作秘密、商业秘密、个人隐私的\r\n\r\nC已经依法公开或者无法控制知悉范围的\r\n\r\nD法律、法规或者国家有关规定要求公开的\r\n\r\n&nbsp;\r\n<ol start="40">\r\n 	<li>4 六部门联合下发的《关于进一步加强全国干部保密教育培训工作的通知》要求，把保密教育培训作为各级党政领导班子成员和中青年干部培训办公室内容，纳入（ABCD）。</li>\r\n</ol>\r\nA干部年度脱产培训计划   B网络在线学习\r\n\r\nC公务员职业道德教育计划\r\n\r\nD公务员初任、任职及其他相关培训\r\n\r\n&nbsp;\r\n<ol start="41">\r\n 	<li>41. 依据现行有效的人事工作和纪检监察工作保密事项范围，很多没有定密权的机关单位都涉及人事和纪检监察定密问题，以下正确的做法是（AD）。</li>\r\n</ol>\r\nA在向上级业务主管部门申请定密授权时，一并就该两项事项提出申请\r\n\r\nB向上级人事或纪检监察部门申请定密授权\r\n\r\nC按照有关保密事项范围或纪检监察部门申请定密，报同级保密行政管理部门备案\r\n\r\nD某设区的市财政局仅需要获得人事、纪检监察工作秘密级定密权时，向市政府提出授权申请\r\n\r\n&nbsp;\r\n<ol start="42">\r\n 	<li>4 禁止定密的事项包括（ABCD）。</li>\r\n</ol>\r\nA需要社会公众广泛知晓或者参与的\r\n\r\nB属于工作秘密、商业秘密、个人隐私的\r\n\r\nC已经依法公开或者无法控制知悉范围的\r\n\r\nD法律、法规或者国家有关规定要求公开的\r\n\r\n&nbsp;\r\n\r\n43．当前，保密工作的阶段性特征是(ACD)“三期叠加”。\r\n\r\nA尖锐复杂期 B转型过渡期 C转型升级期 D战略机遇期\r\n\r\n44．领导干部保密工作责任包括(ABCD)。\r\n\r\nA接受保密监督、检查和考核\r\n\r\nB严格管理亲属子女和身边工作人员\r\n\r\nC带头遵守保密纪律，学习保密知识技能\r\n\r\nD履行保密工作领导责任\r\n\r\n&nbsp;\r\n<ol start="45">\r\n 	<li>4 对检查中发现存在严重泄密隐患的网络、设施、设备和场所，检查人员应当立即向检查组负责人或者组织检查的保密行政管理部门报告，采取 (ABC)等处置措施。</li>\r\n</ol>\r\nA 责令停止使用\r\n\r\nB 断开网络连接\r\n\r\nC 封存设备\r\n\r\nD终止检查\r\n\r\n&nbsp;\r\n<ol start="46">\r\n 	<li>4 保密重区域包括（ABCD）。</li>\r\n</ol>\r\nA处于对敌斗争或反分裂斗争前沿的边疆、沿海地区\r\n\r\nB重要军事设施、国防军工单位连片集中地区\r\n\r\nC涉及国家安全和利益的重大工程、项目所在地区\r\n\r\nD全国及各省（区、市）政治、经济中心\r\n\r\n&nbsp;\r\n<ol start="47">\r\n 	<li>4 保密重点领域具体包括（ABC）等。</li>\r\n</ol>\r\nA测绘    B金融    C教育   D体育\r\n\r\n&nbsp;\r\n\r\n48.涉密人员有（ABCD）的权利。\r\n\r\nA参加保密教育培训    B行使保密监督\r\n\r\nC获得补偿            D要求配备保密设施设备\r\n\r\n&nbsp;\r\n\r\n49.根据国务院有关行政审批权，保密行政管理部门对(ABC)实行保密资质管理。\r\n\r\nA国家秘密载体制作复制单位\r\n\r\nB 涉及国家秘密的信息系统集成单位\r\n\r\nC武器装备科研生产单位\r\n\r\nD涉密工程建设单位\r\n\r\n&nbsp;\r\n\r\n50．机关、单位应当(ABCD)措施，加强涉密网络安全保密技术防护。\r\n\r\nA身份鉴别    B访问及信息流转控制\r\n\r\nC安全审计    D边世安全防护\r\n\r\n&nbsp;\r\n<ol start="51">\r\n 	<li>5 保密宣传教育的作用主要包括（ABCD）。</li>\r\n</ol>\r\nA  引导作用   B  规范作用\r\n\r\nC  推进作用   D  激励作用\r\n\r\n&nbsp;\r\n<ol start="52">\r\n 	<li>5 机关、单位应制定在编人员担任涉密网络的(B C D)</li>\r\n</ol>\r\nA网络巡查员          B 系统管理员\r\n\r\nC 安全保密管理员      D 安全审计员\r\n\r\n&nbsp;\r\n\r\n53．国家主管部门组织的(ABCD)等国家统一考试的试题、答案和评分标准，在启用前均属于国家秘密。\r\n\r\nA国家教育           B执（职）业资格\r\n\r\nC国家公务员录用     D专业技术人员资格\r\n\r\n&nbsp;\r\n\r\n54．保密法制的价值主要体现在(BD)几个方面。\r\n\r\nA规范保密管理行为   B维护国家安全和利益\r\n\r\nC确保公开           D保障公民正当权益\r\n\r\n&nbsp;\r\n<ol start="55">\r\n 	<li>5 机关、单位负责人及其指定的人员为定密责任人，负责本机关、本单位的国家秘密（ABC）工作。</li>\r\n</ol>\r\nA确定    B变更   C解除   D销毁\r\n\r\n&nbsp;\r\n<ol start="56">\r\n 	<li>5 保密干部应当具备的素质能力，包括（ABCD）。</li>\r\n</ol>\r\nA创新能力   B调研能力   C协调能力   D执行能力\r\n\r\n&nbsp;\r\n<ol start="57">\r\n 	<li>5 我国现行保密法律制度体系主要包括：宪法、保密法律、(ABCD)、国际公约或政府间协定的相关规定等。</li>\r\n</ol>\r\nA保密法规        B保密规章\r\n\r\nC国家秘密标准    D相关司法解释\r\n\r\n&nbsp;\r\n<ol start="58">\r\n 	<li>5 机关、单位负责人及其指定的人员为定密责任人，负责本机关、本单位的国家秘密（ABC）工作。</li>\r\n</ol>\r\nA确定    B变更   C解除   D销毁\r\n\r\n&nbsp;\r\n<ol start="59">\r\n 	<li>5 对国秘密确定、变更和解除情况的检查重点应为（ABC）。</li>\r\n</ol>\r\nA是否实行定密责任人制度，依法确定国家秘密事项和密级\r\n\r\nB是否准确标明国家秘密事项密级\r\n\r\nC是否根据情况变化及时变更和解除国家秘密事项密级\r\n\r\nD是否准确确定涉密人员涉密等级\r\n\r\n&nbsp;\r\n<ol start="60">\r\n 	<li>6 保密干部，是依照法律规定，组织开展保密工作的人员，包括（ABC）。</li>\r\n</ol>\r\nA各级保密委员会组成人员\r\n\r\nB各级保密行政管理部门工作人员\r\n\r\nC机关、单位涉密岗位的工作人员\r\n\r\nD各级保密工作机构的专兼职工作人员\r\n<ol start="61">\r\n 	<li>6 有关机关提起密级鉴定，应当提交下列材料（ABC）。</li>\r\n</ol>\r\nA提起密级鉴定的公文\r\n\r\nB需要进行密级鉴定的文件、资料和其他物品\r\n\r\nC进行密级鉴定工作需要掌握的有关情况，包括案件基本情况、主要情节、鉴定材料泄露对象和时间等\r\n\r\nD鉴定材料泄露时适用的保密法律法规、保密事项范围和密级变更、解密文件\r\n<ol start="62">\r\n 	<li>6 以下有密级鉴定权的保密部门是（AB）。</li>\r\n</ol>\r\nA  重庆市保密局    B  甘肃省保密局\r\n\r\nC  深圳市保密局    D  最高人民法院保密委员会办公室\r\n\r\n&nbsp;\r\n\r\n63．在境外活动时，遇到情报机构(ACD)时，要稳立场，巧妙处置，并及时通知我驻外使领馆。\r\n\r\nA策反     B宴请     C威胁      D讹诈\r\n<ol start="64">\r\n 	<li>6 任用、聘用的境外人员确需接触、知悉我国家秘密的，应按照(AC)原则，报国务院有关主管部门或者省、自治区、直辖市人民政府有关主管部门批准。</li>\r\n</ol>\r\nA谁主管、谁负责     B集中报审\r\n\r\nC一事一批           D方便工作\r\n\r\n&nbsp;\r\n\r\n65．保密法规定，各级保密行政管理部门中负有保密管理职责的人员滥用职权、玩忽职守、徇私舞弊的，依法给予处分；构成犯罪的，依法追究刑事责任。其中“玩忽职守”是指(BCD)的行为。\r\n\r\nA弄虚作假      B严重不负责任\r\n\r\nG不履行职责    D不正确履行职责\r\n\r\n66．保密法规定，各级保密行政管理部门中负有保密管理职责的人员滥用职权、玩忽职守、徇私舞弊的，依法给予处分；构成犯罪的，依法追究刑事责任。其中“滥用职权”是指(BD)的行为。\r\n\r\nA不正确履行职责    B违背法律授权宗旨行使职权\r\n\r\nC弄虚作假          D违反法律程序行使职权\r\n\r\n&nbsp;\r\n<ol start="67">\r\n 	<li>6 保密管理的基本要求主要包括（ABCD）。</li>\r\n</ol>\r\nA党管保密    B依法行政\r\n\r\nC保放结合    D综合防范\r\n\r\n&nbsp;\r\n\r\n68．涉密工程的保密管理环节包括(ABCD)。\r\n\r\nA确认    B设计    C建设    D使用\r\n\r\n&nbsp;\r\n\r\n69．涉密工程，是指(ACD)涉及国家秘密事项，公开后会危害国家安全和利益的建筑物的新建、改建、扩建、装修、拆除、修缮工程等。\r\n\r\nA用途    B外观    C功能   D关键部位\r\n\r\n&nbsp;\r\n\r\n70．参加涉外活动应注意(AC)。\r\n\r\nA不得带领境外人员到国家禁止其进入的涉密部门部位\r\n\r\nB同境外人员活动，谨慎携带国家秘密载体\r\n\r\nC须按事先确定的范围和口径与境外人员会谈\r\n\r\nD利用境外通信设施进行涉密联络时，注意保密\r\n\r\n&nbsp;\r\n\r\n71．对外交往合作中提供国家秘密事项的，应根据有关保密法律法规，与接受方签订保密协议，基本内容包括(ABCD)。\r\n\r\nA对外提供的国家秘密事项   B对外提供国家秘密的理由\r\n\r\nC承担的保密义务           D违约责任\r\n\r\n&nbsp;\r\n\r\n72．因工作需要携运属于国家秘密的文件、资料和其他物品出境，须(CD)。\r\n\r\nA自行妥善携运，确保安全\r\n\r\nB夹放在托运行李中悄悄携运\r\n\r\nC交由国家保密局核准的单位和人员携运\r\n\r\nD交由外交信使携运\r\n\r\n&nbsp;\r\n<ol start="73">\r\n 	<li>7  (AD)情况下需申请办理《国家秘密载体出境》许可证。</li>\r\n</ol>\r\nA目的地不通外交信使\r\n\r\nB携运密件赴亚洲以外国家\r\n\r\nC携运绝密级文件出境\r\n\r\nD外交信使难以携运\r\n\r\n&nbsp;\r\n<ol start="74">\r\n 	<li>7 国家秘密技术出口的审查原则是(BCD)。</li>\r\n</ol>\r\nA保障使用、应批尽批\r\n\r\nB维护国家技术优势和经济利益\r\n\r\nC贯彻我国外交路线、方针、政策\r\n\r\nD有利于扩大我国科技影响\r\n\r\n&nbsp;\r\n\r\n75．在境外活动要注意的保密事项有(ABCD)。\r\n\r\nA不随意谈论国家秘密，不议论所在国和第三国的敏感问题\r\n\r\nB不要把涉密文件或内部资料带入会谈场所\r\n\r\nC密电和涉密文件必须在我国驻外使领馆保密室草拟\r\n\r\nD不得使用境外人员使用的办公设备处理涉密信息\r\n\r\n&nbsp;\r\n\r\n76．国家秘密的基本属性包括(BCD)。\r\n\r\nA实用性  B专属性  C限定性  D法定性\r\n\r\n&nbsp;\r\n\r\n77．保密工作作为一门科学，有自身必须遵循的原则，包括最小化、(ABCD)原则。\r\n\r\nA全程化  B精准化   C自主化  D法制化\r\n\r\n&nbsp;\r\n\r\n78．保密法结合保密工作的特点和规律，在总结新时期党和国家保密工作实践经验的基础土，规定保密工作的方针，包括(CD)等。\r\n\r\nA综合防范  B精准管理  C依法管理  D保放适度\r\n\r\n&nbsp;\r\n\r\n79．保密工作的基本经验是(ABCD)。\r\n\r\nA党管保密  B专兼结合   C综合防范  D攻防一体\r\n\r\n&nbsp;\r\n\r\n80．下列属于中央和国家机关保密工作机构的职责的是(BD)。\r\n\r\nA管理本机关的业务及保密工作\r\n\r\nB对本系统的保密工作进行管理和指导\r\n\r\nC对本系统的业务工作进行管理和指导\r\n\r\nD管理本机关的保密工作\r\n\r\n&nbsp;\r\n\r\n81．下列属于我国刑法规定的与保守国家秘密有关的罪名是(BCD)\r\n\r\nA背叛国家罪\r\n\r\nB为境外窃取、刺探、收卖、非法提供国家秘密、情报罪\r\n\r\nC非法获取国家秘密罪\r\n\r\nD过失泄露国家秘密罪\r\n\r\n&nbsp;\r\n\r\n82．国家统一考试命题工作的保密要求有(ABD)。\r\n\r\nA对命题人员和内部工作人员进行审查\r\n\r\nB采取入闱工作形式\r\n\r\nC原始试题应存放在保险柜中，由一人专门保管\r\n\r\nD原始试题应存放在保险柜中，由两人专门保管\r\n\r\n&nbsp;\r\n\r\n83．在我国，保密法律责任主要包括(BC) 。\r\n\r\nA民事责任  B刑事责任  C行政责任  D违宪责任\r\n\r\n&nbsp;\r\n\r\n84．保密法确定了1 l项主要制度，其中包括(ABCD)等。\r\n\r\nA保密工作责任制度\r\n\r\nB保密法律责任制度\r\n\r\nC信息公开发布保密审查制度\r\n\r\nD企业事业单位从事涉密业务保密审查制度\r\n\r\n&nbsp;\r\n\r\n85．保密法强化涉密信息系统保密管理，硬措施主要包括(ABCD)。\r\n\r\nA实行分级保护\r\n\r\nB强化技术防护\r\n\r\nC明确禁止事项\r\n\r\nD明确网络运营商、服务商的法律责任\r\n\r\n&nbsp;\r\n\r\n86．确定保密要害部门部位应坚持(BD)的基本原则。\r\n\r\nA分类确定   B分级确定   C全程化   D最小化\r\n\r\n&nbsp;\r\n\r\n87．涉密人员严禁在(ABD)时填写机关、单位名称和地址等信息。\r\n\r\nA申请手机号码  B注册手机邮箱\r\n\r\nC购买苹果手旗  D开通其他功能\r\n\r\n&nbsp;\r\n\r\n88．互联网及其他公共信息网络运营商、服务商(ABC)，由公安机关或者国家安全机关、信息产业主管部门按照各自职责分工依法予以处罚。\r\n\r\nA不配合检察机关对泄密案件进行调查\r\n\r\nB 发现发布的泄密信息，没有立即停止传输，并报告\r\n\r\nC没有按要求及时删除发布的涉密信息\r\n\r\nD没有定期开展保密检查\r\n\r\n&nbsp;\r\n\r\n89．《行政机关公务员处分条例》第26条规定，泄露（ABCD），造成不良后果的，给予警告、记过或者记大过处分；情节较重的，给予降级或者撤职处分；情节严重的，给予开除处分。\r\n\r\nA 国家秘密                    B工作秘密\r\n\r\nC 因履行职责掌握的商业秘密    D个人隐私\r\n\r\n90．机关、单位违反保密法规定，发生重大泄密案件的，由有关机关、单位依法对(BC)给予处分。\r\n\r\nA保密办主任           B直接负责的主管人员\r\n\r\nC其他直接责任人员     D领导班子成员\r\n\r\n&nbsp;\r\n<ol start="91">\r\n 	<li>9  2011年9月，中共中央办公厅、国务院办公厅印发了《“十二五”时期全国保密事业发展规划，强调“十二五”时期，保密工作要基本健全(ABCD)的现代保密管理体系。</li>\r\n</ol>\r\nA以教育培训为先导    B以法规制度为基础\r\n\r\nC以监督检查为保证    D以科学技术为支撑\r\n\r\n&nbsp;\r\n\r\n92．涉密会议、活动主办单位应当采取(ABCD)保密措施。\r\n\r\nA严格参加人员审查    B严格涉密载体管理\r\n\r\nC严格场所设备检查    D严格新闻报道审查\r\n\r\n&nbsp;\r\n\r\n93．知悉涉密数据的人员(AD)。\r\n\r\nA应当作出保密承诺\r\n\r\nB可以以“预测”方式向个人提供数据\r\n\r\nC不得接受新闻单位采访\r\n\r\nD参加学术活动不得涉及涉密数据及相关信息\r\n\r\n&nbsp;\r\n\r\n&nbsp;\r\n\r\n94．核心涉密人员、重要涉密人员使用的手机应经过必要的安全检查，尽可能配备和使用专用手机，不得使用(BCD)的手机。\r\n\r\nA国外品牌        B未经入网许可\r\n\r\nC开通位置服务    D有连接互联网等功能\r\n\r\n&nbsp;\r\n\r\n95．处理涉密信息的(ABCD)等设备不能连入互联网、普通电话网等公共信息网络。\r\n\r\nA复印机  B多功能一体机   C扫描仪  D打印机\r\n\r\n&nbsp;\r\n\r\n96．保密要害部位应当是存放、保管涉密载体的(ACD)。\r\n\r\nA最小专用场所    B最小行政单位\r\n\r\nC独立场所        D  固定场所\r\n\r\n&nbsp;\r\n\r\n97．涉密会议、活动的承办单位应(CD)。\r\n\r\nA制定保密工作方案    B确定会议、活动的密级\r\n\r\nC提供安全保密的环境、设施和设备\r\n\r\nD对工作人员进行保密教育\r\n\r\n&nbsp;\r\n\r\n98．国家秘密的密级如有下列(BD)情形之一的，应当及时变更。\r\n\r\nA定密责任人认为需要变更\r\n\r\nB确定时依据的保密事项范围已作调整\r\n\r\nC泄露后对国家安全和利益的影响发生变化\r\n\r\nD泄露后对国家安全和利益的损害程度发生明显变化\r\n\r\n&nbsp;\r\n<ol start="99">\r\n 	<li>9 (ABC)人员不得任用、聘用为涉密人员。</li>\r\n</ol>\r\nA酗酒    B因严重违反保密规定被调离涉密岗位\r\n\r\nC受过刑事处罚    D受过警告处分\r\n\r\n&nbsp;\r\n\r\n100．涉密人员某些情况发生变化，应及时报告。须报告的重大事项有(ABD)。\r\n\r\nA发现针对本人的渗透行为 B子女获得境外永久居留资格\r\n\r\nC配偶出境旅游           D与境外人员结婚\r\n\r\n&nbsp;\r\n\r\n101．涉密人员上岗、在岗应该(ABCD)。\r\n\r\nA主动接受保密教育培训   B掌握保密知识技能\r\n\r\nC签订保密承诺书         D自觉接受保密监督检查\r\n\r\n&nbsp;\r\n\r\n102．涉密人员离岗、离职应遵守脱密期管理规定，包括脱密期内未经审查批准，(ABC)。\r\n\r\nA不得擅自出境                 B不得到外资企业工作\r\n\r\nC不得为境外人员提供咨询或服务 D不得为境内单位工作\r\n\r\n&nbsp;\r\n\r\n103．属于国家秘密的设备、产品（简称“密品”），是指直接含有国家秘密信息，或者通过(ABD)能够获取所承载的国家秘密信息的设备和产品。\r\n\r\nA观察    B测试    C询问    D分析\r\n\r\n&nbsp;\r\n\r\n104．收发涉密载体，应当履行(ABCD)手续。\r\n\r\nA清点  B登记  C编号  D签收\r\n\r\n4.查阅、收听、观看涉及国家秘密的信息，要严格遵守保密规定，未经批准，不得擅自(ACD)。\r\n\r\nA记录    B传播    C录音    D录像\r\n\r\n&nbsp;\r\n\r\n105．携带涉密载体外出或参加涉外活动，必须(ABC)，确保涉密载体始终处于有效监控之下。\r\n\r\nA确因工作需要    B经过本机关、本单位主管领导批准\r\n\r\nC采取保密措施    D保证载体连接互联网\r\n\r\n&nbsp;\r\n\r\n106．维修涉密载体，应(ABD)。\r\n\r\nA由本机关、本单位专门技术人员负责\r\n\r\nB需外单位人员维修的，要由本机关、本单位有关人员现场监督\r\n\r\nC请载体制造商派人维修，必要时可带走，保证尽快恢复使用\r\n\r\nD需送外维修的，应当送保密行政管理部门审查批准的定点单位\r\n\r\n&nbsp;\r\n\r\n107．机构撤销、合并时，原机构的涉密载体应根据不同情况，分别移交给(ABC)。移交时，须履行登记、签收手续。\r\n\r\nA制发单位        B档案管理部门\r\n\r\nC合并后的新单位  D相关管理人员\r\n\r\n&nbsp;\r\n\r\n108．不要以(ABCD)作为涉密计算机的口令。\r\n\r\nA姓名    B生日    C英文单词    D手机号\r\n\r\n&nbsp;\r\n\r\n109．涉密计算机不可以接入(ABCD)。\r\n\r\nA互联网  B有线电视网  C  固定电话网  D移动通信网\r\n\r\n&nbsp;\r\n\r\n110．计算机网络防火墙不能(ABCD)。\r\n\r\nA防止数据驱动式攻击\r\n\r\nB防止感染了病毒的软件或文件的传输\r\n\r\nC防范不经由防火墙产生的攻击\r\n\r\nD防范来自内部的攻击\r\n\r\n&nbsp;\r\n<ol start="111">\r\n 	<li>111. 将非涉密信息复制到涉密计算机，应(ABD)。</li>\r\n</ol>\r\nA对复制的数据进行病毒查杀  B使用一次性光盘导入\r\n\r\nC使用U盘导入  D使用经过国家保密行政管理部门批准的信息单向导入设备\r\n\r\n&nbsp;\r\n\r\n112.《党政领导干部保密工作责任制规定》创设了(ABC)等制度\r\n\r\nA述职    B考核    C约谈    D传讯\r\n\r\n&nbsp;\r\n\r\n113．常见的窃听方式有(ABCD)。\r\n\r\nA有线搭线窃听       B无线窃听\r\n\r\nC激光探测窃听       D定向探测窃听\r\n\r\n&nbsp;\r\n\r\n114.涉密网络“三员”的基本职责表述正确的是(AD)。\r\n\r\nA安全审计员主要负责对其他“两员’的操作行为进行审计、跟踪、分析和监督检查\r\n\r\nB系统管理员主要负责对其他“两员”的操作行为进行审计、跟踪、分析和监督检查\r\n\r\nC 安全保密管理员主要负责涉密网络的日常运行维护工作\r\n\r\nD安全保密管理员主要负责涉密网络的日常安全保密管理工作\r\n\r\n&nbsp;\r\n\r\n115．《审计工作国家秘密范围的规定》应当规定该领域国家秘密事项的(AB)。\r\n\r\nA具体名称和密级    B保密期限和知悉范围\r\n\r\nC承办人资格标准    D定密责任人资格标准\r\n\r\n&nbsp;\r\n\r\n116．保密行政管理部门调查或者组织、督促有关机关单位调查处理涉嫌泄露国家秘密的线索和案件的工作，包括(ABCD)阶段。\r\n\r\nA 立案    B调查   C 处理    D结案\r\n\r\n&nbsp;\r\n\r\n117．保密行政管理部门应当对(ABCD)的涉嫌泄露国家秘密的线索和案件，立即进行初步审查。\r\n\r\nA有关部门移送     B保密检查发现\r\n\r\nC机关和单位报告   D公民举报\r\n\r\n&nbsp;\r\n\r\n三、判断题（共20题，每题1分，共20分）\r\n\r\n1、机关、单位及其工作人员履行保密工作责任制情况应当纳入年度考评和考核内容。（ 对 ）\r\n\r\n2、企业事业单位及其工作人员协助机关、单位逃避、妨碍保密检查或者泄露保密检查或者泄露国家秘密案件查处的，由有关主管部门依法予以处罚。（ 对 ）\r\n\r\n3、对本机关产生的仍在保密期限内的国家秘密文件、资料，如果认为符合提前解密条件的，可以不需要办理解密手续，直接删去密级标志后就予以公开。（ 错 ）\r\n\r\n4、连接互联网的计算机必须与处理涉密信息的计算机严格区分，做到专机专用，不得既用于上互联网又用于处理国家秘密信息。（  对  ）\r\n\r\n5、涉密人员可以私自到境外机构、组织或者外商独资企业工作，为其提供服务。（  错  ）\r\n\r\n6、涉密人员被解聘或者本人提出辞职的，应先调离涉密岗位，在本单位履行脱密期后再行办理解聘、辞职或调离手续。（  对  ）\r\n\r\n&nbsp;\r\n\r\n7、国家秘密载体以及属于国家秘密的设备、产品的明显部位应当标注国家秘密标志。（  对  ）\r\n\r\n&nbsp;\r\n\r\n8、复制国家秘密载体或者摘录、引用、汇编属于国家秘密的内容，应当按照规定报批，不得擅自改变原件的密级、保密期限和知悉范围，复制件应当加盖复制机关、单位戳记，并视同原件进行管理。（  对  ）\r\n\r\n&nbsp;\r\n\r\n9、机关单位制作本单位保密承诺书，可以结合实际补充相关内容，也可以适当删减规定的基本内容。（ 错  ）\r\n\r\n&nbsp;\r\n\r\n10、中央国家机关、省级机关及其授松的机关、单位可能确定绝密级、机密级和秘密级国家秘密；设区的市、自治州一级的机关及其授权的机关、单位可以确定绝密级和秘密级国家秘密。（ 错 ）\r\n\r\n&nbsp;\r\n\r\n11、保守国家秘密、维护国家安全和利益是每个公民应尽的宪法义务。（  对  ）\r\n\r\n12、机关、单位确因工作需要，自行销毁少量国家秘密载体的，应当使用符合国家保密标准的销毁设备和方法。（  对  ）\r\n\r\n13、按照“谁定密、谁审批、谁负责”的原则，机关、单位负责人对本机关、本单位的定密工作负责。（对）\r\n\r\n&nbsp;\r\n\r\n14、机关、单位执行中央下发的机密级文件，在执行过程中产生的文件资料，应当确定为秘密级国家秘密。（错）\r\n\r\n&nbsp;\r\n\r\n15、没有定密权的机关、单位，可以向有相应定密权限的上一级机关或有关行来主管部门提出定密授权的申请。（  对  ）\r\n\r\n16、机关、单位对是否属于国家秘密或者属于何种密级不明确或者有争议的，由国家保密行政管理部门或者省、自治区、直辖市保密行政管理部门确定。（  对  ）\r\n\r\n&nbsp;\r\n\r\n17、机关、单位工作人员可以在涉密计算机和非涉密计算机之间交叉使用优盘等移动存储介质。（ 错  ）\r\n\r\n&nbsp;\r\n\r\n18、军事方面的国家秘密及其密级的具体范围，由国家保密局规定。（  错  ）\r\n\r\n&nbsp;\r\n\r\n19、涉密人员的合法权益受法律保护。（  对  ）\r\n\r\n20、签订保密承诺书之前，应当组织对承诺人进行保密教育和培训。承诺人要了解有关保密要求，熟悉保密承诺内容，掌握相关保密知识和技能。（  对  ）\r\n\r\n21、机关、单位发现边秘密已经泄露或者可能泄露的，应当立即采取补救措施，并在12小时内向同级保密行政管理部门和上级保密行政管理部门报告。（ 错   ）\r\n\r\n&nbsp;\r\n\r\n22、在保密审查过程中，机关、单位认为被审查信息涉及商业秘密、个人隐私，公开后可能损害第三方合法权益的，应当口头征求第三方的意见。（  错  ）\r\n\r\n&nbsp;\r\n\r\n23、上网信息的保密管理坚持“谁上网谁负责”的原则。（  对  ）\r\n\r\n24、保密管理的目的是通知采取积极防范、突出重点、依法管理的方针，达到既确保国家保密安全、又便利信息资源合理利用。（  对  ）\r\n\r\n25、制定保密事项范围，既要从国家安全和利益出发，把确属国家秘密的事项纳入保密范围；又要避免“宽一些保险”、“高一些有利”的片面认识，严格控制保密范围，实事求是地确定密级。（  对  ）\r\n\r\n&nbsp;\r\n\r\n26、保密违法行为与侵犯国家秘密犯罪行为之间的区别查处对象不同、法律后果不同、查处主体不同。（  错  ）\r\n\r\n&nbsp;\r\n\r\n27、要充分发挥党校、行政学院、干部学院在领导干部保密教育中的主阵地、主渠道作用，利用党委（党组）理论中心组学习、保密法制讲座和培训、保密知识考试考核等形式开展保密教育。（  对  ）\r\n\r\n&nbsp;\r\n\r\n28、接受保密宣传教育，掌握基本的保密工作常识和技能，是对一名合格公务员的重要标准。（  错  ）\r\n\r\n&nbsp;\r\n\r\n29、工作人员可以通过普通邮政、快递等渠道传递国家秘密载体。（  错  ）\r\n\r\n30、不得将退出使用的涉密计算机、涉密存储设备赠送、出售、丢弃或者改作其他用途。（   对  ）\r\n\r\n&nbsp;\r\n\r\n31、保密承诺书不需要一年一签。（  对  ）\r\n\r\n32、对严重违反保密承诺，泄露国家秘密的，应当依法依纪给予处分；构成犯罪的，依法追究刑事责任。（ 对   ）\r\n\r\n33、离岗人员不需要签保密承诺书。（  错  ）\r\n\r\n34、不得在未采取防护措施的情况下将互联网及其他公共信息网络上的数据复制到涉密计算机及网络。（  对  ）\r\n\r\n35、手机只要在不通话的情况下，可以带入重要涉密场所。（ 错   ）\r\n\r\n36、公安、国家安全机关在其工作范围内按照规定的权限确定国家秘密的密级。（ 对   ）\r\n\r\n37、禁止在互联网及其他公共信息网络或者未采取保密措施的有线和无线通令中传递国家秘密。（  对  ）\r\n\r\n38、应在一般区域建立失泄密案件应急处置机制，及时处置预案。（  错  ）\r\n\r\n39、根据《国家秘密载体销毁管理规定》，国家秘密载体除正在使用或者按照有关规定留存、存档外，应当及时予以销毁。（  对  ）\r\n\r\n40、依照有关规定，标有“内部资料”的信息，不得公开或暂缓公开。（  对  ）\r\n\r\n41、在中华人民共和国境内依法成立2年以上的法人，无违法犯罪记录的企业事业单位可以从事涉密业务。（ 错  ）\r\n\r\n42、国家对在保守、保护国家秘密以及改进保密技术、措施等方面成绩显著的单位或者个人给予奖励。（ 对   ）\r\n\r\n43、国家秘密的密级分为绝密、机密、秘密三级。（ 对   ）\r\n\r\n44、不属于国家秘密的，不应当做出国家秘密标志。（ 对   ）\r\n\r\n&nbsp;', '保密法律法规知识竞赛试题', '', 'publish', 'open', 'open', '', '%e4%bf%9d%e5%af%86%e6%b3%95%e5%be%8b%e6%b3%95%e8%a7%84%e7%9f%a5%e8%af%86%e7%ab%9e%e8%b5%9b%e8%af%95%e9%a2%98', '', '', '2017-05-03 10:42:07', '2017-05-03 02:42:07', '', 0, 'http://bm.yangyongquan.com/?p=156', 0, 'post', '', 0);
INSERT INTO `wp_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES
(158, 1, '2017-04-28 10:33:40', '2017-04-28 02:33:40', '<table>\r\n<tbody>\r\n<tr>\r\n<td colspan="2" width="90">题目</td>\r\n<td colspan="2" width="212">机关单位在确定保密要害部门和部位时，要坚持“（ ）”和“（ ）”原则。</td>\r\n<td colspan="16" width="304">标记    （本试题作答时存在不确定性可做标记待后续检查）</td>\r\n</tr>\r\n<tr>\r\n<td colspan="2" width="90">选项</td>\r\n<td colspan="18" width="516">A 分级确定、最大化 B 最高级别确定、最大化 C 分级确定、最小化 D 最低级别确定、最小化</td>\r\n</tr>\r\n<tr>\r\n<td colspan="5" width="452">单选题</td>\r\n</tr>\r\n<tr>\r\n<td width="83">题目</td>\r\n<td colspan="2" width="195">各级机关单位对所产生的国家秘密事项，应当依照保密范围的规定及时确定密级，最迟不得超过（ ）</td>\r\n<td colspan="2" width="172">标记    （本试题作答时存在不确定性可做标记待后续检查）</td>\r\n</tr>\r\n<tr>\r\n<td width="83">选项</td>\r\n<td colspan="4" width="368">A 20日 B 3日 C 5日 D 10日</td>\r\n</tr>\r\n<tr>\r\n<td colspan="6" width="462">单选题</td>\r\n</tr>\r\n<tr>\r\n<td width="83">题目</td>\r\n<td colspan="2" width="195">发生泄密事件的机关、单位，应在发现后（ ）内，书面向有关保密工作部门或机构报告，情况紧急时，可先口头报告简要情况。</td>\r\n<td colspan="3" width="183">标记    （本试题作答时存在不确定性可做标记待后续检查）</td>\r\n</tr>\r\n<tr>\r\n<td width="83">选项</td>\r\n<td colspan="5" width="378">A 48小时 B 24小时 C 72小时 D 12小时</td>\r\n</tr>\r\n<tr>\r\n<td colspan="19" width="597">判断题</td>\r\n</tr>\r\n<tr>\r\n<td width="83">题目</td>\r\n<td colspan="2" width="195">互联网和其他公共网络信息运营商、服务商具有配合有关机关调查泄密案件的法律责任。</td>\r\n<td colspan="16" width="317">标记    （本试题作答时存在不确定性可做标记待后续检查）</td>\r\n</tr>\r\n<tr>\r\n<td width="83">答案</td>\r\n<td colspan="18" width="513">正确 错误</td>\r\n</tr>\r\n<tr>\r\n<td colspan="7" width="473">判断题</td>\r\n</tr>\r\n<tr>\r\n<td width="83">题目</td>\r\n<td colspan="2" width="195">新修订《保密法》规定：军事方面的国家秘密及其密级的具体范围，由国家保密行政管理部门分别会同外交、公安、国家安全和其他中央有关机关规定。</td>\r\n<td colspan="4" width="193">标记    （本试题作答时存在不确定性可做标记待后续检查）</td>\r\n</tr>\r\n<tr>\r\n<td width="83">答案</td>\r\n<td colspan="6" width="389">正确 错误</td>\r\n</tr>\r\n<tr>\r\n<td colspan="8" width="483">判断题</td>\r\n</tr>\r\n<tr>\r\n<td width="83">题目</td>\r\n<td colspan="2" width="195">新修订的《保密法》规定，发生重大泄的密案件，不仅要对直接责任人追究责任，也要对负有领导责任的直接责任人员给予处分。</td>\r\n<td colspan="5" width="203">标记    （本试题作答时存在不确定性可做标记待后续检查）</td>\r\n</tr>\r\n<tr>\r\n<td width="83">答案</td>\r\n<td colspan="7" width="399">正确 错误</td>\r\n</tr>\r\n<tr>\r\n<td colspan="9" width="493">单选题</td>\r\n</tr>\r\n<tr>\r\n<td width="83">题目</td>\r\n<td colspan="2" width="195">军事禁区和属于国家秘密不对外开放的其他场所、部位，应当采取保密措施，除依照国家有关规定经过批准外，（ ）对外开放或者扩大开放范围。</td>\r\n<td colspan="6" width="214">标记    （本试题作答时存在不确定性可做标记待后续检查）</td>\r\n</tr>\r\n<tr>\r\n<td width="83">选项</td>\r\n<td colspan="8" width="409">A 可以自行决定 B 只能限定时段 C 不得擅自决定 D 也可视情适当</td>\r\n</tr>\r\n<tr>\r\n<td colspan="18" width="586">单选题</td>\r\n</tr>\r\n<tr>\r\n<td width="83">题目</td>\r\n<td colspan="2" width="195">根据《中华人民共和国保守国家秘密法》的有关规定，关于政党的秘密事项表述正确的是（ ）。</td>\r\n<td colspan="15" width="307">标记    （本试题作答时存在不确定性可做标记待后续检查）</td>\r\n</tr>\r\n<tr>\r\n<td width="83">选项</td>\r\n<td colspan="17" width="502">A 政党的秘密事项经保密工作部门确认后，属于国家秘密事项 B 政党的秘密事项中部分属于国家秘密事项 C 政党的秘密事项属于国家机密 D 政党的秘密事项与国家秘密性质不同，不属于国家秘密事项</td>\r\n</tr>\r\n<tr>\r\n<td colspan="10" width="504">单选题</td>\r\n</tr>\r\n<tr>\r\n<td width="83">题目</td>\r\n<td colspan="2" width="195">《保密法》的立法依据是（ ）。</td>\r\n<td colspan="7" width="224">标记    （本试题作答时存在不确定性可做标记待后续检查）</td>\r\n</tr>\r\n<tr>\r\n<td width="83">选项</td>\r\n<td colspan="9" width="420">A 刑法 B 中国共产党党章 C 宪法 D 行政法</td>\r\n</tr>\r\n<tr>\r\n<td colspan="11" width="514">多选题</td>\r\n</tr>\r\n<tr>\r\n<td width="83">题目</td>\r\n<td colspan="2" width="195">下列对保密要害部位的表述正确的有</td>\r\n<td colspan="8" width="234">标记    （本试题作答时存在不确定性可做标记待后续检查）</td>\r\n</tr>\r\n<tr>\r\n<td width="83">选项</td>\r\n<td colspan="10" width="430">A 保密要害部位是指机关、单位日常工作中产生、传递、使用和管理绝密级的机构 B 保密要害部位是机关内部涉及重要国家秘密事项的最小行政单位 C 保密要害部位是存放、保管涉密载体的最小专用、独立、固定场所 D 保密要害部位是指机关、单位内部集中制作、存储、保管涉密载体的专门场所</td>\r\n</tr>\r\n<tr>\r\n<td colspan="17" width="576">单选题</td>\r\n</tr>\r\n<tr>\r\n<td width="83">题目</td>\r\n<td colspan="2" width="195">定密责任人制度的本质是</td>\r\n<td colspan="14" width="296">标记    （本试题作答时存在不确定性可做标记待后续检查）</td>\r\n</tr>\r\n<tr>\r\n<td width="83">选项</td>\r\n<td colspan="16" width="492">A 解决部分机关、单位长期以来的定密不规范行为的重要制度 B 由定密责任人具体负责本单位国家秘密的确定、变更和解除工作 C 由定密责任人具体承担本单位国家秘密的确定是否正确的责任 D 实现定密，全民提升保守国家秘密能力的基本制度保障</td>\r\n</tr>\r\n<tr>\r\n<td colspan="12" width="524">单选题</td>\r\n</tr>\r\n<tr>\r\n<td width="83">题目</td>\r\n<td colspan="2" width="195">（ ）是构成国家秘密的实质要素。</td>\r\n<td colspan="9" width="245">标记    （本试题作答时存在不确定性可做标记待后续检查）</td>\r\n</tr>\r\n<tr>\r\n<td width="83">选项</td>\r\n<td colspan="11" width="440">A 在特定时间内的事项 B 依照有关规定确定 C 关系国家安全和利益 D 特定范围的人员知悉</td>\r\n</tr>\r\n<tr>\r\n<td colspan="13" width="535">单选题</td>\r\n</tr>\r\n<tr>\r\n<td width="83">题目</td>\r\n<td colspan="2" width="195">国家秘密的确定要遵循（ ）和（ ）</td>\r\n<td colspan="10" width="255">标记    （本试题作答时存在不确定性可做标记待后续检查）</td>\r\n</tr>\r\n<tr>\r\n<td width="83">选项</td>\r\n<td colspan="12" width="451">A 定密范围、定密程序 B 定密权限、定密程序 C 定密范围、定密权限 D 定密期限、定密权限</td>\r\n</tr>\r\n<tr>\r\n<td colspan="16" width="566">多选题</td>\r\n</tr>\r\n<tr>\r\n<td width="83">题目</td>\r\n<td colspan="2" width="195">对国家秘密载体与密品的关系，理解正确的是</td>\r\n<td colspan="13" width="286">标记    （本试题作答时存在不确定性可做标记待后续检查）</td>\r\n</tr>\r\n<tr>\r\n<td width="83">选项</td>\r\n<td colspan="15" width="482">A 国家秘密载体包括密品 B 国家秘密载体本身是不含秘密的，而密品本身就是秘密 C 国家秘密载体与密品是两个完全不同的概念 D 密品包含国家秘密载体</td>\r\n</tr>\r\n<tr>\r\n<td colspan="14" width="545">多选题</td>\r\n</tr>\r\n<tr>\r\n<td width="83">题目</td>\r\n<td colspan="2" width="195">《保密法》规定，在公开发布信息前进行保密审查坚持的原则有</td>\r\n<td colspan="11" width="265">标记    （本试题作答时存在不确定性可做标记待后续检查）</td>\r\n</tr>\r\n<tr>\r\n<td width="83">选项</td>\r\n<td colspan="13" width="461">A 事前审查原则 B 谁公开谁审查原则 C 依法审查原则 D 事后审查原则</td>\r\n</tr>\r\n<tr>\r\n<td colspan="15" width="555">多选题</td>\r\n</tr>\r\n<tr>\r\n<td width="83">题目</td>\r\n<td colspan="2" width="195">涉密信息系统保密管理制度包括</td>\r\n<td colspan="12" width="276">标记    （本试题作答时存在不确定性可做标记待后续检查）</td>\r\n</tr>\r\n<tr>\r\n<td width="83">选项</td>\r\n<td colspan="14" width="471">A 涉密信息系统自行卸载和修改安全技术程序的管理制度 B 涉密信息系统固定进行的网络连接制度 C 涉密信息系统实行分级保护制度 D 涉密信息系统建设实行同步规划，同步建设和同步使用的技术防护制度</td>\r\n</tr>\r\n</tbody>\r\n</table>', '保密考试答案2', '', 'publish', 'open', 'open', '', '%e4%bf%9d%e5%af%86%e8%80%83%e8%af%95%e7%ad%94%e6%a1%882', '', '', '2017-05-03 10:35:57', '2017-05-03 02:35:57', '', 0, 'http://bm.yangyongquan.com/?p=158', 0, 'post', '', 0),
(152, 1, '2017-05-03 10:07:32', '2017-05-03 02:07:32', '<table>\r\n<tbody>\r\n<tr>\r\n<td width="371">第1题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">（），中央文明委召开电视电话会议，印发《关于深入开展道德领域突出问题专项教育和治理活动的意见》 A.2001年9月 B.2010年3月 C.2012年11月 D.2013年3月 答案:D</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：D</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：4</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：4.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第2题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">职业道德是从事一定（　　）的人在特定的工作中以其内心信念和特殊社会手段来维系的、以善恶进行评价的心理意识、行为准则和行为规范的总和。 A.管理 B.职业劳动 C.试验检测 D.事业 答案:B</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：B</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：4</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：4.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第3题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">关于进一步加强和规范公路水运工程试验检测工作的若干意见（交质监发[2013]114号）》指出，试验检测工作对公路水运工程质量安全的（　　）日益突显，要切实发挥好试验检测在质量安全监管中的基础性、关键性作用。 A.控制作用 B.支撑作用 C.指导作用 D.基础保障作用 答案:D</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：D</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：4</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：4.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第4题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">公路水运工程试验检测遵守的基本职业道德要求是，爱岗敬业，诚实守信；（　　），保证质量／不造假。 A.认真操作 B.严谨操作 C.规范操作 D.科学控制 答案:C</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：C</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：4</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：4.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第5题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">《关于进一步加强和规范公路水运工程试验检测工作的若干意见（交质监发[2013]114号）》提出，（　　）试验检测数据造假以及在考试、证书管理等环节的弄虚作假行为。 A.严肃处理 B.严厉打击 C.正确处理 D.正确对待 答案:B</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：B</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：4</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：4.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第6题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">《交通建设试验检测行业从业自律公约》要求，试验检测人员必须严守（　　）和工作程序，独立开展试验检测工作，保证试验检测数据科学、客观、公正、准确，并对试验检测结果承担法律责任。不造假数据、不出假证明、不做假鉴定、不做假报告。 A.职业道德准则 B.廉洁自律 C.工作规则 D.操作规程 答案:A</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：A</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：4</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：4.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第7题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">《公路工程质量检验评定标准》3.2.4规定，（　　）应有完整的施工原始记录、试验数据、分项工程自查数据等质量保证资料。 A.建设单位 B.监理单位 C.施工单位 D.档案部门 答案:C</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：C</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：4</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：4.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第8题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">《公路工程施工监理规范》5.1.11规定，监理工程师对已完工程实体质量的抽检频率应不低于施工单位自检频率的（　　）。 A.10％ B.20％ C.30％ D.40％ 答案:B</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：B</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：4</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：4.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第9题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">职业道德规范在从业人员思想及行为中的体现，是从业人员在一系列道德行为中所表现出来的（　　）的特征和倾向。 A.比较稳定 B.可靠 C.代表性 D.明显 答案:A</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：A</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：4</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：4.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第10题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">当前公路水运工程建设管理中要求更加注重（　　）、环保和耐久 A.质量 B.受控 C.安全 D.科学 答案:C</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：C</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：4</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：4.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第11题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">《公民道德建设实施纲要》提出，要大力倡导以（）、奉献社会为主要内容的职业道德，鼓励人们在工作中做一个好建设者。 A.爱岗敬业 B.诚实守信 C.办事公道 D.服务群众 答案:A,B,C,D</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：A,B,C,D</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：6</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：6.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第12题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">《质量发展纲要（2011-2020年）》提出，加快检验检测技术保障体系建设，对技术机构进行分类指导和监管，（），提升社会公信力。 A.规范检验检测行为 B.促进技术机构完善内部管理和激励机制 C.提高检验检测质量和服务水平 D.保证工程质量 答案:A,B,C</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：B,C</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：6</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：0.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第13题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">试验检测在公路水运工程质量管理中的作用包括（）和作为管理依据等。 A.指导施工 B.控制质量 C.评价质量 D.进行鉴定 答案:A,B,C</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：6</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：0.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第14题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">检测人员应当严守职业道德和工作程序，独立开展检测工作，保证试验检测数据（），并对试验检测结果承担法律责任。 A.真实 B.科学 C.客观 D.公正 答案:B,C,D</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：A,B,C</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：6</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：0.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第15题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">《公民道德建设实施纲要》提出，在全社会大力倡导爱国守法、（）的基本道德规范。 A.明礼诚信 B.团结友善 C.勤俭自强 D.敬业奉献 答案:A,B,C,D</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：A,B,C,D</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：6</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：6.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第16题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">2001年9月，中共中央印发《公民道德建设实施纲要》（中发[2001]15号） 答案:正确</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：正确</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：6</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：6.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第17题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">《交通建设试验检测行业从业自律公约》要求，试验检测人员要清正廉洁，不得借工作之便推销建设材料、构配件和设备。不得向客户索取钱物，不收受客户的任何礼金和礼品。 答案:正确</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：正确</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：6</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：6.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第18题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">《公路沥青路面施工技术规范》指出，按照美国的理论，检测指标总的变异性是取样代表性不足造成的变异性、试验方法精度方面造成的变异性和材料及施工过程本身的变异性之和。 答案:正确</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：正确</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：6</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：6.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第19题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">试验检测是公路水运工程质量安全管理的重要手段，真实、准确、客观、公正的试验检测数据是控制和评判工程质量、保障工程施工安全和运营安全的重要依据和基本前提。 答案:正确</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：正确</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：6</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：6.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第20题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">《建设工程质量管理条例》第三十条规定，建设单位必须建立、健全施工质量的检验制度，严格工序管理，作好隐蔽工程的质量检查和记录。 答案:错误</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：错误</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：6</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：6.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">试卷总得分：82.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">试卷总批注：</td>\r\n</tr>\r\n</tbody>\r\n</table>', '2014试验人员继续教育职业道德试题', '', 'publish', 'open', 'open', '', '2014%e8%af%95%e9%aa%8c%e4%ba%ba%e5%91%98%e7%bb%a7%e7%bb%ad%e6%95%99%e8%82%b2%e8%81%8c%e4%b8%9a%e9%81%93%e5%be%b7%e8%af%95%e9%a2%98', '', '', '2017-05-03 10:07:32', '2017-05-03 02:07:32', '', 0, 'http://bm.yangyongquan.com/?p=152', 0, 'post', '', 0),
(153, 1, '2017-05-03 10:07:32', '2017-05-03 02:07:32', '<table>\r\n<tbody>\r\n<tr>\r\n<td width="371">第1题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">（），中央文明委召开电视电话会议，印发《关于深入开展道德领域突出问题专项教育和治理活动的意见》 A.2001年9月 B.2010年3月 C.2012年11月 D.2013年3月 答案:D</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：D</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：4</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：4.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第2题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">职业道德是从事一定（　　）的人在特定的工作中以其内心信念和特殊社会手段来维系的、以善恶进行评价的心理意识、行为准则和行为规范的总和。 A.管理 B.职业劳动 C.试验检测 D.事业 答案:B</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：B</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：4</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：4.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第3题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">关于进一步加强和规范公路水运工程试验检测工作的若干意见（交质监发[2013]114号）》指出，试验检测工作对公路水运工程质量安全的（　　）日益突显，要切实发挥好试验检测在质量安全监管中的基础性、关键性作用。 A.控制作用 B.支撑作用 C.指导作用 D.基础保障作用 答案:D</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：D</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：4</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：4.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第4题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">公路水运工程试验检测遵守的基本职业道德要求是，爱岗敬业，诚实守信；（　　），保证质量／不造假。 A.认真操作 B.严谨操作 C.规范操作 D.科学控制 答案:C</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：C</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：4</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：4.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第5题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">《关于进一步加强和规范公路水运工程试验检测工作的若干意见（交质监发[2013]114号）》提出，（　　）试验检测数据造假以及在考试、证书管理等环节的弄虚作假行为。 A.严肃处理 B.严厉打击 C.正确处理 D.正确对待 答案:B</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：B</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：4</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：4.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第6题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">《交通建设试验检测行业从业自律公约》要求，试验检测人员必须严守（　　）和工作程序，独立开展试验检测工作，保证试验检测数据科学、客观、公正、准确，并对试验检测结果承担法律责任。不造假数据、不出假证明、不做假鉴定、不做假报告。 A.职业道德准则 B.廉洁自律 C.工作规则 D.操作规程 答案:A</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：A</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：4</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：4.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第7题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">《公路工程质量检验评定标准》3.2.4规定，（　　）应有完整的施工原始记录、试验数据、分项工程自查数据等质量保证资料。 A.建设单位 B.监理单位 C.施工单位 D.档案部门 答案:C</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：C</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：4</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：4.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第8题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">《公路工程施工监理规范》5.1.11规定，监理工程师对已完工程实体质量的抽检频率应不低于施工单位自检频率的（　　）。 A.10％ B.20％ C.30％ D.40％ 答案:B</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：B</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：4</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：4.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第9题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">职业道德规范在从业人员思想及行为中的体现，是从业人员在一系列道德行为中所表现出来的（　　）的特征和倾向。 A.比较稳定 B.可靠 C.代表性 D.明显 答案:A</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：A</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：4</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：4.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第10题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">当前公路水运工程建设管理中要求更加注重（　　）、环保和耐久 A.质量 B.受控 C.安全 D.科学 答案:C</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：C</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：4</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：4.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第11题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">《公民道德建设实施纲要》提出，要大力倡导以（）、奉献社会为主要内容的职业道德，鼓励人们在工作中做一个好建设者。 A.爱岗敬业 B.诚实守信 C.办事公道 D.服务群众 答案:A,B,C,D</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：A,B,C,D</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：6</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：6.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第12题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">《质量发展纲要（2011-2020年）》提出，加快检验检测技术保障体系建设，对技术机构进行分类指导和监管，（），提升社会公信力。 A.规范检验检测行为 B.促进技术机构完善内部管理和激励机制 C.提高检验检测质量和服务水平 D.保证工程质量 答案:A,B,C</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：B,C</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：6</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：0.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第13题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">试验检测在公路水运工程质量管理中的作用包括（）和作为管理依据等。 A.指导施工 B.控制质量 C.评价质量 D.进行鉴定 答案:A,B,C</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：6</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：0.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第14题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">检测人员应当严守职业道德和工作程序，独立开展检测工作，保证试验检测数据（），并对试验检测结果承担法律责任。 A.真实 B.科学 C.客观 D.公正 答案:B,C,D</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：A,B,C</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：6</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：0.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第15题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">《公民道德建设实施纲要》提出，在全社会大力倡导爱国守法、（）的基本道德规范。 A.明礼诚信 B.团结友善 C.勤俭自强 D.敬业奉献 答案:A,B,C,D</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：A,B,C,D</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：6</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：6.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第16题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">2001年9月，中共中央印发《公民道德建设实施纲要》（中发[2001]15号） 答案:正确</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：正确</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：6</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：6.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第17题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">《交通建设试验检测行业从业自律公约》要求，试验检测人员要清正廉洁，不得借工作之便推销建设材料、构配件和设备。不得向客户索取钱物，不收受客户的任何礼金和礼品。 答案:正确</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：正确</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：6</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：6.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第18题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">《公路沥青路面施工技术规范》指出，按照美国的理论，检测指标总的变异性是取样代表性不足造成的变异性、试验方法精度方面造成的变异性和材料及施工过程本身的变异性之和。 答案:正确</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：正确</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：6</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：6.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第19题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">试验检测是公路水运工程质量安全管理的重要手段，真实、准确、客观、公正的试验检测数据是控制和评判工程质量、保障工程施工安全和运营安全的重要依据和基本前提。 答案:正确</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：正确</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：6</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：6.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">第20题</td>\r\n</tr>\r\n<tr>\r\n<td width="371">《建设工程质量管理条例》第三十条规定，建设单位必须建立、健全施工质量的检验制度，严格工序管理，作好隐蔽工程的质量检查和记录。 答案:错误</td>\r\n</tr>\r\n<tr>\r\n<td width="371">您的答案：错误</td>\r\n</tr>\r\n<tr>\r\n<td width="371">题目分数：6</td>\r\n</tr>\r\n<tr>\r\n<td width="371">此题得分：6.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">批注：</td>\r\n</tr>\r\n<tr>\r\n<td width="371"></td>\r\n</tr>\r\n<tr>\r\n<td width="371">试卷总得分：82.0</td>\r\n</tr>\r\n<tr>\r\n<td width="371">试卷总批注：</td>\r\n</tr>\r\n</tbody>\r\n</table>', '2014试验人员继续教育职业道德试题', '', 'inherit', 'closed', 'closed', '', '152-revision-v1', '', '', '2017-05-03 10:07:32', '2017-05-03 02:07:32', '', 152, 'http://bm.yangyongquan.com/2017/05/03/152-revision-v1/', 0, 'revision', '', 0);
INSERT INTO `wp_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES
(157, 1, '2017-05-03 10:23:04', '2017-05-03 02:23:04', '保密法律法规知识竞赛试题\r\n\r\n&nbsp;\r\n\r\n一、单项选择题（共20题，每题1.5分）\r\n\r\n1、《中华人民共和国保守国家秘密法》由中华人民共和国第十一届全国人民代表大会常务委员会第十四次会议于2010年4月29日修订通过，自（ C ）起施行。\r\n\r\nA、2008年10月1日\r\n\r\nB、2009年10月1日\r\n\r\nC、2010年10月1日\r\n\r\nD、2011年10月1日\r\n\r\n&nbsp;\r\n\r\n2、 国家秘密是（  B ），依照法定程序确定，在一定时间内只限一定范围的人员知悉的事项。\r\n\r\nA、关系企业安全和利益\r\n\r\nB、关系国家安全和利益\r\n\r\nC、关系单位安全和利益\r\n\r\nD、关系公民个人安全和利益\r\n\r\n&nbsp;\r\n\r\n3、机密级国家秘密是重要的国家秘密，泄露会使国家安全和利益（  C  ）。\r\n\r\nA、遭受损害\r\n\r\nB、遭受一般损害\r\n\r\nC、遭受严重的损害\r\n\r\nD、遭受特别严重的损害\r\n\r\n&nbsp;\r\n\r\n4、 国家秘密的知悉范围以外的人员，因工作需要知悉国家秘密的，应当经过（ D ）批准。\r\n\r\nA、上级主管部门\r\n\r\nB、保密行政管理部门\r\n\r\nC、办公室主任\r\n\r\nD、机关、单位负责人\r\n\r\n&nbsp;\r\n\r\n5、机关、单位定密工作的直接依据是（  A  ）。\r\n\r\nA、国家秘密及其密级的具体范围\r\n\r\nB、国家秘密事项一栏表\r\n\r\nC、上级文件的密级、保密期限和知悉范围\r\n\r\nD、保密法及有关规定\r\n\r\n&nbsp;\r\n\r\n6、《中华人民共和国保守国家秘密法实施条例》，自（ D  ）起施行。\r\n\r\nA、2011年3月1日\r\n\r\nB、2012年3月1日\r\n\r\nC、2013年3月1日\r\n\r\nD、2014年3月1日\r\n\r\n7、涉密人员不得在手机中存储涉及国家秘密的信息，不得在手机通话中涉及国家秘密事项，不得（  C  ）。\r\n\r\nA、用手机发送涉及工作秘密的信息\r\n\r\nB、用手机发送涉及商业秘密的信息\r\n\r\nC、用手机发送涉及国家秘密的信息\r\n\r\nD、用手机发送涉及个人隐私的信息\r\n\r\n&nbsp;\r\n\r\n8、涉密人员保密宣传教育一般应采取经常性保密教育和专门保密培训相结合方式，根据核心、重要和一般涉密人员的岗位特点和管理要求，采取相应的形式抓好（   A  ）各环节的保密宣传教育。\r\n\r\nA、上岗、在岗和离岗\r\n\r\nB、初任、任职和在职\r\n\r\nC、招聘、录用和解聘\r\n\r\nD、长职、晋级\r\n\r\n&nbsp;\r\n\r\n9、机关、单位发现国家秘密已经泄露或者可能泄露的，应当立即采取补救措施，并在（ B ）小时内向同级保密行政管理部门和上级主管部门报告。\r\n\r\nA、12\r\n\r\nB、24\r\n\r\nC、36\r\n\r\nD、48\r\n\r\n&nbsp;\r\n\r\n10、涉密网络中介质交叉使用的风险是指（  C  ）。\r\n\r\nA、硬盘等磁介质存在数据丢失的可能\r\n\r\nB、移动存储介质易发生丢失，导致泄密\r\n\r\nC、在涉密计算机上使用非涉密移动存储介质或在非涉密计算机上使用涉密移动存储介质，导致涉密信息极易被窃取\r\n\r\nD、利用移动存储介质在不同涉密机上拷贝信息，易导致病毒木马传播\r\n\r\n&nbsp;\r\n\r\n11、下列涉及国家安全和利益的事项，泄露后可能损害（  D  ）应当确定为国家秘密。\r\n\r\nA、保密工作责任制落实情况\r\n\r\nB、保密制度建设情况\r\n\r\nC、国家秘密载体管理情况\r\n\r\nD、国家在政治、经济、国防、外交等领域的安全和利益\r\n\r\n&nbsp;\r\n\r\n12、国家秘密及其密级的具体范围由（ A  ）规定。\r\n\r\nA、国家保密行政管理部门分别会同外交、公安、国家安全和其他中央有关机关\r\n\r\nB、科研单位\r\n\r\nC、各单位主要领导\r\n\r\nD、机关、单位负责人其指定人员\r\n\r\n&nbsp;\r\n\r\n13、机关、单位对是否属于国家秘密或者属于何种密级不明确或者有争议的，由（  D  ）确定。\r\n\r\nA、单位主要领导\r\n\r\nB、单位领导班子\r\n\r\nC、县（市）领导\r\n\r\nD、国家保密行政管理部门或者省、自治区、直辖市保密行政管理部门\r\n\r\n&nbsp;\r\n\r\n14、国家秘密的本质属性是（  B ）。\r\n\r\nA、依照法律程序确定\r\n\r\nB、关系国家安全和利益\r\n\r\nC、在一定时间内保密\r\n\r\nD、只限一定范围的人员知悉\r\n\r\n&nbsp;\r\n\r\n15、机关、单位公开发布信息应当坚持“谁公开，谁审查”，事前审查和依法审查的原则。在工作程序上，一般可分为（ A ）。\r\n\r\nA、信息提供部门自审、信息公开工作机构专门审查、主管领导审核批准三个环节\r\n\r\nB、信息提供部门请第三方代审、信息公开工作机构专门审查、主管领导审核批准三个环节\r\n\r\nC、信息提供部门自审、信息提供部门复审、主管领导审核批准三个环节\r\n\r\nD、信息提供部门自审、主管领导审核批准两个环节\r\n\r\n&nbsp;\r\n\r\n16、公民、法人或其他组织认为行政机关不依法履行政府信息公开义务的，可能性向上级行政机关、（ C ）举报，收到举报的机关应予调查处理。\r\n\r\nA、公安机关或政府信息公开工作主管部门\r\n\r\nB、组织部门或政府信息公开工作主管部门\r\n\r\nC、监察机关或政府信息公开工作主管部门\r\n\r\nD、司法部门或政府信息公开工作主管部门\r\n\r\n&nbsp;\r\n\r\n17、涉密信息系统应当由（ D ）设立或者授权的保密测评机构进行检测评估，并经设区的市、自治州以上保密行政管理部门审查合格，方可投入使用。\r\n\r\nA、县级国家保密行政管理部门\r\n\r\nB、当地政府行政管理部门\r\n\r\nC、中央、国务院\r\n\r\nD、国家保密行政管理部门\r\n\r\n&nbsp;\r\n\r\n18、机关、单位对符合保密法的规定，但保密事项范围没有规定的不明确事项，应当先行拟定密级、保密期限和知悉范围，采取相应的保密措施，并自拟定之日起（ A ）日内报有关部门审定。\r\n\r\nA、10\r\n\r\nB、15\r\n\r\nC、20\r\n\r\nD、5\r\n\r\n&nbsp;\r\n\r\n19、涉密人员分为（  D ）人员、重要涉密人员、一般涉密人员。\r\n\r\nA、非常重要\r\n\r\nB、十分重要\r\n\r\nC、特别重要\r\n\r\nD、核心涉密\r\n\r\n&nbsp;\r\n\r\n20、一般涉密人员的脱密期为（ A ）。\r\n\r\nA、1-2年\r\n\r\nB、2-3年\r\n\r\nC、3-5年\r\n\r\nD、10年\r\n\r\n&nbsp;\r\n\r\n21、涉密载体是指经文字、数据符号、图形、声音为方式记载国家秘密信息的纸介质、光介质、（ C ）等各类物品。\r\n\r\nA、U盘\r\n\r\nB、移动硬盘\r\n\r\nC、电磁介质\r\n\r\nD、磁盘\r\n\r\n&nbsp;\r\n\r\n22、机关、单位对需要销毁的涉密载体，应当认真履行清点、登记手续，报（ A  ）审核批准，并在送销前存放在符合安全保密的专门场所。\r\n\r\nA、本机关、本单位主管领导\r\n\r\nB、本单位办公室主任\r\n\r\nC、本级保密行政管理部门\r\n\r\nD、上级业务主管部门\r\n\r\n&nbsp;\r\n\r\n23、保密行政管理部门对公民举报、机关和单位报告、保密检查发现、有关部门移送的涉嫌泄露国家秘密的线索和案件，应当依法（  C  ）或者组织、督促有关机关、单位调查处理。\r\n\r\nA、及时上报\r\n\r\nB、及时处罚\r\n\r\nC、及时调查\r\n\r\nD、及时通报\r\n\r\n&nbsp;\r\n\r\n24、机关、单位发生泄露国家秘密案件不按照规定报告或者未采取补救措施的，对直接负责的主管人员和（  C  ）依法给予处分。\r\n\r\nA、分管领导\r\n\r\nB、单位主要负责人\r\n\r\nC、其他直接责任人\r\n\r\nD、文秘人员\r\n\r\n&nbsp;\r\n\r\n25、国家秘密的保密期限，除另有规定外，绝密级不超过（ D  ）。\r\n\r\nA、十年\r\n\r\nB、十五年\r\n\r\nC、二十年\r\n\r\nD、三十年\r\n\r\n&nbsp;\r\n\r\n26、设区的市、自治州一级的机关及其授权的机关、单位可能确定（ B ）国家秘密。\r\n\r\nA、绝密级和机密级\r\n\r\nB、机密级和秘密级\r\n\r\nC、机密级\r\n\r\nD、秘密级\r\n\r\n&nbsp;\r\n\r\n27、（ B  ）、行政学院、干部学院、保密学院和各级培训机构在保密宣传教育工作中发挥阵地作用，是开展保密宣传的重要平台。\r\n\r\nA、保密教育培训基地\r\n\r\nB、各级党校\r\n\r\nC、大学\r\n\r\nD、保密学院\r\n\r\n&nbsp;\r\n\r\n28、地方各级保密行政管理部门接到泄密报告的，应当在24小时内（ C ）。\r\n\r\nA、报至上级保密行政管理部门\r\n\r\nB、逐级报至中央\r\n\r\nC、逐级报至国家保密行政管理部门\r\n\r\nD、逐级报至国务院\r\n\r\n&nbsp;\r\n\r\n29、保密法制的作用从方式看，主要有引导作用、规范作用、调节作用、（  C  ）。\r\n\r\nA、推动作用\r\n\r\nB、实际作用\r\n\r\nC、制裁作用\r\n\r\nD、激励作用\r\n\r\n&nbsp;\r\n\r\n30、《中国人产党纪律处分条例》、《中共中央保密委员会关于党政领导干部保密工作责任制的规定》明确规定，对不认真发行保密工作领导责任制、疏于保密管理或在保密工作方面失职的领导干部（  A  ）。\r\n\r\nA、实行责任追究制\r\n\r\nB、降级处分\r\n\r\nC、党内警告处分\r\n\r\nD、通报批评\r\n\r\n&nbsp;\r\n\r\n31．国家秘密变更的内容，包括密级的(B)、保密期限的(B)、知悉范围的(B)，三者即可以单独变更，也可以同时变更。\r\n\r\nA降低  缩短  缩小\r\n\r\nB降低或提高  缩短或延长  缩小或扩大\r\n\r\nC提高  延长  扩大    D降低  缩短或延长  缩小\r\n\r\n&nbsp;\r\n\r\n32．涉密岗位，是指在日常工作中(C)或者(C)接触、知悉国家秘密事项的岗位。\r\n\r\nA产生  经常        B经管  偶尔\r\n\r\nC产生  经管  经常  D产生  经管  偶尔\r\n\r\n&nbsp;\r\n\r\n33．确因工作需要，且目的地不通外交信使，携带(A)国家秘密载体出境的，应当经中央和国家机关保密工作机构或地市级（含）以上地方保密行政管理部门批准。\r\n\r\nA秘密级  B机密级绝密级\r\n\r\nC机密级  D秘密级机密级\r\n\r\n34．绝密级国家秘密载体(C)携带出境。\r\n\r\nA按需要   B可以    C不得    D审查后\r\n\r\n&nbsp;\r\n\r\n35．设有机要文件交换站的城市，在市内传递(B)涉密载体，可以通过机要交换站进行。\r\n\r\nA绝密级、机密级、秘密级   B机密级、秘密级\r\n\r\nC机密级                   D秘密级\r\n\r\n&nbsp;\r\n\r\n36．摘录、引用国家秘密内容形成的涉密载体，应(B)。\r\n\r\nA  按新生成密件管理，重新确定密级、保密期限和知悉范围\r\n\r\nB按原件密级、保密期限和知悉范围管理\r\n\r\nC按秘密级密件管理\r\n\r\nD按机密级密件管理\r\n\r\n37．管理绝密级涉密载体，未经原定密机关、单位或者其上级机关批准，(C)。\r\n\r\nA也可复制、摘抄  B可适度摘抄\r\n\r\nC不得复制、摘抄  D只能复制一份\r\n\r\n3．处理绝密级信息的计算机，应采用(D)\r\n\r\nA多种字符和数字混合编制的口令\r\n\r\nB IC卡或USB Key与口令相结合方式\r\n\r\nC自己喜欢且容易记住的话来设定口令，并进行个性化改造\r\n\r\nD指纹、虹膜等强身份鉴别方式\r\n\r\n&nbsp;\r\n\r\n38．某商业银行支行原行长李某因工作调动，按要求对文件、资料进行清理，李某应该(B)\r\n\r\nA只将“红头文件”整理归档即可\r\n\r\nB将个人使用和管理的涉密载体全部清理，退还原工作单位\r\n\r\nC整理后的各类资料可以与报纸一起出售\r\n\r\nD将个人使用和管理的各类载体全部清理，退还原工作单位\r\n\r\n&nbsp;\r\n\r\n39．涉密计算机改作非涉密计算机使用，应当经过机关、单位批准，并采取(A)的安全技术处理措施。\r\n\r\nA拆除信息存储部件  B删除涉密文件\r\n\r\nC格式化硬盘        D硬盘分区\r\n\r\n&nbsp;\r\n\r\n40．(D)可真正保障涉密计算机及信息系统不受来自公共信息网络的黑客攻击，同时也为涉密计算机及信息系统划定了明确的安全边界。\r\n\r\nA隔离卡               B安全保密防护设备\r\n\r\nC安全保密防护软件     D物理隔离\r\n\r\n&nbsp;\r\n\r\n41．涉密计算机可以使用(C)。\r\n\r\nA  无线网卡  B无线键盘  C打印机    D蓝牙传输器\r\n\r\n&nbsp;\r\n\r\n42．机关、单位应建立互联网接入审批和登记制度。中央和国家机关各部门互联网接入口数量原则上不超过(A)，省级以下党政机关逐步实现互联网(A)接入。\r\n\r\nA两个    集中      B三个    集中\r\n\r\nC两个    分部门    D三个    分部门\r\n\r\n43．机关、单位应建立健全互联网信息发布保密审查制度，指定机构和人员负责拟在互联网发布信息的保密审查，并建立(A)。审查应坚持(A)、全面审查，并综合分析信息关联性，防止因数据汇聚涉及国家秘密。\r\n\r\nA审查记录档案  一事一审  B信息发布档案  集中审查\r\n\r\nC审查记录档案  一周二审  D信息发布档案  一月一审\r\n\r\n&nbsp;\r\n\r\n44．涉密人员不得在手机中存储(C)的工作单位、职务等敏感信息，不得启用手机的远程数据同步功能。\r\n\r\nA一般涉密人员     B重要涉密人员\r\n\r\nC核心涉密人员     D各级涉密人员\r\n\r\n&nbsp;\r\n\r\n45．核心涉密人员、重要涉密人员的手机出现故障或发现异常情况时应立即(B)，并在指定地点维修，无法恢复使用的应按涉密器材销毁。\r\n\r\nA关机    B报告   C停机  D更换号码\r\n\r\n&nbsp;\r\n\r\n46．普通电话、专网电话、公网电话等与公共信息网络连接，其通信内容可通过串音、搭线或电磁辐射进行窃听。铺设保密电话线路时，应与普通电话、专网电话、公网电话线路(A)，可以避免()泄密。\r\n\r\nA不靠近、不平行  串音   B不靠近、不平行  搭线\r\n\r\nC平行铺设  串音         D不靠近、不平行  电磁辐射\r\n\r\n&nbsp;\r\n\r\n47．传真涉密信息，必须使用(D)批准使用的加密传真机，只能传输(D)信息，绝密级信息应送当地机要部门译发。\r\n\r\nA保密行政管理部门  秘密级\r\n\r\nB国家密码管理部门  秘密级\r\n\r\nC保密行政管理部门  机密级和秘密级\r\n\r\nD国家密码管理部门  机密级和秘密级\r\n\r\n&nbsp;\r\n\r\n48．中央国家机关下属单位和省级以下机关、单位确定保密要害部门部位，应报(B)审核确认。\r\n\r\nA  国家保密行政管理部门\r\n\r\nB  中央国家机关保密工作机构或省级保密行政管理部门\r\n\r\nC  国家保密行政管理部门或中央国家机关保密工作机构\r\n\r\nD  中央国家机关保密工作机构\r\n\r\n&nbsp;\r\n\r\n49．下列(A)可能定为保密要害部门。\r\n\r\nA科技处  B保密室  C档案室  D涉密信息系统机房\r\n\r\n&nbsp;\r\n\r\n50．涉密会议、活动的保密工作实行(D)的原则。\r\n\r\nA谁监督，谁负责  B谁主管，谁负责\r\n\r\nC谁承办，谁负责  D谁主办，谁负责\r\n\r\n&nbsp;\r\n\r\n51．涉密网络建设完成后，应当经(C)审批，方可报项目审批部门组织峻工验收。\r\n\r\nA本单位信息中心     B公安机关\r\n\r\nC保密行政管理部门   D本单位保密委\r\n\r\n&nbsp;\r\n\r\n52．机关、单位涉密网络使用管理，应依据(D)严格设定用户权限，按照(D)原则，控制国家秘密信息知悉范围。\r\n\r\nA行政级别  最高密级防护和最小授权管理\r\n\r\nB岗位职责  适当密级防护和适当授权管理\r\n\r\nC行政级别  最高密级防护和适当授权管理\r\n\r\nD岗位职责  最高密级防护和最小授权管理\r\n<ol start="53">\r\n 	<li>5 机关、单位确定保密要害部门部位属于（B）。</li>\r\n</ol>\r\nA 资源行为   B 法定义务   C 社会义务   D 自主活动\r\n\r\n&nbsp;\r\n\r\n54．重大涉密会议、活动应当请(A)对保密工作进行监督和指导，并提供必要的(A)。\r\n\r\nA保密行政管理部门  安全保密技术服务保障\r\n\r\nB保密行政管理部门  技术检查设备\r\n\r\nC主办单位保密工作机构  安全保密技术服务保障\r\n\r\nD主办单位保密工作机构  技术检查设备\r\n\r\n55．涉密视频会议系统应当按照(C)有关要求进行建设和管理。\r\n\r\nA涉密通信及办公自动化设备    B涉密移动存储介质\r\n\r\nC涉密网络                    D内部网络\r\n\r\n&nbsp;\r\n\r\n56．国家统一考试保密管理工作由(C)负责。\r\n\r\nA教育部                B保密行政管理部门\r\n\r\nC组织考试的主管部门    D人力资源和社会保障部\r\n\r\n57．测绘成果资料由(A)提供。\r\n\r\nA测绘管理部门  B测绘队  C借领单位  D档案部门\r\n\r\n&nbsp;\r\n\r\n58．提出借领绝密级测绘成果资料的申请，应报(C)部门或(C)批准。\r\n\r\nA省级测绘行政主管  省级保密行政管理部门\r\n\r\nB省级保密行政管理  国家测绘行政主管部门\r\n\r\nC省级测绘行政主管  国家测绘行政主管部门\r\n\r\nD省级保密行政管理  国家保密局\r\n\r\n&nbsp;\r\n\r\n59．国家秘密技术出口，由申请单位或个人按照行政隶属关系报省、自治区、直辖市、计划单列市科技工作主管部门审查后，报科技部审批的是(B)。\r\n\r\nA秘密级技术    B机密级技术\r\n\r\nC绝密级技术    D各类秘密技术\r\n\r\n&nbsp;\r\n\r\n60．保密法第四十八条是对十二项严重违规行为法律责任的规定，这一规定表明(A)，应依法追究责任。\r\n\r\nA不论是否产生泄密实际后果，只要发生所列举的严重违规行为之一的\r\n\r\nB发生所列举的严重违规行为任何一项，且产生泄密实际后果的\r\n\r\nC不论是否产生泄密实际后果，发生两项以上严重违规行为的\r\n\r\nD产生泄密实际后果的违规行为\r\n\r\n&nbsp;\r\n<ol start="61">\r\n 	<li>6 共产党员丢失秘密文件资料或者泄露党和国家秘密，情节严重的，给予(C)处分。</li>\r\n</ol>\r\nA撤销党内职务    B严重警告\r\n\r\nC开除党籍        D留党察看\r\n\r\n&nbsp;\r\n\r\n62．保密法自(B)起施行。\r\n\r\nA 2010年4月29日    B 2010年10月1日\r\n\r\nC 2010年10月7日    D 2010年4月30日\r\n\r\n63．国家秘密区别于其他秘密的关键是(A)\r\n\r\nA关系国家安全和利益    B依照法定程序确定\r\n\r\nC在一定时间内保密      D只限一定范围的人员知悉\r\n\r\n&nbsp;\r\n\r\n64．我国保密工作体制的核心是(A)。\r\n\r\nA党管保密    B一个机构，两块牌子\r\n\r\nC依法管理    D依法行政\r\n\r\n65．保密工作是为维护国家安全和利益，将(C)控制在一定范围和时间内，防止泄露或被非法利用，由国家专门机构组织实施的活动。\r\n\r\nA秘密         B敏感信息\r\n\r\nC国家秘密     D国家秘密、工作秘密等\r\n<ol start="66">\r\n 	<li>6 (D)是党中央统一领导党政军保密工作的领导机构。</li>\r\n</ol>\r\nA国家保密局               B国家安全委员会\r\n\r\nC中央保密委员会办公室     D中央保密委员会\r\n\r\n&nbsp;\r\n\r\n67．业务工作接受上级业务部门垂直管理的单位，保密工作(A)。\r\n\r\nA以上级业务部门管理为主，同时接受地方保密行政管理部门的指导\r\n\r\nB以地方保密行政管理部门为主，同时接受上级业务部门的指导\r\n\r\nC接受上级业务部门和地方保密行政管理部门的双重管理\r\n\r\nD自主管理，同时接受上级业务部门的指导\r\n\r\n&nbsp;\r\n\r\n68．1997年印发的(D)，高度概括了新中国建立以来，特别是改革开放以来保密工作的基本经验，提出了新时期保密工作的基本任务，指明了新形势下保密工作的发展方向。\r\n\r\nA《中华人民共和国保守国家秘密法》\r\n\r\nB《关于加强保密工作的通知》\r\n\r\nC《高级干部保守党和国家秘密的规定》\r\n\r\nD《中共中央关于加强新形势下保密工作的决定》\r\n\r\n&nbsp;\r\n\r\n69．在保密工作手段上，要积极建立(D)的综合防范体系，不断提高发现和消除泄密隐患和风险的能力。\r\n\r\nA攻防一体    B专兼结合\r\n\r\nC知己知彼    D“人防、物防、技防”三位—体\r\n\r\n70．(D)是“一个机构，两块牌子”。\r\n\r\nA各级党委保密委员会办公室与保密工作机构\r\n\r\nB各级党委保密委员会与保密工作机构\r\n\r\nC各级党委保密委员会与各级保密行政管理部门\r\n\r\nD各级党委保密委员会办公室与各级保密行政管理部门\r\n\r\n&nbsp;\r\n\r\n71．我国最早的保密立法始予(A)。\r\n\r\nA西周    B秦汉    C隋唐    D明清\r\n\r\n72．下列(D)不属于保密法制的功能。\r\n\r\nA规范功能  B引导功能  C制裁功能  D参考功能\r\n<ol start="5">\r\n 	<li>随着信息时代特别是网络代的到来，(B)被称为“第五空间”。</li>\r\n</ol>\r\nA领土  B信息空间  C领空   D领海\r\n\r\n&nbsp;\r\n\r\n&nbsp;\r\n\r\n73．中国共产党建党以来第一份关于保密工作的专门文件是(B)。\r\n\r\nA《中国共产党第—个纲领》\r\n\r\nB《加强党的秘密工作通告》\r\n\r\nC《关于秘书工作技术问题的通知》\r\n\r\nD《中共中央关于建立保密工作通告》\r\n\r\n&nbsp;\r\n\r\n74．下列不属于我国保密法律制度体系的是(B)\r\n\r\nA保密法        B公司法\r\n\r\nC国家保密标准  D相关司法解释\r\n\r\n75．我国保密法律制度体系以(C)为核心。\r\n\r\nA宪法    B刑法    C保密法    D中国共产党章程\r\n\r\n&nbsp;\r\n\r\n76．一份保密期限为10年的机密级文件，正确的密级标注为(C)。\r\n\r\nA机密10年      B 10年★机密\r\n\r\nC机密★10年     D机密●10年\r\n\r\n&nbsp;\r\n\r\n77．国家秘密的保密期限届满时，应(C)。\r\n\r\nA适当延长保密期限  B自行公开\r\n\r\nC自行解密          D作为工作秘密管理\r\n\r\n&nbsp;\r\n\r\n78．(C)不可以确定绝密级国家秘密。\r\n\r\nA国家体育总局      B司法部\r\n\r\nC济南市人民政府    D重庆市人民改府\r\n\r\n&nbsp;\r\n<ol start="79">\r\n 	<li>7 机关、单位定密工作的直接依据是（A）。</li>\r\n</ol>\r\nA国家秘密及其密级的具体范围   B国家保密事项一览表\r\n\r\nC上级文件的密级期限和知悉范围 D保密法及有关规定\r\n\r\n&nbsp;\r\n<ol start="80">\r\n 	<li>80.定密工作程序为：由（A）对照保密事项范围提出国家秘密确定、变更和解除的具体意见，再由（）审核批准并承担（）。</li>\r\n</ol>\r\nA承办人  定密责任人  法律责任\r\n\r\nB定密责任人  定密小组组长  行政责任\r\n\r\nC承办人  定密小组组长  法律责任\r\n\r\nD承办人  定密责任人  行政责任\r\n\r\n&nbsp;\r\n\r\n81.（D）专业正式列入《普通高等学校本科专业目录（2012）》，实现了保密学历教育的历史性突破。\r\n\r\nA保密技术    B信息安全\r\n\r\nC保密法学    D保密管理\r\n\r\n&nbsp;\r\n<ol start="82">\r\n 	<li>8 核心涉密场所禁止带入手机，重要涉密场所禁止使用手机，一般涉密场所（B）。</li>\r\n</ol>\r\nA禁止使用手机     B限制使用手机\r\n\r\nC可以使用手机     D定时使用手机\r\n\r\n&nbsp;\r\n<ol start="83">\r\n 	<li>8 机关、单位定密工作的直接依据是（A）。</li>\r\n</ol>\r\nA国家秘密及其密级的具体范围   B国家保密事项一览表\r\n\r\nC上级文件的密级期限和知悉范围 D保密法及有关规定\r\n\r\n&nbsp;\r\n<ol start="84">\r\n 	<li>8 定密工作程序为：由（A）对照保密事项范围提出国家秘密确定、变更和解除的具体意见，再由（）审核批准并承担（）。</li>\r\n</ol>\r\nA承办人  定密责任人  法律责任\r\n\r\nB定密责任人  定密小组组长  行政责任\r\n\r\nC承办人  定密小组组长  法律责任\r\n\r\nD承办人  定密责任人  行政责任\r\n\r\n&nbsp;\r\n\r\n85.（D）专业正式列入《普通高等学校本科专业目录（2012）》，实现了保密学历教育的历史性突破。\r\n\r\nA保密技术    B信息安全\r\n\r\nC保密法学    D保密管理\r\n\r\n&nbsp;\r\n<ol start="86">\r\n 	<li>8 核心涉密场所禁止带入手机，重要涉密场所禁止使用手机，一般涉密场所（B）。</li>\r\n</ol>\r\nA禁止使用手机     B限制使用手机\r\n\r\nC可以使用手机     D定时使用手机\r\n\r\n&nbsp;\r\n<ol start="87">\r\n 	<li>8 安全保密产品的检测证书有效期通常（B ）。</li>\r\n</ol>\r\nA 2年     B 3年     C 5年\r\n\r\nD在产品形态不改变的前提下，终身有效\r\n\r\n&nbsp;\r\n<ol start="88">\r\n 	<li>8 《报告涉露国家秘密事件的规定》第三条规定，发生泄密事件的机关、单位，应当在发现后的（A）内，书面向有关保密工作部门或机构报告。</li>\r\n</ol>\r\nA 24小时    B 12小时    C 36小时    D 48小时\r\n\r\n&nbsp;\r\n<ol start="89">\r\n 	<li>8 以下不属于保密违法行为的是（D）。</li>\r\n</ol>\r\nA 私自买卖涉密地图\r\n\r\nB 利用连接互联网计算机存储、处理绝密信息\r\n\r\nC 将涉密计算机连接互联网\r\n\r\nD 按照国家有关规定对涉密载体进行销毁\r\n\r\n&nbsp;\r\n\r\n90．给受检单位的检查通知一般应当（D）。\r\n\r\nA不发通知             B提前7个工作日发出\r\n\r\nC提前3个工作日发出   D提前1—2个工作日发出\r\n\r\n&nbsp;\r\n<ol start="91">\r\n 	<li>9 涉密信息系统测评中属于一票否决项的是（A）。</li>\r\n</ol>\r\nA物理隔离、信息传输密码保护\r\n\r\nB密级标识、用户口令强度\r\n\r\nC访问控制、使用移动存储介质\r\n\r\nD使用移动存储介质、用户身份鉴别\r\n\r\n&nbsp;\r\n\r\n92． 关于国家秘密载体销毁的程序及有关规定正确的是（D）。\r\n\r\nA只要通过本单位主管部门审核批准，要立即进行销毁\r\n\r\nB确因工作需要，自行销毁少量国家秘密载体时，应严格履行清点、登记和审批手续，使用本单位具备的销毁设备和方法进行了销毁\r\n\r\nC送销国家秘密载体，应当分类封装，安全运送，如无特殊情况，无需派专人现场监销\r\n\r\nD应将需要销毁的国家秘密载体送交保密行政管理部门设立的销毁工作机构或者保密行政管理部门指定的单位\r\n\r\n&nbsp;\r\n<ol start="93">\r\n 	<li>9 领导同志处、核心涉密部门场所选设备应符合（）标准，优先考虑（C）设备。</li>\r\n</ol>\r\nA IS09001   进口    B国内信息安全认证   功能齐全\r\n\r\nC国家保密  国产    D国办认证  性能好\r\n\r\n&nbsp;\r\n<ol start="94">\r\n 	<li>9 保密行政管理部门确定重点区域应当按照（A）原则，以（A）为最小单位。</li>\r\n</ol>\r\nA最小化  县级行政区划\r\n\r\nB积极防范  县级行政区划\r\n\r\nC最小化   市级行政区划\r\n\r\nD积极防范  市级行政区划\r\n\r\n&nbsp;\r\n<ol start="95">\r\n 	<li>9 （D）承担国家秘密教育培训规划制定，保密教育培训组织实施，保密教育培训教材、师资建设，保密学科建设等重要职责。</li>\r\n</ol>\r\nA国家保密学院    B国家行政学院\r\n\r\nC中央党校        D国家保密教育培训基地\r\n\r\n&nbsp;\r\n\r\n&nbsp;\r\n\r\n96．非密事项需发传真、电报的（B）。\r\n\r\nA可以使用密码传真、密码电报\r\n\r\nB不得使用密码传真、密码电报\r\n\r\nC有时可以使用密码传真、密码电报\r\n\r\nD使用密码传真、密码电报应当严格遵守规定\r\n\r\n&nbsp;\r\n<ol start="97">\r\n 	<li>97. 涉密打印机与涉密计算机之间（D）。</li>\r\n</ol>\r\nA采用无线连接方式应当严格遵守规定\r\n\r\nB可以采用无线连接方式\r\n\r\nC有时采用无线连接方式\r\n\r\nD不能采用无线连接方式\r\n\r\n&nbsp;\r\n\r\n98 保放结合，是指在开展保密工作时，要正确处理保密与信息公开的关系，做到（C）。\r\n\r\nA保要害 保重点   B保中心 保重点\r\n\r\nC保核心 保重点   D保核心 保要害\r\n\r\n&nbsp;\r\n\r\n99．定密授权机关在作出定密授权决定时，应当明确一定的授权期限。一般而言，定密授权期限最长不超过(C)。\r\n\r\nA 1年    B 3年    C 5年    D 10年\r\n\r\n&nbsp;\r\n\r\n100．《国家秘密定密管理暂行规定》第九条规定：没有定密权但经常产生国家秘密事项的机关、单位，或者虽有定密权但经常产生超出其定密权限的国家秘密事项的机关、单位，可以向授权机关申请定密授权。这里“经常”是指(C)。\r\n\r\nA 3年来年均产生5件以上国家秘密事项\r\n\r\nB 2年来年均产生6件以上国家秘密事项\r\n\r\nC 3年来年均产生6件以上国家秘密事项\r\n\r\nD 2年来年均产生5件以上国家秘密事项\r\n\r\n&nbsp;\r\n<ol start="101">\r\n 	<li>101. 法宝的定密责任人，是指法律明确规定作为定密责任人的人员，即机关、单位负责人。机关、单位负责人一般是指机关、单位的（A）。</li>\r\n</ol>\r\nA正职负责人         B领导班子\r\n\r\nC保密委员会主任     D纪委书记\r\n\r\n&nbsp;\r\n\r\n102． 承办人，是指根据机关、单位内部职责分工，负责具体处理、办理涉及国家秘密事项的工作人员。承办人是（B）。\r\n\r\nA定密业务培训的组织者\r\n\r\nB定密流程中第一个环节工作的执行者\r\n\r\nC拟公开发布信息的保密审查者\r\n\r\nD定密异议的受理者\r\n\r\n&nbsp;\r\n<ol start="103">\r\n 	<li>103. 下列哪一个选项不能确定为保密期限（D）。</li>\r\n</ol>\r\nA 10年                    B 2015年5月1日之前\r\n\r\nC外交部发言人公开宣布前   D《大公报》的公开报道前\r\n\r\n&nbsp;\r\n\r\n104． 在（D）情况下，机关单位定密时才可以将有关事项的保密期限确定为长期。\r\n\r\nA法定定密责任人认为有必要的\r\n\r\nB绝密级已满三十年保密期的\r\n\r\nC知悉范围很小的\r\n\r\nD保密事项范围明确规定某一项国家秘密事项保密期限为长期的\r\n\r\n&nbsp;\r\n<ol start="105">\r\n 	<li>105. 在实际工作中，一些单位存在党、政各有一把手的情况。这些单位在确定法定定密责任人时，（C）。</li>\r\n</ol>\r\nA只能确定党委一把手作为法定定密责任人\r\n\r\nB从两人中选举产生一位法定定密切责任人\r\n\r\nC可以确定两人同时为法定定密责任人\r\n\r\nD应报请上级主管部门确定法定定密责任人\r\n\r\n&nbsp;\r\n<ol start="106">\r\n 	<li>106. 国有企业虽然一定行政级别，但不属于保密法规定的具有法定定密权的机关范畴。金融机构应向（A）申请授权。</li>\r\n</ol>\r\nA银监会   B中国银行   C国资会   D国家保密局\r\n\r\n&nbsp;\r\n<ol start="107">\r\n 	<li>107. 下列说法正确的是（A）。</li>\r\n</ol>\r\nA无论机关单位是否具有相应的定密权限，都可以进行派生定密\r\n\r\nB派生定密需要定密授权\r\n\r\nC涉及绝密级国家秘密事项的派生定密需要定密授权\r\n\r\nD派生定密无需定密授权，介只能确定密级\r\n\r\n&nbsp;\r\n<ol start="108">\r\n 	<li>108. 定密的根本依据是（C）。</li>\r\n</ol>\r\nA保密事项范围    B定密目录\r\n\r\nC保密法          D国家秘密定密管理暂行规定\r\n\r\n&nbsp;\r\n<ol start="109">\r\n 	<li>109. 国家秘密标志不正确的是（A）。</li>\r\n</ol>\r\nA秘密★15年         B机密★2015年12月31日\r\n\r\nC秘密★会议开始前    D绝密★长期\r\n\r\n&nbsp;\r\n<ol start="110">\r\n 	<li>110. 机关单位应当每（B）对所确定的国家秘密进行审核。</li>\r\n</ol>\r\nA半年     B一年     C两年    D五年\r\n\r\n&nbsp;\r\n<ol start="111">\r\n 	<li>111. 机关单位对不明确事项，应当先行拟定密级、保密期限和知悉范围，采取相应的保密措施，并自拟定之日起（B）个工作日内报有关部门确定。</li>\r\n</ol>\r\nA  5      B  10     C  15      D  20\r\n\r\n&nbsp;\r\n\r\n112 对已经移交各级国家档案馆的涉密档案，应由（B）组织进行解密审核。\r\n\r\nA移交部门               B档案馆\r\n\r\nC同级保密行政管理部门   D上级档案行政管理部门\r\n\r\n&nbsp;\r\n<ol start="113">\r\n 	<li>113. 机关单位延长所确定的国家秘密的保密期限，累计超过保密事项范围规定的期限，应当（C）。</li>\r\n</ol>\r\nA报同级保密行政管理部门批准\r\n\r\nB报本单位保密委员会批准\r\n\r\nC报规定该保密事项范围的中央有关机关批准\r\n\r\nD解密\r\n\r\n&nbsp;\r\n\r\n114．突出重点是保密检查的原则之一，关于突出重点，下列说法错误的是(C)。\r\n\r\nA把服从服务党和国家中心工作作为重点\r\n\r\nB把关系政治、经济、外交、国防等战略性、全局性核心国家秘密作为重点\r\n\r\nC把所有机关单位和涉密人员作为重点\r\n\r\nD把发生重大泄密事件的机关、单位，以及工作中容易发生泄密的薄弱环节作为重点\r\n\r\n&nbsp;\r\n\r\n115．党政机关和涉密单位对需要维修维护的设备产品，应当认真履行(B)手续，并存放在(B)的专门场所。\r\n\r\nA清点、登记  处级以上办公\r\n\r\nB清点、登记、审批符合安全保密要求\r\n\r\nC清点、登记  符合安全保密要求\r\n\r\nD清点、登记、审批  处级以上办公\r\n\r\n&nbsp;\r\n\r\n116．中央和国家机关各部门发生泄密事件，应向(B)报告。\r\n\r\nA国务院办公厅    B国家保密局\r\n\r\nC公安部          D北京市保密局\r\n\r\n&nbsp;\r\n\r\n117．涉密人员不得在手机中存储涉及国家秘密的信息，不得在手机通话中涉及国家秘密事项，不得 (C)\r\n\r\nA用手机发送涉及工作秘密的信息\r\n\r\nB用手机发送涉及商业秘密的信息\r\n\r\nC用手机发送涉及国家秘密的信息\r\n\r\nD用手机发送涉及个人隐私的信息\r\n\r\n&nbsp;\r\n<ol start="118">\r\n 	<li>118. 下列不属于违反保密法律应承担的责任的是(C)。</li>\r\n</ol>\r\nA行政责任    B刑事责任   C民事责任    D党纪处分\r\n\r\n&nbsp;\r\n\r\n119.国家秘密的变更是指(A)的变更。\r\n\r\nA密级、保密期限、知悉范围\r\n\r\nB 保密期限、知悉范围、涉密内容\r\n\r\nC保密期限、知悉范围\r\n\r\nD密级、保密期限、知悉范围、涉密内容\r\n\r\n&nbsp;\r\n\r\n120.某机密级文件保密期限为20年。8年后，该文件根据工作需要降低为秘密级国家秘密，其保密期限最长还有(C)年。\r\n\r\nA  10年  B 12年  C  2年   D  5年\r\n\r\n&nbsp;\r\n\r\n&nbsp;\r\n\r\n121．机关单位执行中央下发的机密级文件，执行过程中产生的文件资料，应当确定为(B)。\r\n\r\nA秘密级国家秘密    B机密级国家秘密\r\n\r\nC绝密级国家秘密    D内部事项\r\n\r\n&nbsp;\r\n\r\n122．保密行政管理部门受理鉴定申请后，应当(A)出具鉴定结论；不能按期出具鉴定结论的，经保密行政管理部门负责众批准，可以(  )。\r\n\r\nA自受理之日起30日内  延长30日\r\n\r\nB 自受理之日起15日内  延长15日\r\n\r\nC自提出鉴定申请之日起30日内   延长30日\r\n\r\nD 自提出签定申请之日起15日内  延长1 5日\r\n\r\n&nbsp;\r\n\r\n二、多项选择题\r\n\r\n1、政府信息公开的原则包括（ABD）\r\n\r\nA、公正、公平、便民原则\r\n\r\nB、及时、准确原则\r\n\r\nC、服务领导原则\r\n\r\nD、保障公共利益原则\r\n\r\n&nbsp;\r\n\r\n2、各级政府应当建立健全政府信息公开（ABC），定期对政府信息公开工作进行考核、评议。\r\n\r\nA、考核制度\r\n\r\nB、社会评议制度\r\n\r\nC、责任追究制度\r\n\r\nD、审查制度\r\n\r\n&nbsp;\r\n\r\n3、1997年，党中央下发《中共中央关于加强新形势下保密工作的决定》明确提出，要全面提高保密干部的政治思想和业务素质，努力做好（ABCD）。\r\n\r\nA、业务精\r\n\r\nB、政治强\r\n\r\nC、作风正\r\n\r\nD、纪律严\r\n\r\n&nbsp;\r\n\r\n4、涉密人员上岗前需进行（ ACD ）。\r\n\r\nA、任前审查\r\n\r\nB、交接手续\r\n\r\nC、上岗培训\r\n\r\nD、上岗保密承诺\r\n\r\n&nbsp;\r\n\r\n5、涉密人员所签订的保密承诺书的主要内容包括（ABCD）等。\r\n\r\nA、了解并遵守各项保密制度\r\n\r\nB、知悉并履行保密义务\r\n\r\nC、自愿接受保密审查\r\n\r\nD、承担法律责任\r\n\r\n&nbsp;\r\n\r\n6、涉密载体可分为（ABC）\r\n\r\nA、纸介质涉密载体\r\n\r\nB、光介质涉密载体\r\n\r\nC、电磁介质涉密载体\r\n\r\nD、移动存储介质涉密载体\r\n\r\n&nbsp;\r\n\r\n7、机关、单位保密承诺书签订人员范围包括（ABCD）。\r\n\r\nA、领导干部，即现任地方各级各部门、各涉密单位副科级以上领导干部\r\n\r\nB、在岗涉密人员，包括在职、新任、借调、聘用等人员\r\n\r\nC、离岗涉密人员，包括退休、调离、辞职、辞退等人员\r\n\r\nD、其他可能接触、知悉国家秘密的人员\r\n\r\n&nbsp;\r\n\r\n8、保密法制的作用从方式看，主要有（ABCD）。\r\n\r\nA、引导作用\r\n\r\nB、规范作用\r\n\r\nC、制裁作用\r\n\r\nD、调节作用\r\n\r\n&nbsp;\r\n\r\n9、举办会议或者其他活动涉及国家秘密的，主办单位应当采取下列哪几项保密措施？（ABCD）\r\n\r\nA、根据会议、活动的内容确定密级，制定保密方案，限定参加人员范围\r\n\r\nB、按照国家保密规定管理国家秘密载体\r\n\r\nC、对参加人员提出具体保密要求\r\n\r\nD、使用符合国家保密规定和标准的场所、设施、设备\r\n\r\n&nbsp;\r\n\r\n10、保密宣传教育是一项长期性工作，要达到工作目标，取得实际效果，必须按照坚持正确方向、坚持联系实际、（ ABC）的基本要求开展工作。\r\n\r\nA、坚持分类施教\r\n\r\nB、坚持持之以恒\r\n\r\nC、坚持改革创新\r\n\r\nD、坚持务求实效\r\n\r\n&nbsp;\r\n\r\n11、信息公开保密审查应当依照下列程序（ABD）。\r\n\r\nA、信息产生机构提出是否公开信息的审查意见\r\n\r\nB、信息公开保密审查人员提出审核意见\r\n\r\nC、已确定为涉密或不宜公开的信息\r\n\r\nD、机关、单位负责人或被授权人审批\r\n\r\n&nbsp;\r\n\r\n12、下列哪几项是《政府信息公开条例》的有关规定。（ABCD）\r\n\r\nA、各级政府应当建立健全政府信息公开工作考核制度、社会评议制度和责任追究制度，定期限对政府信息公开工作进行考核、评议\r\n\r\nB、监察机关对信息公开保密审查情况监督检查\r\n\r\nC、各级行政机关定期公布本行政机关政府信息公开工作年度报告\r\n\r\nD、公民、法人或其他组织认为行政机关不依法履行政府信息公开义务的，可以向上级行政机关、监察机关或政府信息公开工作主管部门举报，收到举报的应予调查处理\r\n\r\n&nbsp;\r\n\r\n13、根据保密法和《报告泄露国家秘密事件的规定》，泄密案件报告可分为（ABC）。\r\n\r\nA、发现泄密案件的人员向有关机关、单位报告\r\n\r\nB、有关机关、单位向保密行政管理部门报告\r\n\r\nC、下级保密行政管理部门或保密工作机构向上级保密行政管理部门报告\r\n\r\nD、上级保密行政管理部门向国家保密行政管理部门报告\r\n\r\n&nbsp;\r\n\r\n14、保密违法案件查处的主要内容有（ABCD）。\r\n\r\nA、查明案情\r\n\r\nB、及时补救\r\n\r\nC、责任追究\r\n\r\nD、保密整改\r\n\r\n&nbsp;\r\n\r\n15、保密违法案件查处的基本原则有（ ABC）。\r\n\r\nA、国家安全和利益至上\r\n\r\nB、实事求是\r\n\r\nC、依法办案\r\n\r\nD、责任追究\r\n\r\n&nbsp;\r\n\r\n16、保密违法行为与侵犯国家秘密犯罪行为之间的区别有（BCD）。\r\n\r\nA、查处对象不同\r\n\r\nB、法律后果不同\r\n\r\nC、查处主体不同\r\n\r\nD、查处依据不同\r\n\r\n&nbsp;\r\n\r\n17、报告泄密案件，应当包括被泄露国家秘密事项的内容、密级、数量及载体形式；泄密案件的发现经过；泄密责任人的基本情况及（ABCD）。\r\n\r\nA、泄密案件发生的时间、地点及经过\r\n\r\nB、泄密案件造成或可能千万的危害\r\n\r\nC、已进行或拟进行的查处工作情况\r\n\r\nD、已采取或拟采取的补救措施\r\n\r\n&nbsp;\r\n\r\n18、保密教育培训的主要种类有（ABC）。\r\n\r\nA、岗前培训、在岗培训和离岗教育\r\n\r\nB、综合培训和专题培训\r\n\r\nC、资格培训和非资格培训\r\n\r\nD、专业培训和非专业培训\r\n\r\n&nbsp;\r\n\r\n19、下列应当确定为国家秘密的是（ABCD）。\r\n\r\nA、国家事务重大决策中的秘密事项\r\n\r\nB、国防建设和武装力量活动中的秘密事项\r\n\r\nC、外交和外事活动中的秘密事项以及对外承担保密义务的秘密事项\r\n\r\nD、科学技术中的秘密事项\r\n\r\n&nbsp;\r\n\r\n20、从事涉密业务的企业事业单位应当具备下列哪些条件？（ABCD）\r\n\r\nA、在中华人民共和国境内依法成立3年以上的法人，无违法犯罪记录及从事涉密业务的人员具有中华人民共和国国籍\r\n\r\nB、保密制度完善，有专门的机构或者人员负责保密工作\r\n\r\nC、用于涉密业务的场所、设施、设备符合国家保密规定和标准及具有从事涉密业务的专业能力\r\n\r\nD、法律、行政法规和国家保密行政管理部门规定的其他条件\r\n\r\n&nbsp;\r\n\r\n21、从事涉密业务企事业单位发生（ABCD）变更的，应当在变更后30个工作日内向省级保密行政管理部门书面报告。\r\n\r\nA、法定代表人\r\n\r\nB、单位名称\r\n\r\nC、注册地址、生产经营场所\r\n\r\nD、资本构成、经营范围、单位性质发生重大变化\r\n\r\n&nbsp;\r\n\r\n22、申报涉密项目的机关、单位（以下简称申报单位）应当提交（ABCD）及拟采取的保密管理和技术材料，其他与涉密项目申报相关的材料。\r\n\r\nA、申报审查确认的公文\r\n\r\nB、立项申请文件\r\n\r\nC、涉密项目的基本情况，包括名称、来源、背景、规模、实施计划以及主管单位等\r\n\r\nD、项目涉密的论证报告，包括项目密级、定密依据、涉密内容等。\r\n\r\n&nbsp;\r\n\r\n23、主办涉密会议、活动的单位需采取的保密管理措施包括严格参加人员审查、（ABD）、严格新闻报道。\r\n\r\nA、严格场所设备检查\r\n\r\nB、严格保密要求\r\n\r\nC、严格会议内容\r\n\r\nD、严格涉密载体管理\r\n\r\n&nbsp;\r\n\r\n24、对于非涉密网络，要坚持源头控制原则，确保（ AB）。\r\n\r\nA、上非涉密网络的信息不涉密\r\n\r\nB、涉密信息不上非涉密网络\r\n\r\nC、信息内容严格审查\r\n\r\nD、信息发布规范程序\r\n\r\n&nbsp;\r\n\r\n25、涉密人员的具体脱必期限由机关、单位保密工作机构会同有关业务主管部门根据其接触、知悉国家秘密的（ABD）等情况审查确定。\r\n\r\nA、密级\r\n\r\nB、数量\r\n\r\nC、工作年限\r\n\r\nD、时间\r\n\r\n&nbsp;\r\n\r\n26、对发生下列行为之一的档案服务机构，应撤销其云南省档案数字化服务机构备案证书。（ABCD）\r\n\r\nA、不接受档案、保密行政管理部门监督以及被要求限期整改，逾期不改的\r\n\r\nB、发生严重档案安全事故的及发生泄密事件的\r\n\r\nC、未按期限进行复查或未通过复查的\r\n\r\nD、两年内没有承接档案数字化工作的\r\n\r\n&nbsp;\r\n\r\n27、秘密可分为（ABCD）。\r\n\r\nA、个人隐私\r\n\r\nB、国家秘密\r\n\r\nC、工作秘密\r\n\r\nD、商业秘密\r\n\r\n&nbsp;\r\n\r\n28、国家秘密必须具备的基本要素有（ ABC）。\r\n\r\nA、关系国家利益\r\n\r\nB、依照法定程序确定\r\n\r\nC、在一定时间内只限一定范围的人员知悉\r\n\r\nD、受法律保护\r\n\r\n&nbsp;\r\n\r\n29、国家秘密与工作秘密的区别在于（ABCD）。\r\n\r\nA、关系的利益主体不同\r\n\r\nB、确定方式不同\r\n\r\nC、秘密标志不同\r\n\r\nD、管理方式和法律责任不同\r\n\r\n&nbsp;\r\n\r\n30、现行泄密案件报告制度实行（AC ）。\r\n\r\nA、一事一报制度\r\n\r\nB、半年报告制度\r\n\r\nC、年度综合报告制度\r\n\r\nD、季度报告制度\r\n\r\n&nbsp;\r\n<ol start="31">\r\n 	<li>31. 针对涉密网络存在的主要安全保密隐患，可采取的技术监管措施包扎（ABC）。</li>\r\n</ol>\r\nA网络终端监管    B存储介质监管\r\n\r\nC网络行为监管    D涉密文件特征检测监管\r\n<ol start="32">\r\n 	<li>3 磁介质载体的销毁包括（ABC），且必须满足国家保密标准《涉及国家秘密的载体销毁与信息消除安全保密要求》。</li>\r\n</ol>\r\nA物理粉碎      B强磁场消磁\r\n\r\nC数据写覆盖    D涂层防护\r\n\r\n&nbsp;\r\n\r\n33．具有法定定密权的机关包括(ABC)。\r\n\r\nA中央国家机关                 B省级机关\r\n\r\nC设区的市和自治州一级的机关   D县级机关\r\n\r\n&nbsp;\r\n\r\n34．《党政机关和涉密单位网络保密管理规定》对涉密网络(ABCD)等环节的保密管理提出明确要求。\r\n\r\nA密集确定、方案论证   B建设实施、测评审批\r\n\r\nC风险评估、重大变化   D 废止\r\n\r\n35.当前，非涉密网络是(ACD)。\r\n\r\nA 网络泄密的重灾区\r\n\r\nB 网络保密管理的“命根子”\r\n\r\nC 境外情报机构获取涉密信息的主渠道\r\n\r\nD 境外情报机构实施网络攻击窃密的“跳板”\r\n\r\n&nbsp;\r\n\r\n36．根据保密法实施条例的规定，定密授权的方式包括(BC)。\r\n\r\nA定时授权   B主动授权   C依申请授权   D单项授权\r\n\r\n&nbsp;\r\n\r\n37．关于国家秘密的变更，以下说法正确的是（ABD）。\r\n\r\nA 国家秘密“谁确定，谁变更，谁解除”\r\n\r\nB 国家秘密的变更应当由确定该国家秘密的主体负责\r\n\r\nC 国家秘密的变更应当由使用该国家秘密的主体负责\r\n\r\nD 国家秘密的变更可以由原定密机关单位的上级机关决定\r\n\r\n&nbsp;\r\n\r\n38．定密监督的方式主要包括(ABCD)。\r\n\r\nA定密检查    B法定定密责任人的监督\r\n\r\nC定密统计    D定密核查\r\n\r\n2．保密技术装备配备方式，包括(AC)。\r\n\r\nA强制配备  B自主配备  C指导配备  D统一配备\r\n\r\n&nbsp;\r\n<ol start="39">\r\n 	<li>3 下列事项中，（ABCD）不得确定为国家秘密。</li>\r\n</ol>\r\nA需要社会公众广泛知晓或者参与的\r\n\r\nB属于工作秘密、商业秘密、个人隐私的\r\n\r\nC已经依法公开或者无法控制知悉范围的\r\n\r\nD法律、法规或者国家有关规定要求公开的\r\n\r\n&nbsp;\r\n<ol start="40">\r\n 	<li>4 六部门联合下发的《关于进一步加强全国干部保密教育培训工作的通知》要求，把保密教育培训作为各级党政领导班子成员和中青年干部培训办公室内容，纳入（ABCD）。</li>\r\n</ol>\r\nA干部年度脱产培训计划   B网络在线学习\r\n\r\nC公务员职业道德教育计划\r\n\r\nD公务员初任、任职及其他相关培训\r\n\r\n&nbsp;\r\n<ol start="41">\r\n 	<li>41. 依据现行有效的人事工作和纪检监察工作保密事项范围，很多没有定密权的机关单位都涉及人事和纪检监察定密问题，以下正确的做法是（AD）。</li>\r\n</ol>\r\nA在向上级业务主管部门申请定密授权时，一并就该两项事项提出申请\r\n\r\nB向上级人事或纪检监察部门申请定密授权\r\n\r\nC按照有关保密事项范围或纪检监察部门申请定密，报同级保密行政管理部门备案\r\n\r\nD某设区的市财政局仅需要获得人事、纪检监察工作秘密级定密权时，向市政府提出授权申请\r\n\r\n&nbsp;\r\n<ol start="42">\r\n 	<li>4 禁止定密的事项包括（ABCD）。</li>\r\n</ol>\r\nA需要社会公众广泛知晓或者参与的\r\n\r\nB属于工作秘密、商业秘密、个人隐私的\r\n\r\nC已经依法公开或者无法控制知悉范围的\r\n\r\nD法律、法规或者国家有关规定要求公开的\r\n\r\n&nbsp;\r\n\r\n43．当前，保密工作的阶段性特征是(ACD)“三期叠加”。\r\n\r\nA尖锐复杂期 B转型过渡期 C转型升级期 D战略机遇期\r\n\r\n44．领导干部保密工作责任包括(ABCD)。\r\n\r\nA接受保密监督、检查和考核\r\n\r\nB严格管理亲属子女和身边工作人员\r\n\r\nC带头遵守保密纪律，学习保密知识技能\r\n\r\nD履行保密工作领导责任\r\n\r\n&nbsp;\r\n<ol start="45">\r\n 	<li>4 对检查中发现存在严重泄密隐患的网络、设施、设备和场所，检查人员应当立即向检查组负责人或者组织检查的保密行政管理部门报告，采取 (ABC)等处置措施。</li>\r\n</ol>\r\nA 责令停止使用\r\n\r\nB 断开网络连接\r\n\r\nC 封存设备\r\n\r\nD终止检查\r\n\r\n&nbsp;\r\n<ol start="46">\r\n 	<li>4 保密重区域包括（ABCD）。</li>\r\n</ol>\r\nA处于对敌斗争或反分裂斗争前沿的边疆、沿海地区\r\n\r\nB重要军事设施、国防军工单位连片集中地区\r\n\r\nC涉及国家安全和利益的重大工程、项目所在地区\r\n\r\nD全国及各省（区、市）政治、经济中心\r\n\r\n&nbsp;\r\n<ol start="47">\r\n 	<li>4 保密重点领域具体包括（ABC）等。</li>\r\n</ol>\r\nA测绘    B金融    C教育   D体育\r\n\r\n&nbsp;\r\n\r\n48.涉密人员有（ABCD）的权利。\r\n\r\nA参加保密教育培训    B行使保密监督\r\n\r\nC获得补偿            D要求配备保密设施设备\r\n\r\n&nbsp;\r\n\r\n49.根据国务院有关行政审批权，保密行政管理部门对(ABC)实行保密资质管理。\r\n\r\nA国家秘密载体制作复制单位\r\n\r\nB 涉及国家秘密的信息系统集成单位\r\n\r\nC武器装备科研生产单位\r\n\r\nD涉密工程建设单位\r\n\r\n&nbsp;\r\n\r\n50．机关、单位应当(ABCD)措施，加强涉密网络安全保密技术防护。\r\n\r\nA身份鉴别    B访问及信息流转控制\r\n\r\nC安全审计    D边世安全防护\r\n\r\n&nbsp;\r\n<ol start="51">\r\n 	<li>5 保密宣传教育的作用主要包括（ABCD）。</li>\r\n</ol>\r\nA  引导作用   B  规范作用\r\n\r\nC  推进作用   D  激励作用\r\n\r\n&nbsp;\r\n<ol start="52">\r\n 	<li>5 机关、单位应制定在编人员担任涉密网络的(B C D)</li>\r\n</ol>\r\nA网络巡查员          B 系统管理员\r\n\r\nC 安全保密管理员      D 安全审计员\r\n\r\n&nbsp;\r\n\r\n53．国家主管部门组织的(ABCD)等国家统一考试的试题、答案和评分标准，在启用前均属于国家秘密。\r\n\r\nA国家教育           B执（职）业资格\r\n\r\nC国家公务员录用     D专业技术人员资格\r\n\r\n&nbsp;\r\n\r\n54．保密法制的价值主要体现在(BD)几个方面。\r\n\r\nA规范保密管理行为   B维护国家安全和利益\r\n\r\nC确保公开           D保障公民正当权益\r\n\r\n&nbsp;\r\n<ol start="55">\r\n 	<li>5 机关、单位负责人及其指定的人员为定密责任人，负责本机关、本单位的国家秘密（ABC）工作。</li>\r\n</ol>\r\nA确定    B变更   C解除   D销毁\r\n\r\n&nbsp;\r\n<ol start="56">\r\n 	<li>5 保密干部应当具备的素质能力，包括（ABCD）。</li>\r\n</ol>\r\nA创新能力   B调研能力   C协调能力   D执行能力\r\n\r\n&nbsp;\r\n<ol start="57">\r\n 	<li>5 我国现行保密法律制度体系主要包括：宪法、保密法律、(ABCD)、国际公约或政府间协定的相关规定等。</li>\r\n</ol>\r\nA保密法规        B保密规章\r\n\r\nC国家秘密标准    D相关司法解释\r\n\r\n&nbsp;\r\n<ol start="58">\r\n 	<li>5 机关、单位负责人及其指定的人员为定密责任人，负责本机关、本单位的国家秘密（ABC）工作。</li>\r\n</ol>\r\nA确定    B变更   C解除   D销毁\r\n\r\n&nbsp;\r\n<ol start="59">\r\n 	<li>5 对国秘密确定、变更和解除情况的检查重点应为（ABC）。</li>\r\n</ol>\r\nA是否实行定密责任人制度，依法确定国家秘密事项和密级\r\n\r\nB是否准确标明国家秘密事项密级\r\n\r\nC是否根据情况变化及时变更和解除国家秘密事项密级\r\n\r\nD是否准确确定涉密人员涉密等级\r\n\r\n&nbsp;\r\n<ol start="60">\r\n 	<li>6 保密干部，是依照法律规定，组织开展保密工作的人员，包括（ABC）。</li>\r\n</ol>\r\nA各级保密委员会组成人员\r\n\r\nB各级保密行政管理部门工作人员\r\n\r\nC机关、单位涉密岗位的工作人员\r\n\r\nD各级保密工作机构的专兼职工作人员\r\n<ol start="61">\r\n 	<li>6 有关机关提起密级鉴定，应当提交下列材料（ABC）。</li>\r\n</ol>\r\nA提起密级鉴定的公文\r\n\r\nB需要进行密级鉴定的文件、资料和其他物品\r\n\r\nC进行密级鉴定工作需要掌握的有关情况，包括案件基本情况、主要情节、鉴定材料泄露对象和时间等\r\n\r\nD鉴定材料泄露时适用的保密法律法规、保密事项范围和密级变更、解密文件\r\n<ol start="62">\r\n 	<li>6 以下有密级鉴定权的保密部门是（AB）。</li>\r\n</ol>\r\nA  重庆市保密局    B  甘肃省保密局\r\n\r\nC  深圳市保密局    D  最高人民法院保密委员会办公室\r\n\r\n&nbsp;\r\n\r\n63．在境外活动时，遇到情报机构(ACD)时，要稳立场，巧妙处置，并及时通知我驻外使领馆。\r\n\r\nA策反     B宴请     C威胁      D讹诈\r\n<ol start="64">\r\n 	<li>6 任用、聘用的境外人员确需接触、知悉我国家秘密的，应按照(AC)原则，报国务院有关主管部门或者省、自治区、直辖市人民政府有关主管部门批准。</li>\r\n</ol>\r\nA谁主管、谁负责     B集中报审\r\n\r\nC一事一批           D方便工作\r\n\r\n&nbsp;\r\n\r\n65．保密法规定，各级保密行政管理部门中负有保密管理职责的人员滥用职权、玩忽职守、徇私舞弊的，依法给予处分；构成犯罪的，依法追究刑事责任。其中“玩忽职守”是指(BCD)的行为。\r\n\r\nA弄虚作假      B严重不负责任\r\n\r\nG不履行职责    D不正确履行职责\r\n\r\n66．保密法规定，各级保密行政管理部门中负有保密管理职责的人员滥用职权、玩忽职守、徇私舞弊的，依法给予处分；构成犯罪的，依法追究刑事责任。其中“滥用职权”是指(BD)的行为。\r\n\r\nA不正确履行职责    B违背法律授权宗旨行使职权\r\n\r\nC弄虚作假          D违反法律程序行使职权\r\n\r\n&nbsp;\r\n<ol start="67">\r\n 	<li>6 保密管理的基本要求主要包括（ABCD）。</li>\r\n</ol>\r\nA党管保密    B依法行政\r\n\r\nC保放结合    D综合防范\r\n\r\n&nbsp;\r\n\r\n68．涉密工程的保密管理环节包括(ABCD)。\r\n\r\nA确认    B设计    C建设    D使用\r\n\r\n&nbsp;\r\n\r\n69．涉密工程，是指(ACD)涉及国家秘密事项，公开后会危害国家安全和利益的建筑物的新建、改建、扩建、装修、拆除、修缮工程等。\r\n\r\nA用途    B外观    C功能   D关键部位\r\n\r\n&nbsp;\r\n\r\n70．参加涉外活动应注意(AC)。\r\n\r\nA不得带领境外人员到国家禁止其进入的涉密部门部位\r\n\r\nB同境外人员活动，谨慎携带国家秘密载体\r\n\r\nC须按事先确定的范围和口径与境外人员会谈\r\n\r\nD利用境外通信设施进行涉密联络时，注意保密\r\n\r\n&nbsp;\r\n\r\n71．对外交往合作中提供国家秘密事项的，应根据有关保密法律法规，与接受方签订保密协议，基本内容包括(ABCD)。\r\n\r\nA对外提供的国家秘密事项   B对外提供国家秘密的理由\r\n\r\nC承担的保密义务           D违约责任\r\n\r\n&nbsp;\r\n\r\n72．因工作需要携运属于国家秘密的文件、资料和其他物品出境，须(CD)。\r\n\r\nA自行妥善携运，确保安全\r\n\r\nB夹放在托运行李中悄悄携运\r\n\r\nC交由国家保密局核准的单位和人员携运\r\n\r\nD交由外交信使携运\r\n\r\n&nbsp;\r\n<ol start="73">\r\n 	<li>7  (AD)情况下需申请办理《国家秘密载体出境》许可证。</li>\r\n</ol>\r\nA目的地不通外交信使\r\n\r\nB携运密件赴亚洲以外国家\r\n\r\nC携运绝密级文件出境\r\n\r\nD外交信使难以携运\r\n\r\n&nbsp;\r\n<ol start="74">\r\n 	<li>7 国家秘密技术出口的审查原则是(BCD)。</li>\r\n</ol>\r\nA保障使用、应批尽批\r\n\r\nB维护国家技术优势和经济利益\r\n\r\nC贯彻我国外交路线、方针、政策\r\n\r\nD有利于扩大我国科技影响\r\n\r\n&nbsp;\r\n\r\n75．在境外活动要注意的保密事项有(ABCD)。\r\n\r\nA不随意谈论国家秘密，不议论所在国和第三国的敏感问题\r\n\r\nB不要把涉密文件或内部资料带入会谈场所\r\n\r\nC密电和涉密文件必须在我国驻外使领馆保密室草拟\r\n\r\nD不得使用境外人员使用的办公设备处理涉密信息\r\n\r\n&nbsp;\r\n\r\n76．国家秘密的基本属性包括(BCD)。\r\n\r\nA实用性  B专属性  C限定性  D法定性\r\n\r\n&nbsp;\r\n\r\n77．保密工作作为一门科学，有自身必须遵循的原则，包括最小化、(ABCD)原则。\r\n\r\nA全程化  B精准化   C自主化  D法制化\r\n\r\n&nbsp;\r\n\r\n78．保密法结合保密工作的特点和规律，在总结新时期党和国家保密工作实践经验的基础土，规定保密工作的方针，包括(CD)等。\r\n\r\nA综合防范  B精准管理  C依法管理  D保放适度\r\n\r\n&nbsp;\r\n\r\n79．保密工作的基本经验是(ABCD)。\r\n\r\nA党管保密  B专兼结合   C综合防范  D攻防一体\r\n\r\n&nbsp;\r\n\r\n80．下列属于中央和国家机关保密工作机构的职责的是(BD)。\r\n\r\nA管理本机关的业务及保密工作\r\n\r\nB对本系统的保密工作进行管理和指导\r\n\r\nC对本系统的业务工作进行管理和指导\r\n\r\nD管理本机关的保密工作\r\n\r\n&nbsp;\r\n\r\n81．下列属于我国刑法规定的与保守国家秘密有关的罪名是(BCD)\r\n\r\nA背叛国家罪\r\n\r\nB为境外窃取、刺探、收卖、非法提供国家秘密、情报罪\r\n\r\nC非法获取国家秘密罪\r\n\r\nD过失泄露国家秘密罪\r\n\r\n&nbsp;\r\n\r\n82．国家统一考试命题工作的保密要求有(ABD)。\r\n\r\nA对命题人员和内部工作人员进行审查\r\n\r\nB采取入闱工作形式\r\n\r\nC原始试题应存放在保险柜中，由一人专门保管\r\n\r\nD原始试题应存放在保险柜中，由两人专门保管\r\n\r\n&nbsp;\r\n\r\n83．在我国，保密法律责任主要包括(BC) 。\r\n\r\nA民事责任  B刑事责任  C行政责任  D违宪责任\r\n\r\n&nbsp;\r\n\r\n84．保密法确定了1 l项主要制度，其中包括(ABCD)等。\r\n\r\nA保密工作责任制度\r\n\r\nB保密法律责任制度\r\n\r\nC信息公开发布保密审查制度\r\n\r\nD企业事业单位从事涉密业务保密审查制度\r\n\r\n&nbsp;\r\n\r\n85．保密法强化涉密信息系统保密管理，硬措施主要包括(ABCD)。\r\n\r\nA实行分级保护\r\n\r\nB强化技术防护\r\n\r\nC明确禁止事项\r\n\r\nD明确网络运营商、服务商的法律责任\r\n\r\n&nbsp;\r\n\r\n86．确定保密要害部门部位应坚持(BD)的基本原则。\r\n\r\nA分类确定   B分级确定   C全程化   D最小化\r\n\r\n&nbsp;\r\n\r\n87．涉密人员严禁在(ABD)时填写机关、单位名称和地址等信息。\r\n\r\nA申请手机号码  B注册手机邮箱\r\n\r\nC购买苹果手旗  D开通其他功能\r\n\r\n&nbsp;\r\n\r\n88．互联网及其他公共信息网络运营商、服务商(ABC)，由公安机关或者国家安全机关、信息产业主管部门按照各自职责分工依法予以处罚。\r\n\r\nA不配合检察机关对泄密案件进行调查\r\n\r\nB 发现发布的泄密信息，没有立即停止传输，并报告\r\n\r\nC没有按要求及时删除发布的涉密信息\r\n\r\nD没有定期开展保密检查\r\n\r\n&nbsp;\r\n\r\n89．《行政机关公务员处分条例》第26条规定，泄露（ABCD），造成不良后果的，给予警告、记过或者记大过处分；情节较重的，给予降级或者撤职处分；情节严重的，给予开除处分。\r\n\r\nA 国家秘密                    B工作秘密\r\n\r\nC 因履行职责掌握的商业秘密    D个人隐私\r\n\r\n90．机关、单位违反保密法规定，发生重大泄密案件的，由有关机关、单位依法对(BC)给予处分。\r\n\r\nA保密办主任           B直接负责的主管人员\r\n\r\nC其他直接责任人员     D领导班子成员\r\n\r\n&nbsp;\r\n<ol start="91">\r\n 	<li>9  2011年9月，中共中央办公厅、国务院办公厅印发了《“十二五”时期全国保密事业发展规划，强调“十二五”时期，保密工作要基本健全(ABCD)的现代保密管理体系。</li>\r\n</ol>\r\nA以教育培训为先导    B以法规制度为基础\r\n\r\nC以监督检查为保证    D以科学技术为支撑\r\n\r\n&nbsp;\r\n\r\n92．涉密会议、活动主办单位应当采取(ABCD)保密措施。\r\n\r\nA严格参加人员审查    B严格涉密载体管理\r\n\r\nC严格场所设备检查    D严格新闻报道审查\r\n\r\n&nbsp;\r\n\r\n93．知悉涉密数据的人员(AD)。\r\n\r\nA应当作出保密承诺\r\n\r\nB可以以“预测”方式向个人提供数据\r\n\r\nC不得接受新闻单位采访\r\n\r\nD参加学术活动不得涉及涉密数据及相关信息\r\n\r\n&nbsp;\r\n\r\n&nbsp;\r\n\r\n94．核心涉密人员、重要涉密人员使用的手机应经过必要的安全检查，尽可能配备和使用专用手机，不得使用(BCD)的手机。\r\n\r\nA国外品牌        B未经入网许可\r\n\r\nC开通位置服务    D有连接互联网等功能\r\n\r\n&nbsp;\r\n\r\n95．处理涉密信息的(ABCD)等设备不能连入互联网、普通电话网等公共信息网络。\r\n\r\nA复印机  B多功能一体机   C扫描仪  D打印机\r\n\r\n&nbsp;\r\n\r\n96．保密要害部位应当是存放、保管涉密载体的(ACD)。\r\n\r\nA最小专用场所    B最小行政单位\r\n\r\nC独立场所        D  固定场所\r\n\r\n&nbsp;\r\n\r\n97．涉密会议、活动的承办单位应(CD)。\r\n\r\nA制定保密工作方案    B确定会议、活动的密级\r\n\r\nC提供安全保密的环境、设施和设备\r\n\r\nD对工作人员进行保密教育\r\n\r\n&nbsp;\r\n\r\n98．国家秘密的密级如有下列(BD)情形之一的，应当及时变更。\r\n\r\nA定密责任人认为需要变更\r\n\r\nB确定时依据的保密事项范围已作调整\r\n\r\nC泄露后对国家安全和利益的影响发生变化\r\n\r\nD泄露后对国家安全和利益的损害程度发生明显变化\r\n\r\n&nbsp;\r\n<ol start="99">\r\n 	<li>9 (ABC)人员不得任用、聘用为涉密人员。</li>\r\n</ol>\r\nA酗酒    B因严重违反保密规定被调离涉密岗位\r\n\r\nC受过刑事处罚    D受过警告处分\r\n\r\n&nbsp;\r\n\r\n100．涉密人员某些情况发生变化，应及时报告。须报告的重大事项有(ABD)。\r\n\r\nA发现针对本人的渗透行为 B子女获得境外永久居留资格\r\n\r\nC配偶出境旅游           D与境外人员结婚\r\n\r\n&nbsp;\r\n\r\n101．涉密人员上岗、在岗应该(ABCD)。\r\n\r\nA主动接受保密教育培训   B掌握保密知识技能\r\n\r\nC签订保密承诺书         D自觉接受保密监督检查\r\n\r\n&nbsp;\r\n\r\n102．涉密人员离岗、离职应遵守脱密期管理规定，包括脱密期内未经审查批准，(ABC)。\r\n\r\nA不得擅自出境                 B不得到外资企业工作\r\n\r\nC不得为境外人员提供咨询或服务 D不得为境内单位工作\r\n\r\n&nbsp;\r\n\r\n103．属于国家秘密的设备、产品（简称“密品”），是指直接含有国家秘密信息，或者通过(ABD)能够获取所承载的国家秘密信息的设备和产品。\r\n\r\nA观察    B测试    C询问    D分析\r\n\r\n&nbsp;\r\n\r\n104．收发涉密载体，应当履行(ABCD)手续。\r\n\r\nA清点  B登记  C编号  D签收\r\n\r\n4.查阅、收听、观看涉及国家秘密的信息，要严格遵守保密规定，未经批准，不得擅自(ACD)。\r\n\r\nA记录    B传播    C录音    D录像\r\n\r\n&nbsp;\r\n\r\n105．携带涉密载体外出或参加涉外活动，必须(ABC)，确保涉密载体始终处于有效监控之下。\r\n\r\nA确因工作需要    B经过本机关、本单位主管领导批准\r\n\r\nC采取保密措施    D保证载体连接互联网\r\n\r\n&nbsp;\r\n\r\n106．维修涉密载体，应(ABD)。\r\n\r\nA由本机关、本单位专门技术人员负责\r\n\r\nB需外单位人员维修的，要由本机关、本单位有关人员现场监督\r\n\r\nC请载体制造商派人维修，必要时可带走，保证尽快恢复使用\r\n\r\nD需送外维修的，应当送保密行政管理部门审查批准的定点单位\r\n\r\n&nbsp;\r\n\r\n107．机构撤销、合并时，原机构的涉密载体应根据不同情况，分别移交给(ABC)。移交时，须履行登记、签收手续。\r\n\r\nA制发单位        B档案管理部门\r\n\r\nC合并后的新单位  D相关管理人员\r\n\r\n&nbsp;\r\n\r\n108．不要以(ABCD)作为涉密计算机的口令。\r\n\r\nA姓名    B生日    C英文单词    D手机号\r\n\r\n&nbsp;\r\n\r\n109．涉密计算机不可以接入(ABCD)。\r\n\r\nA互联网  B有线电视网  C  固定电话网  D移动通信网\r\n\r\n&nbsp;\r\n\r\n110．计算机网络防火墙不能(ABCD)。\r\n\r\nA防止数据驱动式攻击\r\n\r\nB防止感染了病毒的软件或文件的传输\r\n\r\nC防范不经由防火墙产生的攻击\r\n\r\nD防范来自内部的攻击\r\n\r\n&nbsp;\r\n<ol start="111">\r\n 	<li>111. 将非涉密信息复制到涉密计算机，应(ABD)。</li>\r\n</ol>\r\nA对复制的数据进行病毒查杀  B使用一次性光盘导入\r\n\r\nC使用U盘导入  D使用经过国家保密行政管理部门批准的信息单向导入设备\r\n\r\n&nbsp;\r\n\r\n112.《党政领导干部保密工作责任制规定》创设了(ABC)等制度\r\n\r\nA述职    B考核    C约谈    D传讯\r\n\r\n&nbsp;\r\n\r\n113．常见的窃听方式有(ABCD)。\r\n\r\nA有线搭线窃听       B无线窃听\r\n\r\nC激光探测窃听       D定向探测窃听\r\n\r\n&nbsp;\r\n\r\n114.涉密网络“三员”的基本职责表述正确的是(AD)。\r\n\r\nA安全审计员主要负责对其他“两员’的操作行为进行审计、跟踪、分析和监督检查\r\n\r\nB系统管理员主要负责对其他“两员”的操作行为进行审计、跟踪、分析和监督检查\r\n\r\nC 安全保密管理员主要负责涉密网络的日常运行维护工作\r\n\r\nD安全保密管理员主要负责涉密网络的日常安全保密管理工作\r\n\r\n&nbsp;\r\n\r\n115．《审计工作国家秘密范围的规定》应当规定该领域国家秘密事项的(AB)。\r\n\r\nA具体名称和密级    B保密期限和知悉范围\r\n\r\nC承办人资格标准    D定密责任人资格标准\r\n\r\n&nbsp;\r\n\r\n116．保密行政管理部门调查或者组织、督促有关机关单位调查处理涉嫌泄露国家秘密的线索和案件的工作，包括(ABCD)阶段。\r\n\r\nA 立案    B调查   C 处理    D结案\r\n\r\n&nbsp;\r\n\r\n117．保密行政管理部门应当对(ABCD)的涉嫌泄露国家秘密的线索和案件，立即进行初步审查。\r\n\r\nA有关部门移送     B保密检查发现\r\n\r\nC机关和单位报告   D公民举报\r\n\r\n&nbsp;\r\n\r\n三、判断题（共20题，每题1分，共20分）\r\n\r\n1、机关、单位及其工作人员履行保密工作责任制情况应当纳入年度考评和考核内容。（ 对 ）\r\n\r\n2、企业事业单位及其工作人员协助机关、单位逃避、妨碍保密检查或者泄露保密检查或者泄露国家秘密案件查处的，由有关主管部门依法予以处罚。（ 对 ）\r\n\r\n3、对本机关产生的仍在保密期限内的国家秘密文件、资料，如果认为符合提前解密条件的，可以不需要办理解密手续，直接删去密级标志后就予以公开。（ 错 ）\r\n\r\n4、连接互联网的计算机必须与处理涉密信息的计算机严格区分，做到专机专用，不得既用于上互联网又用于处理国家秘密信息。（  对  ）\r\n\r\n5、涉密人员可以私自到境外机构、组织或者外商独资企业工作，为其提供服务。（  错  ）\r\n\r\n6、涉密人员被解聘或者本人提出辞职的，应先调离涉密岗位，在本单位履行脱密期后再行办理解聘、辞职或调离手续。（  对  ）\r\n\r\n&nbsp;\r\n\r\n7、国家秘密载体以及属于国家秘密的设备、产品的明显部位应当标注国家秘密标志。（  对  ）\r\n\r\n&nbsp;\r\n\r\n8、复制国家秘密载体或者摘录、引用、汇编属于国家秘密的内容，应当按照规定报批，不得擅自改变原件的密级、保密期限和知悉范围，复制件应当加盖复制机关、单位戳记，并视同原件进行管理。（  对  ）\r\n\r\n&nbsp;\r\n\r\n9、机关单位制作本单位保密承诺书，可以结合实际补充相关内容，也可以适当删减规定的基本内容。（ 错  ）\r\n\r\n&nbsp;\r\n\r\n10、中央国家机关、省级机关及其授松的机关、单位可能确定绝密级、机密级和秘密级国家秘密；设区的市、自治州一级的机关及其授权的机关、单位可以确定绝密级和秘密级国家秘密。（ 错 ）\r\n\r\n&nbsp;\r\n\r\n11、保守国家秘密、维护国家安全和利益是每个公民应尽的宪法义务。（  对  ）\r\n\r\n12、机关、单位确因工作需要，自行销毁少量国家秘密载体的，应当使用符合国家保密标准的销毁设备和方法。（  对  ）\r\n\r\n13、按照“谁定密、谁审批、谁负责”的原则，机关、单位负责人对本机关、本单位的定密工作负责。（对）\r\n\r\n&nbsp;\r\n\r\n14、机关、单位执行中央下发的机密级文件，在执行过程中产生的文件资料，应当确定为秘密级国家秘密。（错）\r\n\r\n&nbsp;\r\n\r\n15、没有定密权的机关、单位，可以向有相应定密权限的上一级机关或有关行来主管部门提出定密授权的申请。（  对  ）\r\n\r\n16、机关、单位对是否属于国家秘密或者属于何种密级不明确或者有争议的，由国家保密行政管理部门或者省、自治区、直辖市保密行政管理部门确定。（  对  ）\r\n\r\n&nbsp;\r\n\r\n17、机关、单位工作人员可以在涉密计算机和非涉密计算机之间交叉使用优盘等移动存储介质。（ 错  ）\r\n\r\n&nbsp;\r\n\r\n18、军事方面的国家秘密及其密级的具体范围，由国家保密局规定。（  错  ）\r\n\r\n&nbsp;\r\n\r\n19、涉密人员的合法权益受法律保护。（  对  ）\r\n\r\n20、签订保密承诺书之前，应当组织对承诺人进行保密教育和培训。承诺人要了解有关保密要求，熟悉保密承诺内容，掌握相关保密知识和技能。（  对  ）\r\n\r\n21、机关、单位发现边秘密已经泄露或者可能泄露的，应当立即采取补救措施，并在12小时内向同级保密行政管理部门和上级保密行政管理部门报告。（ 错   ）\r\n\r\n&nbsp;\r\n\r\n22、在保密审查过程中，机关、单位认为被审查信息涉及商业秘密、个人隐私，公开后可能损害第三方合法权益的，应当口头征求第三方的意见。（  错  ）\r\n\r\n&nbsp;\r\n\r\n23、上网信息的保密管理坚持“谁上网谁负责”的原则。（  对  ）\r\n\r\n24、保密管理的目的是通知采取积极防范、突出重点、依法管理的方针，达到既确保国家保密安全、又便利信息资源合理利用。（  对  ）\r\n\r\n25、制定保密事项范围，既要从国家安全和利益出发，把确属国家秘密的事项纳入保密范围；又要避免“宽一些保险”、“高一些有利”的片面认识，严格控制保密范围，实事求是地确定密级。（  对  ）\r\n\r\n&nbsp;\r\n\r\n26、保密违法行为与侵犯国家秘密犯罪行为之间的区别查处对象不同、法律后果不同、查处主体不同。（  错  ）\r\n\r\n&nbsp;\r\n\r\n27、要充分发挥党校、行政学院、干部学院在领导干部保密教育中的主阵地、主渠道作用，利用党委（党组）理论中心组学习、保密法制讲座和培训、保密知识考试考核等形式开展保密教育。（  对  ）\r\n\r\n&nbsp;\r\n\r\n28、接受保密宣传教育，掌握基本的保密工作常识和技能，是对一名合格公务员的重要标准。（  错  ）\r\n\r\n&nbsp;\r\n\r\n29、工作人员可以通过普通邮政、快递等渠道传递国家秘密载体。（  错  ）\r\n\r\n30、不得将退出使用的涉密计算机、涉密存储设备赠送、出售、丢弃或者改作其他用途。（   对  ）\r\n\r\n&nbsp;\r\n\r\n31、保密承诺书不需要一年一签。（  对  ）\r\n\r\n32、对严重违反保密承诺，泄露国家秘密的，应当依法依纪给予处分；构成犯罪的，依法追究刑事责任。（ 对   ）\r\n\r\n33、离岗人员不需要签保密承诺书。（  错  ）\r\n\r\n34、不得在未采取防护措施的情况下将互联网及其他公共信息网络上的数据复制到涉密计算机及网络。（  对  ）\r\n\r\n35、手机只要在不通话的情况下，可以带入重要涉密场所。（ 错   ）\r\n\r\n36、公安、国家安全机关在其工作范围内按照规定的权限确定国家秘密的密级。（ 对   ）\r\n\r\n37、禁止在互联网及其他公共信息网络或者未采取保密措施的有线和无线通令中传递国家秘密。（  对  ）\r\n\r\n38、应在一般区域建立失泄密案件应急处置机制，及时处置预案。（  错  ）\r\n\r\n39、根据《国家秘密载体销毁管理规定》，国家秘密载体除正在使用或者按照有关规定留存、存档外，应当及时予以销毁。（  对  ）\r\n\r\n40、依照有关规定，标有“内部资料”的信息，不得公开或暂缓公开。（  对  ）\r\n\r\n41、在中华人民共和国境内依法成立2年以上的法人，无违法犯罪记录的企业事业单位可以从事涉密业务。（ 错  ）\r\n\r\n42、国家对在保守、保护国家秘密以及改进保密技术、措施等方面成绩显著的单位或者个人给予奖励。（ 对   ）\r\n\r\n43、国家秘密的密级分为绝密、机密、秘密三级。（ 对   ）\r\n\r\n44、不属于国家秘密的，不应当做出国家秘密标志。（ 对   ）\r\n\r\n&nbsp;', '保密法律法规知识竞赛试题', '', 'inherit', 'closed', 'closed', '', '156-revision-v1', '', '', '2017-05-03 10:23:04', '2017-05-03 02:23:04', '', 156, 'http://bm.yangyongquan.com/2017/05/03/156-revision-v1/', 0, 'revision', '', 0);
INSERT INTO `wp_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES
(159, 1, '2017-05-03 10:35:57', '2017-05-03 02:35:57', '<table>\r\n<tbody>\r\n<tr>\r\n<td colspan="2" width="90">题目</td>\r\n<td colspan="2" width="212">机关单位在确定保密要害部门和部位时，要坚持“（ ）”和“（ ）”原则。</td>\r\n<td colspan="16" width="304">标记    （本试题作答时存在不确定性可做标记待后续检查）</td>\r\n</tr>\r\n<tr>\r\n<td colspan="2" width="90">选项</td>\r\n<td colspan="18" width="516">A 分级确定、最大化 B 最高级别确定、最大化 C 分级确定、最小化 D 最低级别确定、最小化</td>\r\n</tr>\r\n<tr>\r\n<td colspan="5" width="452">单选题</td>\r\n</tr>\r\n<tr>\r\n<td width="83">题目</td>\r\n<td colspan="2" width="195">各级机关单位对所产生的国家秘密事项，应当依照保密范围的规定及时确定密级，最迟不得超过（ ）</td>\r\n<td colspan="2" width="172">标记    （本试题作答时存在不确定性可做标记待后续检查）</td>\r\n</tr>\r\n<tr>\r\n<td width="83">选项</td>\r\n<td colspan="4" width="368">A 20日 B 3日 C 5日 D 10日</td>\r\n</tr>\r\n<tr>\r\n<td colspan="6" width="462">单选题</td>\r\n</tr>\r\n<tr>\r\n<td width="83">题目</td>\r\n<td colspan="2" width="195">发生泄密事件的机关、单位，应在发现后（ ）内，书面向有关保密工作部门或机构报告，情况紧急时，可先口头报告简要情况。</td>\r\n<td colspan="3" width="183">标记    （本试题作答时存在不确定性可做标记待后续检查）</td>\r\n</tr>\r\n<tr>\r\n<td width="83">选项</td>\r\n<td colspan="5" width="378">A 48小时 B 24小时 C 72小时 D 12小时</td>\r\n</tr>\r\n<tr>\r\n<td colspan="19" width="597">判断题</td>\r\n</tr>\r\n<tr>\r\n<td width="83">题目</td>\r\n<td colspan="2" width="195">互联网和其他公共网络信息运营商、服务商具有配合有关机关调查泄密案件的法律责任。</td>\r\n<td colspan="16" width="317">标记    （本试题作答时存在不确定性可做标记待后续检查）</td>\r\n</tr>\r\n<tr>\r\n<td width="83">答案</td>\r\n<td colspan="18" width="513">正确 错误</td>\r\n</tr>\r\n<tr>\r\n<td colspan="7" width="473">判断题</td>\r\n</tr>\r\n<tr>\r\n<td width="83">题目</td>\r\n<td colspan="2" width="195">新修订《保密法》规定：军事方面的国家秘密及其密级的具体范围，由国家保密行政管理部门分别会同外交、公安、国家安全和其他中央有关机关规定。</td>\r\n<td colspan="4" width="193">标记    （本试题作答时存在不确定性可做标记待后续检查）</td>\r\n</tr>\r\n<tr>\r\n<td width="83">答案</td>\r\n<td colspan="6" width="389">正确 错误</td>\r\n</tr>\r\n<tr>\r\n<td colspan="8" width="483">判断题</td>\r\n</tr>\r\n<tr>\r\n<td width="83">题目</td>\r\n<td colspan="2" width="195">新修订的《保密法》规定，发生重大泄的密案件，不仅要对直接责任人追究责任，也要对负有领导责任的直接责任人员给予处分。</td>\r\n<td colspan="5" width="203">标记    （本试题作答时存在不确定性可做标记待后续检查）</td>\r\n</tr>\r\n<tr>\r\n<td width="83">答案</td>\r\n<td colspan="7" width="399">正确 错误</td>\r\n</tr>\r\n<tr>\r\n<td colspan="9" width="493">单选题</td>\r\n</tr>\r\n<tr>\r\n<td width="83">题目</td>\r\n<td colspan="2" width="195">军事禁区和属于国家秘密不对外开放的其他场所、部位，应当采取保密措施，除依照国家有关规定经过批准外，（ ）对外开放或者扩大开放范围。</td>\r\n<td colspan="6" width="214">标记    （本试题作答时存在不确定性可做标记待后续检查）</td>\r\n</tr>\r\n<tr>\r\n<td width="83">选项</td>\r\n<td colspan="8" width="409">A 可以自行决定 B 只能限定时段 C 不得擅自决定 D 也可视情适当</td>\r\n</tr>\r\n<tr>\r\n<td colspan="18" width="586">单选题</td>\r\n</tr>\r\n<tr>\r\n<td width="83">题目</td>\r\n<td colspan="2" width="195">根据《中华人民共和国保守国家秘密法》的有关规定，关于政党的秘密事项表述正确的是（ ）。</td>\r\n<td colspan="15" width="307">标记    （本试题作答时存在不确定性可做标记待后续检查）</td>\r\n</tr>\r\n<tr>\r\n<td width="83">选项</td>\r\n<td colspan="17" width="502">A 政党的秘密事项经保密工作部门确认后，属于国家秘密事项 B 政党的秘密事项中部分属于国家秘密事项 C 政党的秘密事项属于国家机密 D 政党的秘密事项与国家秘密性质不同，不属于国家秘密事项</td>\r\n</tr>\r\n<tr>\r\n<td colspan="10" width="504">单选题</td>\r\n</tr>\r\n<tr>\r\n<td width="83">题目</td>\r\n<td colspan="2" width="195">《保密法》的立法依据是（ ）。</td>\r\n<td colspan="7" width="224">标记    （本试题作答时存在不确定性可做标记待后续检查）</td>\r\n</tr>\r\n<tr>\r\n<td width="83">选项</td>\r\n<td colspan="9" width="420">A 刑法 B 中国共产党党章 C 宪法 D 行政法</td>\r\n</tr>\r\n<tr>\r\n<td colspan="11" width="514">多选题</td>\r\n</tr>\r\n<tr>\r\n<td width="83">题目</td>\r\n<td colspan="2" width="195">下列对保密要害部位的表述正确的有</td>\r\n<td colspan="8" width="234">标记    （本试题作答时存在不确定性可做标记待后续检查）</td>\r\n</tr>\r\n<tr>\r\n<td width="83">选项</td>\r\n<td colspan="10" width="430">A 保密要害部位是指机关、单位日常工作中产生、传递、使用和管理绝密级的机构 B 保密要害部位是机关内部涉及重要国家秘密事项的最小行政单位 C 保密要害部位是存放、保管涉密载体的最小专用、独立、固定场所 D 保密要害部位是指机关、单位内部集中制作、存储、保管涉密载体的专门场所</td>\r\n</tr>\r\n<tr>\r\n<td colspan="17" width="576">单选题</td>\r\n</tr>\r\n<tr>\r\n<td width="83">题目</td>\r\n<td colspan="2" width="195">定密责任人制度的本质是</td>\r\n<td colspan="14" width="296">标记    （本试题作答时存在不确定性可做标记待后续检查）</td>\r\n</tr>\r\n<tr>\r\n<td width="83">选项</td>\r\n<td colspan="16" width="492">A 解决部分机关、单位长期以来的定密不规范行为的重要制度 B 由定密责任人具体负责本单位国家秘密的确定、变更和解除工作 C 由定密责任人具体承担本单位国家秘密的确定是否正确的责任 D 实现定密，全民提升保守国家秘密能力的基本制度保障</td>\r\n</tr>\r\n<tr>\r\n<td colspan="12" width="524">单选题</td>\r\n</tr>\r\n<tr>\r\n<td width="83">题目</td>\r\n<td colspan="2" width="195">（ ）是构成国家秘密的实质要素。</td>\r\n<td colspan="9" width="245">标记    （本试题作答时存在不确定性可做标记待后续检查）</td>\r\n</tr>\r\n<tr>\r\n<td width="83">选项</td>\r\n<td colspan="11" width="440">A 在特定时间内的事项 B 依照有关规定确定 C 关系国家安全和利益 D 特定范围的人员知悉</td>\r\n</tr>\r\n<tr>\r\n<td colspan="13" width="535">单选题</td>\r\n</tr>\r\n<tr>\r\n<td width="83">题目</td>\r\n<td colspan="2" width="195">国家秘密的确定要遵循（ ）和（ ）</td>\r\n<td colspan="10" width="255">标记    （本试题作答时存在不确定性可做标记待后续检查）</td>\r\n</tr>\r\n<tr>\r\n<td width="83">选项</td>\r\n<td colspan="12" width="451">A 定密范围、定密程序 B 定密权限、定密程序 C 定密范围、定密权限 D 定密期限、定密权限</td>\r\n</tr>\r\n<tr>\r\n<td colspan="16" width="566">多选题</td>\r\n</tr>\r\n<tr>\r\n<td width="83">题目</td>\r\n<td colspan="2" width="195">对国家秘密载体与密品的关系，理解正确的是</td>\r\n<td colspan="13" width="286">标记    （本试题作答时存在不确定性可做标记待后续检查）</td>\r\n</tr>\r\n<tr>\r\n<td width="83">选项</td>\r\n<td colspan="15" width="482">A 国家秘密载体包括密品 B 国家秘密载体本身是不含秘密的，而密品本身就是秘密 C 国家秘密载体与密品是两个完全不同的概念 D 密品包含国家秘密载体</td>\r\n</tr>\r\n<tr>\r\n<td colspan="14" width="545">多选题</td>\r\n</tr>\r\n<tr>\r\n<td width="83">题目</td>\r\n<td colspan="2" width="195">《保密法》规定，在公开发布信息前进行保密审查坚持的原则有</td>\r\n<td colspan="11" width="265">标记    （本试题作答时存在不确定性可做标记待后续检查）</td>\r\n</tr>\r\n<tr>\r\n<td width="83">选项</td>\r\n<td colspan="13" width="461">A 事前审查原则 B 谁公开谁审查原则 C 依法审查原则 D 事后审查原则</td>\r\n</tr>\r\n<tr>\r\n<td colspan="15" width="555">多选题</td>\r\n</tr>\r\n<tr>\r\n<td width="83">题目</td>\r\n<td colspan="2" width="195">涉密信息系统保密管理制度包括</td>\r\n<td colspan="12" width="276">标记    （本试题作答时存在不确定性可做标记待后续检查）</td>\r\n</tr>\r\n<tr>\r\n<td width="83">选项</td>\r\n<td colspan="14" width="471">A 涉密信息系统自行卸载和修改安全技术程序的管理制度 B 涉密信息系统固定进行的网络连接制度 C 涉密信息系统实行分级保护制度 D 涉密信息系统建设实行同步规划，同步建设和同步使用的技术防护制度</td>\r\n</tr>\r\n</tbody>\r\n</table>', '保密考试答案2', '', 'inherit', 'closed', 'closed', '', '158-revision-v1', '', '', '2017-05-03 10:35:57', '2017-05-03 02:35:57', '', 158, 'http://bm.yangyongquan.com/2017/05/03/158-revision-v1/', 0, 'revision', '', 0),
(160, 1, '2017-04-28 16:36:29', '2017-04-28 08:36:29', '<strong><b>教师普法考试试题及答案</b></strong>\r\n\r\n&nbsp;\r\n\r\n<strong><b>一、填空题共 10 题每小题 2 分共 20 分 </b></strong>\r\n\r\n1.教育法是调整各级各类教育关系的法律规范的总称。\r\n\r\n2.教育法规定国家保护教师的合法权利改善教师的工作条件和生活条件提高教师的社会地位。\r\n\r\n3.教师主要通过教职工代表大会或者其他形式参与学校的民主管理。\r\n\r\n4.依法治校是依法治教的要求也是落实学校办学自主权、提高管理效率、保护有关法律关系主体合法权益的需求。\r\n\r\n5 .教师的平均工资水平应当不低于或者高于国家公务员的平均工资水平并逐步提高。\r\n\r\n6 .中国公民在各级各类学校和其他教育机构中专门从事教育教学工作应当依法取得教师资格。\r\n\r\n7 .《教师法》规定教师是履行教育教学职责的专业人员。\r\n<ol start="8">\r\n 	<li>学校依法对学生的人身安全承担教育、管理、保护责任。</li>\r\n</ol>\r\n9 .《教师法》明确规定实行教师资格制度、教师职务制度和教师聘任制度从而奠定了教师任用与管理的新机制构成了教师管理法律制度的核心。\r\n<ol start="10">\r\n 	<li>在我国教师节是每年的9月10日。</li>\r\n</ol>\r\n&nbsp;\r\n\r\n<strong><b> 二、单项选择题共 10 题每题只有一个正确选项每题 2 分共20 分 </b></strong>\r\n\r\n&nbsp;\r\n<ol>\r\n 	<li>根据法律的规定，我国义务教育学校的内部管理体制为______（ D ）。</li>\r\n</ol>\r\nA、教师负责制 B、校务委员会负责制 C、家长委员会负责制 D、校长负责制\r\n<ol start="2">\r\n 	<li>教师资格证书的适用的地域范围是：______（ A ）。</li>\r\n</ol>\r\n&nbsp;\r\n<ol>\r\n 	<li>在全国范围适用 B. 只在本地区适用C. 只在本校适用 D. 在外国也适用</li>\r\n</ol>\r\n&nbsp;\r\n<ol start="3">\r\n 	<li>中华人民共和国公民有受教育的______。（ C ）</li>\r\n</ol>\r\nA 权利     B 义务       C 权利和义务         D 权力\r\n\r\n&nbsp;\r\n<ol start="4">\r\n 	<li>学校不履行法律法规规定的义务，情节严重或者造成严重后果，根据有关法律规定，______要承担相应的法律责任。（ D ）</li>\r\n</ol>\r\n&nbsp;\r\n\r\nA 校长 B 学校负责人 C 有关直接负责人 D 学校负责人和有关直接负责人\r\n\r\n&nbsp;\r\n\r\n5.教师认为行政机关的具体行政行为侵犯其合法权益，应当自知道具体行政行为之日起______日内提起行政复议申请，法律、法规规定超过此时限的除外。（ D ）\r\n\r\n&nbsp;\r\n\r\nA.15         B.20           C.30            D.60\r\n\r\n&nbsp;\r\n<ol start="6">\r\n 	<li>____是国家统一实施的所有适龄儿童、少年必须接受的教育，是国家必须予以保障的公益性事业。（ A ）</li>\r\n</ol>\r\n&nbsp;\r\n\r\nA.义务教育         B.中等教育          C.职业教育         D.高等教育\r\n\r\n&nbsp;\r\n<ol start="7">\r\n 	<li>在学生伤害事故处理中，学校责任适用的归责原则是：____（ A ）</li>\r\n</ol>\r\n&nbsp;\r\n\r\nA、过错责任原则 B、无过错责任原则C、严格责任原则 D、公平原则\r\n\r\n&nbsp;\r\n\r\n8.学校____聘用曾经因故意犯罪被依法剥夺政治权利的人担任工作人员。（ B ）\r\n\r\n&nbsp;\r\n\r\nA.可以         B.不得           C.特殊情况可以            D.经批准可以\r\n\r\n&nbsp;\r\n\r\n9.教师对学校或者其他教育机构侵犯其合法权益的，或者对学校或者其他教育机构作出的处理不服的，可以向教育行政部门提出申诉，教育行政部门应当在接到申诉的次日起____内作出处理。（ C ）\r\n\r\n&nbsp;\r\n\r\nA.15 日            B.20 日              C.30 日           D.60 日\r\n\r\n&nbsp;\r\n<ol start="10">\r\n 	<li>侵占学校及其他教育机构校舍、场地及其他财产的，依法承担____（ C ）</li>\r\n</ol>\r\nA.行政责任      B.刑事责任          C.民事责任          D.AB 两种责任\r\n\r\n&nbsp;\r\n\r\n<strong><b>三、多项选择题共 10 题每题有两个以上正确选项每题 2 分共20 分 </b></strong>\r\n\r\n&nbsp;\r\n\r\n1.教师法律救济的途径是指教师认为其权益受到损害时，请求解决或补偿的渠道或方式。一般可分为：（ABC ）\r\n\r\n&nbsp;\r\n\r\nA.司法救济           B.行政救济        C.社会救济          D.自力救济\r\n\r\n&nbsp;\r\n<ol start="2">\r\n 	<li>以下哪些处罚种类属于教育行政处罚：（ ABCD ）。</li>\r\n</ol>\r\n&nbsp;\r\n\r\nA.警告、罚款     B.责令停止招生     C.撤销教师资格  D.吊销办学许可证\r\n\r\n&nbsp;\r\n<ol start="3">\r\n 	<li>李某是一名教师，可以行使的权利有：（ ABC ）</li>\r\n</ol>\r\n&nbsp;\r\n\r\nA、通过教职工代表大会或者其他形式，参与学校的民主管理B、参加进修或者其他方式的培训。C、在寒暑假期带薪休假D、责令上课不遵守纪律的学生离开教室\r\n\r\n&nbsp;\r\n\r\n4.学生伤害事故的处理途径有：（ ABC ）\r\n\r\n&nbsp;\r\n\r\nA.自行协商解决；   B.申请调解；   C.伤害事故的赔偿；  D.不予理睬\r\n\r\n&nbsp;\r\n\r\n5.根据现有教育法律、法规规定，可以依法提起学生行政申诉的对象和内容包括：（ ABCD ）\r\n\r\n&nbsp;\r\n\r\nA.对学校给予的处分不服的 B.对学校侵犯其合法财产权的C.对学校侵犯其人身权的 D.对学校侵犯其知识产权的\r\n\r\n&nbsp;\r\n<ol start="6">\r\n 	<li>我国教育法规定的在校学生的权利有：（ ABCD ）</li>\r\n</ol>\r\n&nbsp;\r\n\r\nA、参加教育教学活动权 B、获得资助权 C、获得公正评价权 D、申诉、诉讼权\r\n\r\n&nbsp;\r\n\r\n7.学校作为法人的主要特点：（ ABC ）\r\n\r\n&nbsp;\r\n\r\nA.公益性     B.民事活动范围的有限性      C.财产的受限性     D.盈利性\r\n\r\n&nbsp;\r\n<ol start="8">\r\n 	<li>为保障教师完成教学任务，保证教师权利的实现，各级政府、有关部门、学校应当履行的职责有： ABCD</li>\r\n</ol>\r\n&nbsp;\r\n\r\nA、提供符合国家安全标准的教育教学设施和设备B、提供必须的图书、资料及其他教育教学用品C、对教师在教育教学、科学研究中的创造性工作给以鼓励和帮助D、支持教师制止侵犯学生合法权益的行为\r\n\r\n&nbsp;\r\n\r\n9.教师有下列情形之一的，由所在学校、其他教育机构或者教育行政部门给予行政处分或者解聘。（ BCD ）\r\n\r\n&nbsp;\r\n\r\nA.因不可抗力给教育教学工作造成损失的B.故意不完成教育教学任务给教育教学工作造成损失的C.体罚学生，经教育不改的D.品行不良，侮辱学生，影响恶劣的\r\n\r\n&nbsp;\r\n<ol start="10">\r\n 	<li>国家建立统一的义务教育教师职务制度。教师职务分为：（ ABC ）</li>\r\n</ol>\r\n&nbsp;\r\n\r\nA．初级职务          B.中级职务        C.高级职务         D.特级职务\r\n\r\n&nbsp;\r\n\r\n<strong><b>四、简答题共 4 题每题 5 分共 20 分 </b></strong>\r\n\r\n&nbsp;\r\n\r\n<strong><b>1、学校应履行哪些义务？ </b></strong>\r\n\r\n&nbsp;\r\n\r\n答：《教育法》第二十九条规定学校要履行以下基本义务：\r\n\r\n一遵守法律、法规。\r\n\r\n二贯彻国家的教育方针执行国家教育教学标准保证教育教学质量。\r\n\r\n三维护受教育者、教师及其他职工的合法权益。\r\n\r\n四以适当方式为受教育者及其监护人了解受教育者的学业成绩及其他有关情况提供便利。\r\n\r\n五遵照国家有关规定收取费用并公开收费项目。\r\n\r\n六依法接受监督。\r\n\r\n&nbsp;\r\n\r\n<strong><b>2、教师应当依法履行哪些义务？ </b></strong>\r\n\r\n&nbsp;\r\n\r\n答：《教师法》第八条规定教师应当履行下列义务：\r\n\r\n一 遵守宪法、法律和职业道德为人师表\r\n\r\n二 贯彻国家的教育方针遵守规章制度执行学校的教学计划履行教师聘约完成教育教学工作任务\r\n\r\n三 对学生进行宪法所确定的基本原则的教育和爱国主义、民族团结的教育法制教育以及思想品德、文化、科学技术教育组织、带领学生开展有益的社会活动\r\n\r\n四 关心、爱护全体学生尊重学生人格促进学生在品德、智力、体质等方面全面发展\r\n\r\n五 制止有害于学生的行为或者其他侵犯学生合法权益的行为批评和抵制有害于学生健康成长的现象\r\n\r\n六 不断提高思想政治觉悟和教育教学业务水平。\r\n\r\n&nbsp;\r\n\r\n<strong><b>3、教育法律原则的具体内容是哪些 ？</b></strong>\r\n\r\n&nbsp;\r\n\r\n答：一促进人的全面发展的原则\r\n\r\n二尊重和保障受教育权的原则\r\n\r\n三教育优先发展原则 四维护受教育者健康成长的原则\r\n\r\n&nbsp;\r\n\r\n<strong><b>4、学校安全工作的职责有哪些？</b></strong>\r\n\r\n&nbsp;\r\n\r\n答：学校安全工作的职责主要包括 ：\r\n\r\n1、保证设施安全；\r\n\r\n2、完善安全制度；\r\n\r\n3、 落实安全教育；\r\n\r\n4、安全管理到位；\r\n\r\n5、及时救治伤病；\r\n\r\n6、常备应急预案；\r\n\r\n7、关注校园周边环境安全。\r\n\r\n&nbsp;\r\n\r\n<strong><b>五、论述题20 分 </b></strong>\r\n\r\n&nbsp;\r\n\r\n<strong><b>结合实际谈谈如何实施依法治校、构建和谐校园。 </b></strong>\r\n\r\n1、建章立制依法治校促进学校的民主化管理\r\n\r\n依法治校民主管理是一个学校发展的基石。依据法律、法规以及学校的实际情况学校应制定了一系列规章制度并汇编成册保证了学校各部门各岗位高效运作学校管理步入了规范化、制度化的轨道。学校系列的管理职责和制度让教师们严守规范尽职尽责学生管理方面的制度又制约着学生规范行为勤奋学习努力向上学生、家长评价等方面的制度督促老师认真教学形成文明教风。各项制度又形成合力推动着学校文明三风的形成。如下列学校制度推进学校办学管理的民主进程。\r\n\r\n一教代会制度。高度重视教代会充分发扬民主倾听群众的呼声广泛采纳各种合理化建议保证了学校工作健康发展。\r\n\r\n二民主生活会制度。每学期学校行政班子都要举行23次民主生活会通过召开行政班子成员民主生活会开展批评和自我批评班子内部进一步加强了沟通形成了民主作风。\r\n\r\n三师生申诉制度。学校重视保护师生的合法权益畅通了申诉渠道师生均可以通过一定程序为维护自己的权益逐级向上质询、申诉。\r\n\r\n四多渠道评教制度。学校坚持学生评议教师师生评议领导群众评议党员家长、社会单位评议学校的四评议制度形成了学校的管理特色。\r\n\r\n五校务公开制度。坚持校务公开制度是学校管理民主化的重要体现是依法治校、和谐发展的重要举措。我校坚持通过告家长书、公示栏、意见箱、网络平台等向家长、社会、师生公开校务。学校规划与发展目标的确立年度计划的拟定学校规章制度的落实各项方案的实施校内各项工程承包财务收支、津贴发放、资金分配、职称晋升、评模选优等事关学校发展与教职工利益的大事情都要经过学校各级民主会议讨论评议由教代会通过并将结果张榜公示。对群众师生关心的问题由专人负责解释收费问题严格按照收费标准收费和据实结算并按要求公示\r\n\r\n六家长委员会制度。家长委员会在评教和为学校发展献计献策的活动中发挥着重大作用。家长委员会定期召开会议还经常应邀参加学校重大决策和重要会议发挥民主建议作用。\r\n\r\n七规范办学社会承诺制度。为规范办学行为对事关群众利益的招生、教育收费标准和结算情况、农转非家庭和城市困难职工家庭学生杂费减免等焦点、热点问题学校通过校园公示栏、召开家长会、公开向社会承诺并自觉接受社会监督。\r\n\r\n2、以人为本依法办学促进校园和谐发展\r\n\r\n学校应提出建设和谐校园打造名校品牌的校园建设目标把健康、文明、和谐、发展确定为校园主题。在办学过程中做到全面贯彻党的教育方针自觉遵守国家法律法规依法实施办学活动全面实施素质教育。学校认真推行新课程改革方案执行学制规定、课程计划、按课程标准实施教学活动学校教师依法执教没有无故使学生中途停学、退学或开除学生的现象没有擅自放假现象学生遵章守纪没有违法违纪的事件发生。依法维护学生受教育权尊重学生人格和权利。保障学生参加教育教学计划安排的各项活动无体罚或变相体罚及侮辱、歧视学生的现象按照国家规定的收费规定标准和收费项目向学生收取费用无乱收费现象。建立学生安全和伤害事故的应急处理预案和报告制度依法妥善处理学生伤害事故。实现安全教育制度化、规范化预防和减少了学生的伤害事故。建立“校长信箱”“校长接待制度”接受学生申诉家长投诉维护学生合法权益。\r\n\r\n一充分保障教师权益。在教师队伍建设中。学校注重教师工作环境的改善注重教师教育人生、生活品味的提升。不断改善教师福利坚持帮扶弱势群体在家属与子女就业、入学等问题上提供便利实行了优秀教师、骨干教师学习进修培训制度关心慰问教师红白喜事为教师排忧解难。使教师生存有保障、生活有质量、发展有平台、事业有追求。\r\n\r\n二充分尊重和保护学生权益。在学生管理中学校倡导“法”就是常规“法”就是生活的观点要求领导、教师将《教育法》、《教师法》、《未成年人保护法》的贯彻具体到日常教学管理中提出了“全员抓德育全民重德育”的管理思想。每个领导要融入教师、融入学生、融入校园生活每个教师要融入学生、融入课堂、融入学生生活从学习、生活、与人交往等诸多方面为学生做出表率。教师必须全面掌握本班学生的情况特别要关注和关心家庭有困难的学生。要求教师必须充分尊重每一个学生的人格及其他人身权利和财产权利保障学生参加教育教学计划安排的各项活动将教师的师德师风考核与晋级晋职考核相结合实行“一票否决”制度。\r\n\r\n&nbsp;', '教师普法考试试题及答案', '', 'publish', 'open', 'open', '', '%e6%95%99%e5%b8%88%e6%99%ae%e6%b3%95%e8%80%83%e8%af%95%e8%af%95%e9%a2%98%e5%8f%8a%e7%ad%94%e6%a1%88', '', '', '2017-05-03 10:37:43', '2017-05-03 02:37:43', '', 0, 'http://bm.yangyongquan.com/?p=160', 0, 'post', '', 0),
(161, 1, '2017-05-03 10:37:27', '2017-05-03 02:37:27', '<strong><b>教师普法考试试题及答案</b></strong>\r\n\r\n&nbsp;\r\n\r\n<strong><b>一、填空题共 10 题每小题 2 分共 20 分 </b></strong>\r\n\r\n1.教育法是调整各级各类教育关系的法律规范的总称。\r\n\r\n2.教育法规定国家保护教师的合法权利改善教师的工作条件和生活条件提高教师的社会地位。\r\n\r\n3.教师主要通过教职工代表大会或者其他形式参与学校的民主管理。\r\n\r\n4.依法治校是依法治教的要求也是落实学校办学自主权、提高管理效率、保护有关法律关系主体合法权益的需求。\r\n\r\n5 .教师的平均工资水平应当不低于或者高于国家公务员的平均工资水平并逐步提高。\r\n\r\n6 .中国公民在各级各类学校和其他教育机构中专门从事教育教学工作应当依法取得教师资格。\r\n\r\n7 .《教师法》规定教师是履行教育教学职责的专业人员。\r\n<ol start="8">\r\n 	<li>学校依法对学生的人身安全承担教育、管理、保护责任。</li>\r\n</ol>\r\n9 .《教师法》明确规定实行教师资格制度、教师职务制度和教师聘任制度从而奠定了教师任用与管理的新机制构成了教师管理法律制度的核心。\r\n<ol start="10">\r\n 	<li>在我国教师节是每年的9月10日。</li>\r\n</ol>\r\n&nbsp;\r\n\r\n<strong><b> 二、单项选择题共 10 题每题只有一个正确选项每题 2 分共20 分 </b></strong>\r\n\r\n&nbsp;\r\n<ol>\r\n 	<li>根据法律的规定，我国义务教育学校的内部管理体制为______（ D ）。</li>\r\n</ol>\r\nA、教师负责制 B、校务委员会负责制 C、家长委员会负责制 D、校长负责制\r\n<ol start="2">\r\n 	<li>教师资格证书的适用的地域范围是：______（ A ）。</li>\r\n</ol>\r\n&nbsp;\r\n<ol>\r\n 	<li>在全国范围适用 B. 只在本地区适用C. 只在本校适用 D. 在外国也适用</li>\r\n</ol>\r\n&nbsp;\r\n<ol start="3">\r\n 	<li>中华人民共和国公民有受教育的______。（ C ）</li>\r\n</ol>\r\nA 权利     B 义务       C 权利和义务         D 权力\r\n\r\n&nbsp;\r\n<ol start="4">\r\n 	<li>学校不履行法律法规规定的义务，情节严重或者造成严重后果，根据有关法律规定，______要承担相应的法律责任。（ D ）</li>\r\n</ol>\r\n&nbsp;\r\n\r\nA 校长 B 学校负责人 C 有关直接负责人 D 学校负责人和有关直接负责人\r\n\r\n&nbsp;\r\n\r\n5.教师认为行政机关的具体行政行为侵犯其合法权益，应当自知道具体行政行为之日起______日内提起行政复议申请，法律、法规规定超过此时限的除外。（ D ）\r\n\r\n&nbsp;\r\n\r\nA.15         B.20           C.30            D.60\r\n\r\n&nbsp;\r\n<ol start="6">\r\n 	<li>____是国家统一实施的所有适龄儿童、少年必须接受的教育，是国家必须予以保障的公益性事业。（ A ）</li>\r\n</ol>\r\n&nbsp;\r\n\r\nA.义务教育         B.中等教育          C.职业教育         D.高等教育\r\n\r\n&nbsp;\r\n<ol start="7">\r\n 	<li>在学生伤害事故处理中，学校责任适用的归责原则是：____（ A ）</li>\r\n</ol>\r\n&nbsp;\r\n\r\nA、过错责任原则 B、无过错责任原则C、严格责任原则 D、公平原则\r\n\r\n&nbsp;\r\n\r\n8.学校____聘用曾经因故意犯罪被依法剥夺政治权利的人担任工作人员。（ B ）\r\n\r\n&nbsp;\r\n\r\nA.可以         B.不得           C.特殊情况可以            D.经批准可以\r\n\r\n&nbsp;\r\n\r\n9.教师对学校或者其他教育机构侵犯其合法权益的，或者对学校或者其他教育机构作出的处理不服的，可以向教育行政部门提出申诉，教育行政部门应当在接到申诉的次日起____内作出处理。（ C ）\r\n\r\n&nbsp;\r\n\r\nA.15 日            B.20 日              C.30 日           D.60 日\r\n\r\n&nbsp;\r\n<ol start="10">\r\n 	<li>侵占学校及其他教育机构校舍、场地及其他财产的，依法承担____（ C ）</li>\r\n</ol>\r\nA.行政责任      B.刑事责任          C.民事责任          D.AB 两种责任\r\n\r\n&nbsp;\r\n\r\n<strong><b>三、多项选择题共 10 题每题有两个以上正确选项每题 2 分共20 分 </b></strong>\r\n\r\n&nbsp;\r\n\r\n1.教师法律救济的途径是指教师认为其权益受到损害时，请求解决或补偿的渠道或方式。一般可分为：（ABC ）\r\n\r\n&nbsp;\r\n\r\nA.司法救济           B.行政救济        C.社会救济          D.自力救济\r\n\r\n&nbsp;\r\n<ol start="2">\r\n 	<li>以下哪些处罚种类属于教育行政处罚：（ ABCD ）。</li>\r\n</ol>\r\n&nbsp;\r\n\r\nA.警告、罚款     B.责令停止招生     C.撤销教师资格  D.吊销办学许可证\r\n\r\n&nbsp;\r\n<ol start="3">\r\n 	<li>李某是一名教师，可以行使的权利有：（ ABC ）</li>\r\n</ol>\r\n&nbsp;\r\n\r\nA、通过教职工代表大会或者其他形式，参与学校的民主管理B、参加进修或者其他方式的培训。C、在寒暑假期带薪休假D、责令上课不遵守纪律的学生离开教室\r\n\r\n&nbsp;\r\n\r\n4.学生伤害事故的处理途径有：（ ABC ）\r\n\r\n&nbsp;\r\n\r\nA.自行协商解决；   B.申请调解；   C.伤害事故的赔偿；  D.不予理睬\r\n\r\n&nbsp;\r\n\r\n5.根据现有教育法律、法规规定，可以依法提起学生行政申诉的对象和内容包括：（ ABCD ）\r\n\r\n&nbsp;\r\n\r\nA.对学校给予的处分不服的 B.对学校侵犯其合法财产权的C.对学校侵犯其人身权的 D.对学校侵犯其知识产权的\r\n\r\n&nbsp;\r\n<ol start="6">\r\n 	<li>我国教育法规定的在校学生的权利有：（ ABCD ）</li>\r\n</ol>\r\n&nbsp;\r\n\r\nA、参加教育教学活动权 B、获得资助权 C、获得公正评价权 D、申诉、诉讼权\r\n\r\n&nbsp;\r\n\r\n7.学校作为法人的主要特点：（ ABC ）\r\n\r\n&nbsp;\r\n\r\nA.公益性     B.民事活动范围的有限性      C.财产的受限性     D.盈利性\r\n\r\n&nbsp;\r\n<ol start="8">\r\n 	<li>为保障教师完成教学任务，保证教师权利的实现，各级政府、有关部门、学校应当履行的职责有： ABCD</li>\r\n</ol>\r\n&nbsp;\r\n\r\nA、提供符合国家安全标准的教育教学设施和设备B、提供必须的图书、资料及其他教育教学用品C、对教师在教育教学、科学研究中的创造性工作给以鼓励和帮助D、支持教师制止侵犯学生合法权益的行为\r\n\r\n&nbsp;\r\n\r\n9.教师有下列情形之一的，由所在学校、其他教育机构或者教育行政部门给予行政处分或者解聘。（ BCD ）\r\n\r\n&nbsp;\r\n\r\nA.因不可抗力给教育教学工作造成损失的B.故意不完成教育教学任务给教育教学工作造成损失的C.体罚学生，经教育不改的D.品行不良，侮辱学生，影响恶劣的\r\n\r\n&nbsp;\r\n<ol start="10">\r\n 	<li>国家建立统一的义务教育教师职务制度。教师职务分为：（ ABC ）</li>\r\n</ol>\r\n&nbsp;\r\n\r\nA．初级职务          B.中级职务        C.高级职务         D.特级职务\r\n\r\n&nbsp;\r\n\r\n<strong><b>四、简答题共 4 题每题 5 分共 20 分 </b></strong>\r\n\r\n&nbsp;\r\n\r\n<strong><b>1、学校应履行哪些义务？ </b></strong>\r\n\r\n&nbsp;\r\n\r\n答：《教育法》第二十九条规定学校要履行以下基本义务：\r\n\r\n一遵守法律、法规。\r\n\r\n二贯彻国家的教育方针执行国家教育教学标准保证教育教学质量。\r\n\r\n三维护受教育者、教师及其他职工的合法权益。\r\n\r\n四以适当方式为受教育者及其监护人了解受教育者的学业成绩及其他有关情况提供便利。\r\n\r\n五遵照国家有关规定收取费用并公开收费项目。\r\n\r\n六依法接受监督。\r\n\r\n&nbsp;\r\n\r\n<strong><b>2、教师应当依法履行哪些义务？ </b></strong>\r\n\r\n&nbsp;\r\n\r\n答：《教师法》第八条规定教师应当履行下列义务：\r\n\r\n一 遵守宪法、法律和职业道德为人师表\r\n\r\n二 贯彻国家的教育方针遵守规章制度执行学校的教学计划履行教师聘约完成教育教学工作任务\r\n\r\n三 对学生进行宪法所确定的基本原则的教育和爱国主义、民族团结的教育法制教育以及思想品德、文化、科学技术教育组织、带领学生开展有益的社会活动\r\n\r\n四 关心、爱护全体学生尊重学生人格促进学生在品德、智力、体质等方面全面发展\r\n\r\n五 制止有害于学生的行为或者其他侵犯学生合法权益的行为批评和抵制有害于学生健康成长的现象\r\n\r\n六 不断提高思想政治觉悟和教育教学业务水平。\r\n\r\n&nbsp;\r\n\r\n<strong><b>3、教育法律原则的具体内容是哪些 ？</b></strong>\r\n\r\n&nbsp;\r\n\r\n答：一促进人的全面发展的原则\r\n\r\n二尊重和保障受教育权的原则\r\n\r\n三教育优先发展原则 四维护受教育者健康成长的原则\r\n\r\n&nbsp;\r\n\r\n<strong><b>4、学校安全工作的职责有哪些？</b></strong>\r\n\r\n&nbsp;\r\n\r\n答：学校安全工作的职责主要包括 ：\r\n\r\n1、保证设施安全；\r\n\r\n2、完善安全制度；\r\n\r\n3、 落实安全教育；\r\n\r\n4、安全管理到位；\r\n\r\n5、及时救治伤病；\r\n\r\n6、常备应急预案；\r\n\r\n7、关注校园周边环境安全。\r\n\r\n&nbsp;\r\n\r\n<strong><b>五、论述题20 分 </b></strong>\r\n\r\n&nbsp;\r\n\r\n<strong><b>结合实际谈谈如何实施依法治校、构建和谐校园。 </b></strong>\r\n\r\n1、建章立制依法治校促进学校的民主化管理\r\n\r\n依法治校民主管理是一个学校发展的基石。依据法律、法规以及学校的实际情况学校应制定了一系列规章制度并汇编成册保证了学校各部门各岗位高效运作学校管理步入了规范化、制度化的轨道。学校系列的管理职责和制度让教师们严守规范尽职尽责学生管理方面的制度又制约着学生规范行为勤奋学习努力向上学生、家长评价等方面的制度督促老师认真教学形成文明教风。各项制度又形成合力推动着学校文明三风的形成。如下列学校制度推进学校办学管理的民主进程。\r\n\r\n一教代会制度。高度重视教代会充分发扬民主倾听群众的呼声广泛采纳各种合理化建议保证了学校工作健康发展。\r\n\r\n二民主生活会制度。每学期学校行政班子都要举行23次民主生活会通过召开行政班子成员民主生活会开展批评和自我批评班子内部进一步加强了沟通形成了民主作风。\r\n\r\n三师生申诉制度。学校重视保护师生的合法权益畅通了申诉渠道师生均可以通过一定程序为维护自己的权益逐级向上质询、申诉。\r\n\r\n四多渠道评教制度。学校坚持学生评议教师师生评议领导群众评议党员家长、社会单位评议学校的四评议制度形成了学校的管理特色。\r\n\r\n五校务公开制度。坚持校务公开制度是学校管理民主化的重要体现是依法治校、和谐发展的重要举措。我校坚持通过告家长书、公示栏、意见箱、网络平台等向家长、社会、师生公开校务。学校规划与发展目标的确立年度计划的拟定学校规章制度的落实各项方案的实施校内各项工程承包财务收支、津贴发放、资金分配、职称晋升、评模选优等事关学校发展与教职工利益的大事情都要经过学校各级民主会议讨论评议由教代会通过并将结果张榜公示。对群众师生关心的问题由专人负责解释收费问题严格按照收费标准收费和据实结算并按要求公示\r\n\r\n六家长委员会制度。家长委员会在评教和为学校发展献计献策的活动中发挥着重大作用。家长委员会定期召开会议还经常应邀参加学校重大决策和重要会议发挥民主建议作用。\r\n\r\n七规范办学社会承诺制度。为规范办学行为对事关群众利益的招生、教育收费标准和结算情况、农转非家庭和城市困难职工家庭学生杂费减免等焦点、热点问题学校通过校园公示栏、召开家长会、公开向社会承诺并自觉接受社会监督。\r\n\r\n2、以人为本依法办学促进校园和谐发展\r\n\r\n学校应提出建设和谐校园打造名校品牌的校园建设目标把健康、文明、和谐、发展确定为校园主题。在办学过程中做到全面贯彻党的教育方针自觉遵守国家法律法规依法实施办学活动全面实施素质教育。学校认真推行新课程改革方案执行学制规定、课程计划、按课程标准实施教学活动学校教师依法执教没有无故使学生中途停学、退学或开除学生的现象没有擅自放假现象学生遵章守纪没有违法违纪的事件发生。依法维护学生受教育权尊重学生人格和权利。保障学生参加教育教学计划安排的各项活动无体罚或变相体罚及侮辱、歧视学生的现象按照国家规定的收费规定标准和收费项目向学生收取费用无乱收费现象。建立学生安全和伤害事故的应急处理预案和报告制度依法妥善处理学生伤害事故。实现安全教育制度化、规范化预防和减少了学生的伤害事故。建立“校长信箱”“校长接待制度”接受学生申诉家长投诉维护学生合法权益。\r\n\r\n一充分保障教师权益。在教师队伍建设中。学校注重教师工作环境的改善注重教师教育人生、生活品味的提升。不断改善教师福利坚持帮扶弱势群体在家属与子女就业、入学等问题上提供便利实行了优秀教师、骨干教师学习进修培训制度关心慰问教师红白喜事为教师排忧解难。使教师生存有保障、生活有质量、发展有平台、事业有追求。\r\n\r\n二充分尊重和保护学生权益。在学生管理中学校倡导“法”就是常规“法”就是生活的观点要求领导、教师将《教育法》、《教师法》、《未成年人保护法》的贯彻具体到日常教学管理中提出了“全员抓德育全民重德育”的管理思想。每个领导要融入教师、融入学生、融入校园生活每个教师要融入学生、融入课堂、融入学生生活从学习、生活、与人交往等诸多方面为学生做出表率。教师必须全面掌握本班学生的情况特别要关注和关心家庭有困难的学生。要求教师必须充分尊重每一个学生的人格及其他人身权利和财产权利保障学生参加教育教学计划安排的各项活动将教师的师德师风考核与晋级晋职考核相结合实行“一票否决”制度。\r\n\r\n&nbsp;', '教师普法考试试题及答案', '', 'inherit', 'closed', 'closed', '', '160-revision-v1', '', '', '2017-05-03 10:37:27', '2017-05-03 02:37:27', '', 160, 'http://bm.yangyongquan.com/2017/05/03/160-revision-v1/', 0, 'revision', '', 0);
INSERT INTO `wp_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES
(163, 1, '2017-04-27 16:48:18', '2017-04-27 08:48:18', '绝密★ 启用前\r\n\r\n<strong><b>2007 年江苏省普通高中学业水平测试（必修科目）试卷生物</b></strong>\r\n\r\n注意事项\r\n\r\n考生在答题前请认真阅读本注意事项及各题答题要求\r\n\r\n1．本试卷包含选择题（第1 题～第35 题，35 题，共70 分）、非选择题（第36 题～第40 题，5 题，共30 分）共两部分。考生答题全部答在答题卡上，答在本试卷上无效。本次考试时间为75 分钟。考试结束后，请将本试卷和答题卡一并放在桌面，等待监考员收回。\r\n\r\n2．答题前，请务必将自己的姓名、准考证号用书写黑色字迹的0.5毫米签字笔填写在本试卷及答题卡上。\r\n\r\n3．请认真核对监考员在答题卡右上角所粘贴条形码上的姓名、准考证号是否与本人的相符合。\r\n\r\n4．答选择题必须用ZB 铅笔把答题卡上对应题目的答案标号涂黑。如需改动，请用橡皮擦干净后，再选涂其它答案。答非选择题必须用书写黑色字迹的0. 5 毫米签字笔写在答题卡上的指定位置，在其它位置答题一律无效。\r\n\r\n<strong><b>一、单项选择题：每小题只有一个选项最符合题意（本题包括35 小题，每小题2 分，共70 分）。</b></strong>\r\n\r\n1．鱼类在水中遨游、鸟类在空中飞翔，虽形态各异、习性不同，但体内的基本组成相似。它们细胞中含量最多的化合物都是\r\n\r\nA．水      B．糖类      C．脂肪      D．蛋白质\r\n\r\n2．在血红蛋白的结构中，连接两个氨基酸分子的化学键叫做\r\n\r\nA．磷酸键     B．二酯键     C．肽键     D．离子键\r\n\r\n3．组成细胞膜的主要成分是\r\n\r\nA．脂质（磷脂）和多糖           B．蛋白质和多糖\r\n\r\nC．脂质（磷脂）和蛋白质         D．核酸和蛋白质\r\n\r\n4．下列细胞结构属于生物膜系统的是\r\n\r\nA．中心体     B．核糖体    C．染色体     D．内质网\r\n\r\n5．在电子显微镜下观察某生物细胞，发现有叶绿体、高尔基体、线粒体等细胞器，由此可判断该细胞可能取自\r\n\r\nA．果蝇       B．水稻      C．家兔       D．大肠杆菌\r\n\r\n6．将哺乳动物的新鲜红细胞放人下列溶液中，会使红细胞涨破的溶液是\r\n<ol>\r\n 	<li>0.9％生理盐水    B.5％盐水      C. 10％盐水     D．自来水</li>\r\n</ol>\r\n7．生物体细胞有氧呼吸的最终产物是\r\n\r\nA．丙酮酸和[H]              B．乳酸\r\n\r\nC．二氧化碳和水             D．酒精和二氧化碳\r\n\r\n8．在植物细胞工程中常需要去掉细胞壁，在不损伤植物细胞内部结构的情况下，下列可用于去除细胞壁的物质是\r\n\r\nA．纤维素酶        B．蛋白酶\r\n\r\nC．盐酸            D．脂肪酶\r\n\r\n9．生物体的生命活动都需要能量，直接给细胞的生命活动提供能量的物质是\r\n\r\nA．糖类            B.蛋白质\r\n<ol>\r\n 	<li>ATP  D．核酸</li>\r\n</ol>\r\n10．右图表示某种生物细胞的有丝分裂过程中某一时期的图像，该细胞所处的分裂时期为\r\n\r\nA．前期          B．中期       C．后期         D．末期\r\n\r\n11．下列有关癌细胞的叙述，错误的是\r\n\r\nA．癌细胞不能在体内转移     B．癌细胞能够无限增殖\r\n\r\nC．癌细胞膜上的糖蛋白减少   D．癌细胞是由正常细胞转化而来的\r\n\r\n12．蝴蝶兰幼叶的叶肉细胞经离体组织培养能培育成蝴蝶兰幼苗，这说明植物细胞具有\r\n\r\nA．专一性   B．全能性   C．恢复原状态的能力   D．进一步分化的能力\r\n\r\n13．右图为某动物精巢内一个精原细胞在减数分裂过程中细胞核内DNA 含量变化的曲线图。b-c段细胞内染色体的数目是DNA含量\r\n\r\nA.n    B.2n   C.3n   D.4n\r\n\r\n14．在人类探究遗传物质的过程中，科学家以T<sub>2</sub>噬菌体作为实验材料，利用放射性同位素标记技术完成了噬菌体侵染细菌的实验，在此实验中，用<sup>35</sup>S、<sup>32</sup> P 分别标记的是噬菌体的\r\n<ol>\r\n 	<li>DNA 、蛋白质    B．蛋白质、蛋白质</li>\r\n 	<li>DNA 、DNA       D．蛋白质、DNA</li>\r\n</ol>\r\n15．在双链DNA分子结构中，两条链上的碱基通过氢键连接成碱基对，下列碱基配对正确的是\r\n<ol>\r\n 	<li>A-T     B. A-G    C. T-G     D.T-C</li>\r\n</ol>\r\n16．下列有关基因的叙述，错误的是\r\n\r\nA．可以准确地复制            B．能够存储遗传信息\r\n\r\nC．是20种氨基酸的有序排列   D．是有遗传效应的DNA 片段\r\n\r\n17．在遗传信息的传递过程中，以DNA的一条链为模板合成信使RNA的过程称为\r\n\r\nA．逆转录    B．转录       C．复制     D．翻译\r\n\r\n18．下图为某家族白化病的遗传系谱图，该病的致病基因位于常染色体上。在第Ⅲ代个体中，可能不带致病基因的是\r\n\r\n&nbsp;\r\n\r\nA.8      B.9    C.10    D.11 ,\r\n\r\n19．根据基因的自由组合定律，在正常情况下，基因型为YyRr的豌豆不能产生的配子是\r\n\r\nA.YR      B.Yr     C.yR     D.YY\r\n\r\n20．下列关于孟德尔研究遗传规律获得成功原因的叙述，错误的是\r\n\r\nA．先分析多对相对性状，后分析一对相对性状\r\n\r\nB．科学地设计实验程序，提出假说并进行验证\r\n\r\nC．正确地选用豌豆作为实验材料\r\n\r\nD．运用统计学方法分析实验结果\r\n\r\n21．下列各组性状中，属于相对性状的是\r\n\r\nA．豌豆的高茎与绿色豆荚   B．羊的黑毛与兔的白毛\r\n\r\nC．棉花的细绒与长绒       D．人的双眼皮与单眼皮\r\n\r\n22．诱变育种所依据的遗传学原理是\r\n\r\nA．基因自由组合           B．基因突变\r\n\r\nC．染色体变异             D．染色体交叉互换\r\n\r\n23．下列人类常见遗传病中属于染色体变异的是\r\n\r\nA．红绿色盲病             B．镰刀型细胞贫血症\r\n<ol>\r\n 	<li>21三体综合征          D．先天性聋哑</li>\r\n</ol>\r\n24．下列关于现代生物进化理论的说法，错误的是\r\n\r\nA．生物进化的基本单位是生态系统\r\n\r\nB．突变和基因重组产生进化的原材料\r\n\r\nC．进化的实质是种群内基因频率的改变\r\n\r\nD．自然选择决定生物进化的方向\r\n\r\n25．人体细胞的生活环境称为内环境，内环境是指\r\n\r\nA．细胞内液     B．细胞外液     C．体液       D．组织液\r\n\r\n26．在人体的特异性免疫中发挥主要作用的是\r\n\r\nA．神经细胞     B．内分泌细胞   C．上皮细胞   D．淋巴细胞\r\n<ol start="27">\r\n 	<li>2006年的“世界艾滋病日”会议在我国天津市举行，会议的主题为：行动起来，遏制艾滋。关于艾滋病的说法错误的是</li>\r\n</ol>\r\nA．艾滋病是一种遗传病      B．艾滋病病毒主要攻击T淋巴细胞\r\n\r\nC．艾滋病主要通过血液传染   D．艾滋病又称获得性免疫缺陷综合症（AIDS )\r\n\r\n28．在盛有称猴桃的袋子里放几只成熟的苹果，能促进较硬的称猴桃很快成熟变软，这期间起重要作用的激素是\r\n\r\nA．生长素     B．赤霉素    C．乙烯     D．脱落酸\r\n\r\n29．下图表示某种昆虫在不同温度和湿度条件下种群数量的变化曲线，有关叙述正确的是\r\n\r\n&nbsp;\r\n\r\nA．昆虫种群数量的变化只受湿度的影响\r\n\r\nB．昆虫种群数量的变化只受温度的影响\r\n\r\nC．昆虫种群数量的变化是温度和湿度综合作用的结果\r\n\r\nD．昆虫种群数量的变化与温度和湿度无关，只和种群大小有关\r\n\r\n30．从裸露的岩石上长出森林是一个漫长而艰难的演替过程。发生在裸露岩石上的群落演替，顺序正确的是\r\n\r\nA．地衣、苔鲜阶段→草本阶段→灌木阶段→森林阶段\r\n\r\nB．地衣、苔鲜阶段→灌木阶段→草本阶段→森林阶段\r\n\r\nC．草本阶段→地衣、苔鲜阶段→灌木阶段→森林阶段\r\n\r\nD．地衣、苔鲜阶段→草本阶段→森林阶段→灌木阶段\r\n\r\n31．人类的下列活动中，有利于维持生态系统稳定性的是\r\n\r\nA．大量喷洒农药杀虫      B．大量引进外来物种\r\n\r\nC．围湖造田扩大耕地      D．建造防护林防风阻沙\r\n\r\n32．在生态系统中传递着多种多样的信息，下列属于化学信息的是\r\n\r\nA．丹顶鹤求偶时的双双起舞    B．雌蚕蛾释放的性外激素\r\n\r\nC．蜘蛛网的振动频率          D．春季鸟类的求偶鸣叫声\r\n\r\n33．生物多样性是人类赖以生存和发展的物质基础，通常所指的生物多样性不包括\r\n\r\nA．遗传（基因）的多样性      B．生态系统的多样性\r\n\r\nC．物种的多样性              D．细胞结构的多样性\r\n\r\n34．在观察植物细胞有丝分裂的实验中，将洋葱根尖染色的试剂是\r\n\r\nA．碘液     B．斐林试剂      C．龙胆紫溶液    D．苏丹Ⅲ染液\r\n\r\n35．有同学尝试设计生态瓶，在制定方案时，下列有关设计的方法步骤错误的是\r\n\r\nA．合理搭配瓶内生物与非生物的成分\r\n\r\nB．按合适的比例放入不同营养级的生物\r\n\r\nC．生态瓶摆放在光照适宜的位置\r\n\r\nD．定期向瓶内投放食物\r\n\r\n<strong><b>二、非选择题：（本题包括5小题，共30分）</b></strong>\r\n<ol start="36">\r\n 	<li>( 6分）下图为光照条件下一个叶肉细胞中两种细胞器之间的气体交换示意图，据图回答（在［   ］中填序号，在 <u></u>上填名称）:</li>\r\n</ol>\r\n&nbsp;\r\n\r\n(l）图中所示的细胞器A是<u>        </u> , B 是<u>         </u>。\r\n\r\n(2）图中物质a是<u>        </u>，它是在[    ]<u>        </u>部位产生的。\r\n\r\n(3）实验室中进行光合作用实验的植物，如果突然停止给予光照，那么在短时间内，该植物进行光合作用的细胞器中，三碳化合物和五碳化合物的含量变化分别是<u>                                        </u>。\r\n<ol start="37">\r\n 	<li>( 6分）某种自花传粉的豆科植物，同一植株能开很多花，不同品种植株所结种子的子叶有紫色也有白色。现用该豆科植物的甲、乙、丙三个品种的植株进行如下实验。</li>\r\n</ol>\r\n<table>\r\n<tbody>\r\n<tr>\r\n<td rowspan="2" width="91">实验组别</td>\r\n<td rowspan="2" width="296">亲本的处理方法</td>\r\n<td colspan="2" width="180">所结种子的性状及数量</td>\r\n</tr>\r\n<tr>\r\n<td width="87">紫色子叶</td>\r\n<td width="92">白色子叶</td>\r\n</tr>\r\n<tr>\r\n<td width="91">实验一</td>\r\n<td width="296">将甲植株进行自花传粉</td>\r\n<td width="87">409粒</td>\r\n<td width="92">0</td>\r\n</tr>\r\n<tr>\r\n<td width="91">实验二</td>\r\n<td width="296">将乙植株进行自花传粉</td>\r\n<td width="87">O</td>\r\n<td width="92">405粒</td>\r\n</tr>\r\n<tr>\r\n<td width="91">实验三</td>\r\n<td width="296">将甲植株的花除去未成熟的全部雄蕊，然后套上纸袋，待雌蕊成熟时，接受乙植株的花粉</td>\r\n<td width="87">396粒</td>\r\n<td width="92">0</td>\r\n</tr>\r\n<tr>\r\n<td width="91">实验四</td>\r\n<td width="296">将丙植株进行自花传粉</td>\r\n<td width="87">297粒</td>\r\n<td width="92">101粒</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n分析回答：\r\n\r\n(l）在该植物种子子叶的紫色和白色这一对相对性状中，显性性状是<u>         </u>。如果用A代表显性基因，a代表隐性基因，则甲植株的基因型为<u>       </u>，丙植株的基因型为<u>      </u>。\r\n\r\n(2）实验三所结的紫色子叶种子中，能稳定遗传的种子占<u>         </u>。\r\n\r\n(3）实验四所结的297粒紫色子叶种子中杂合子的理论值为<u>          </u>粒。\r\n\r\n(4）若将丙植株的花除去未成熟的全部雄蕊，然后套上纸袋，待雌蕊成熟时，接受乙植株的花粉，则预期的实验结果为紫色子叶种子：白色子叶种子＝<u>                  </u>。\r\n<ol start="38">\r\n 	<li>( 6分）下图表示反射弧和神经纤维局部放大的示意图，据图回答（在[    ]中填序号，在 <u></u>上填名称）:</li>\r\n</ol>\r\n&nbsp;\r\n\r\n(l）在A 图中，①所示的结构属于反射弧的<u>               </u>。\r\n\r\n(2) B图表示神经纤维受到刺激的瞬间膜内外电荷的分布情况，在a、b、c中兴奋部位是<u>             </u>。在兴奋部位和相邻的未兴奋部位之间，由于电位差的存在而发生电荷移动，这样就形成了<u>                    </u>。\r\n\r\n(3）兴奋在反射弧中按单一方向传导的原因是在A 图的[   ]<u>           </u>结构中，信号的传递是单一方向的，在此结构中信号的转换模式为<u>                       </u>。\r\n<ol start="39">\r\n 	<li>( 6分）某研究性学习小组的同学利用郊游的机会，对当地某一农田生态系统进行了调查。他们发现水稻田中有稗草等杂草和蝗虫等动物。蝗虫、田鼠以水稻、稗草为食，蛙以蝗虫为食，蛇既吃田鼠也吃蛙。分析回答：</li>\r\n</ol>\r\n(l）请将该农田生态系统的食物链（网）补充完整。\r\n\r\n&nbsp;\r\n\r\n(2）蛇在此生态系统中所处的营养级是<u>                    </u>。\r\n\r\n(3）如果想对田鼠这种活动能力强、活动范围大的动物进行种群密度的调查，常采用<u>     </u>法。\r\n\r\n(4）如果你是该研究小组的成员，为了使该生态系统中的能量尽可能多地流向水稻，同时又要保护生态环境，你会向农民提出哪些合理化建议？（至少提出两条）\r\n\r\n&nbsp;\r\n\r\n&nbsp;\r\n\r\n40.(6分）根据我国现行的食品质量标准，0～6个月的婴儿奶粉中蛋白质的含量应为12％～18％。现有一种待测婴儿奶粉，请你尝试完成鉴定实验。\r\n\r\n(l）实验目的\r\n\r\n鉴定该待测婴儿奶粉蛋白质的含量是否符合质量标准。\r\n\r\n(2）实验原理\r\n\r\n蛋白质与<u>          </u>试剂发生作用，产生紫色反应。\r\n\r\n(3）材料用具\r\n\r\n相同浓度的标准婴儿奶粉溶液和待测婴儿奶粉溶液、0.1g/mL的Na0H 溶液、0.01 g/mL 的CuSO<sub>4</sub>溶液、试管和滴管等。\r\n\r\n(4）实验步骤\r\n\r\n① 取两支试管分别加人2mL的标准婴儿奶粉溶液（编号甲）和2mL的待测婴儿奶粉溶液（编号乙）。标准婴儿奶粉溶液在本实验中起<u>               </u>作用。\r\n\r\n② 分别向两支试管中加入2mL的<u>          </u>溶液，振荡，摇匀。\r\n\r\n③ 再分别向两支试管中加人3～4滴<u>         </u>溶液，振荡，摇匀，比较颜色的变化。\r\n\r\n(5）结果预期\r\n\r\n<u>                                                                      </u>。\r\n\r\n&nbsp;', '绝密★-启用前', '', 'publish', 'open', 'open', '', '%e7%bb%9d%e5%af%86%e2%98%85-%e5%90%af%e7%94%a8%e5%89%8d', '', '', '2017-05-03 10:50:04', '2017-05-03 02:50:04', '', 0, 'http://bm.yangyongquan.com/?p=163', 0, 'post', '', 0),
(164, 1, '2017-05-03 10:50:04', '2017-05-03 02:50:04', '绝密★ 启用前\r\n\r\n<strong><b>2007 年江苏省普通高中学业水平测试（必修科目）试卷生物</b></strong>\r\n\r\n注意事项\r\n\r\n考生在答题前请认真阅读本注意事项及各题答题要求\r\n\r\n1．本试卷包含选择题（第1 题～第35 题，35 题，共70 分）、非选择题（第36 题～第40 题，5 题，共30 分）共两部分。考生答题全部答在答题卡上，答在本试卷上无效。本次考试时间为75 分钟。考试结束后，请将本试卷和答题卡一并放在桌面，等待监考员收回。\r\n\r\n2．答题前，请务必将自己的姓名、准考证号用书写黑色字迹的0.5毫米签字笔填写在本试卷及答题卡上。\r\n\r\n3．请认真核对监考员在答题卡右上角所粘贴条形码上的姓名、准考证号是否与本人的相符合。\r\n\r\n4．答选择题必须用ZB 铅笔把答题卡上对应题目的答案标号涂黑。如需改动，请用橡皮擦干净后，再选涂其它答案。答非选择题必须用书写黑色字迹的0. 5 毫米签字笔写在答题卡上的指定位置，在其它位置答题一律无效。\r\n\r\n<strong><b>一、单项选择题：每小题只有一个选项最符合题意（本题包括35 小题，每小题2 分，共70 分）。</b></strong>\r\n\r\n1．鱼类在水中遨游、鸟类在空中飞翔，虽形态各异、习性不同，但体内的基本组成相似。它们细胞中含量最多的化合物都是\r\n\r\nA．水      B．糖类      C．脂肪      D．蛋白质\r\n\r\n2．在血红蛋白的结构中，连接两个氨基酸分子的化学键叫做\r\n\r\nA．磷酸键     B．二酯键     C．肽键     D．离子键\r\n\r\n3．组成细胞膜的主要成分是\r\n\r\nA．脂质（磷脂）和多糖           B．蛋白质和多糖\r\n\r\nC．脂质（磷脂）和蛋白质         D．核酸和蛋白质\r\n\r\n4．下列细胞结构属于生物膜系统的是\r\n\r\nA．中心体     B．核糖体    C．染色体     D．内质网\r\n\r\n5．在电子显微镜下观察某生物细胞，发现有叶绿体、高尔基体、线粒体等细胞器，由此可判断该细胞可能取自\r\n\r\nA．果蝇       B．水稻      C．家兔       D．大肠杆菌\r\n\r\n6．将哺乳动物的新鲜红细胞放人下列溶液中，会使红细胞涨破的溶液是\r\n<ol>\r\n 	<li>0.9％生理盐水    B.5％盐水      C. 10％盐水     D．自来水</li>\r\n</ol>\r\n7．生物体细胞有氧呼吸的最终产物是\r\n\r\nA．丙酮酸和[H]              B．乳酸\r\n\r\nC．二氧化碳和水             D．酒精和二氧化碳\r\n\r\n8．在植物细胞工程中常需要去掉细胞壁，在不损伤植物细胞内部结构的情况下，下列可用于去除细胞壁的物质是\r\n\r\nA．纤维素酶        B．蛋白酶\r\n\r\nC．盐酸            D．脂肪酶\r\n\r\n9．生物体的生命活动都需要能量，直接给细胞的生命活动提供能量的物质是\r\n\r\nA．糖类            B.蛋白质\r\n<ol>\r\n 	<li>ATP  D．核酸</li>\r\n</ol>\r\n10．右图表示某种生物细胞的有丝分裂过程中某一时期的图像，该细胞所处的分裂时期为\r\n\r\nA．前期          B．中期       C．后期         D．末期\r\n\r\n11．下列有关癌细胞的叙述，错误的是\r\n\r\nA．癌细胞不能在体内转移     B．癌细胞能够无限增殖\r\n\r\nC．癌细胞膜上的糖蛋白减少   D．癌细胞是由正常细胞转化而来的\r\n\r\n12．蝴蝶兰幼叶的叶肉细胞经离体组织培养能培育成蝴蝶兰幼苗，这说明植物细胞具有\r\n\r\nA．专一性   B．全能性   C．恢复原状态的能力   D．进一步分化的能力\r\n\r\n13．右图为某动物精巢内一个精原细胞在减数分裂过程中细胞核内DNA 含量变化的曲线图。b-c段细胞内染色体的数目是DNA含量\r\n\r\nA.n    B.2n   C.3n   D.4n\r\n\r\n14．在人类探究遗传物质的过程中，科学家以T<sub>2</sub>噬菌体作为实验材料，利用放射性同位素标记技术完成了噬菌体侵染细菌的实验，在此实验中，用<sup>35</sup>S、<sup>32</sup> P 分别标记的是噬菌体的\r\n<ol>\r\n 	<li>DNA 、蛋白质    B．蛋白质、蛋白质</li>\r\n 	<li>DNA 、DNA       D．蛋白质、DNA</li>\r\n</ol>\r\n15．在双链DNA分子结构中，两条链上的碱基通过氢键连接成碱基对，下列碱基配对正确的是\r\n<ol>\r\n 	<li>A-T     B. A-G    C. T-G     D.T-C</li>\r\n</ol>\r\n16．下列有关基因的叙述，错误的是\r\n\r\nA．可以准确地复制            B．能够存储遗传信息\r\n\r\nC．是20种氨基酸的有序排列   D．是有遗传效应的DNA 片段\r\n\r\n17．在遗传信息的传递过程中，以DNA的一条链为模板合成信使RNA的过程称为\r\n\r\nA．逆转录    B．转录       C．复制     D．翻译\r\n\r\n18．下图为某家族白化病的遗传系谱图，该病的致病基因位于常染色体上。在第Ⅲ代个体中，可能不带致病基因的是\r\n\r\n&nbsp;\r\n\r\nA.8      B.9    C.10    D.11 ,\r\n\r\n19．根据基因的自由组合定律，在正常情况下，基因型为YyRr的豌豆不能产生的配子是\r\n\r\nA.YR      B.Yr     C.yR     D.YY\r\n\r\n20．下列关于孟德尔研究遗传规律获得成功原因的叙述，错误的是\r\n\r\nA．先分析多对相对性状，后分析一对相对性状\r\n\r\nB．科学地设计实验程序，提出假说并进行验证\r\n\r\nC．正确地选用豌豆作为实验材料\r\n\r\nD．运用统计学方法分析实验结果\r\n\r\n21．下列各组性状中，属于相对性状的是\r\n\r\nA．豌豆的高茎与绿色豆荚   B．羊的黑毛与兔的白毛\r\n\r\nC．棉花的细绒与长绒       D．人的双眼皮与单眼皮\r\n\r\n22．诱变育种所依据的遗传学原理是\r\n\r\nA．基因自由组合           B．基因突变\r\n\r\nC．染色体变异             D．染色体交叉互换\r\n\r\n23．下列人类常见遗传病中属于染色体变异的是\r\n\r\nA．红绿色盲病             B．镰刀型细胞贫血症\r\n<ol>\r\n 	<li>21三体综合征          D．先天性聋哑</li>\r\n</ol>\r\n24．下列关于现代生物进化理论的说法，错误的是\r\n\r\nA．生物进化的基本单位是生态系统\r\n\r\nB．突变和基因重组产生进化的原材料\r\n\r\nC．进化的实质是种群内基因频率的改变\r\n\r\nD．自然选择决定生物进化的方向\r\n\r\n25．人体细胞的生活环境称为内环境，内环境是指\r\n\r\nA．细胞内液     B．细胞外液     C．体液       D．组织液\r\n\r\n26．在人体的特异性免疫中发挥主要作用的是\r\n\r\nA．神经细胞     B．内分泌细胞   C．上皮细胞   D．淋巴细胞\r\n<ol start="27">\r\n 	<li>2006年的“世界艾滋病日”会议在我国天津市举行，会议的主题为：行动起来，遏制艾滋。关于艾滋病的说法错误的是</li>\r\n</ol>\r\nA．艾滋病是一种遗传病      B．艾滋病病毒主要攻击T淋巴细胞\r\n\r\nC．艾滋病主要通过血液传染   D．艾滋病又称获得性免疫缺陷综合症（AIDS )\r\n\r\n28．在盛有称猴桃的袋子里放几只成熟的苹果，能促进较硬的称猴桃很快成熟变软，这期间起重要作用的激素是\r\n\r\nA．生长素     B．赤霉素    C．乙烯     D．脱落酸\r\n\r\n29．下图表示某种昆虫在不同温度和湿度条件下种群数量的变化曲线，有关叙述正确的是\r\n\r\n&nbsp;\r\n\r\nA．昆虫种群数量的变化只受湿度的影响\r\n\r\nB．昆虫种群数量的变化只受温度的影响\r\n\r\nC．昆虫种群数量的变化是温度和湿度综合作用的结果\r\n\r\nD．昆虫种群数量的变化与温度和湿度无关，只和种群大小有关\r\n\r\n30．从裸露的岩石上长出森林是一个漫长而艰难的演替过程。发生在裸露岩石上的群落演替，顺序正确的是\r\n\r\nA．地衣、苔鲜阶段→草本阶段→灌木阶段→森林阶段\r\n\r\nB．地衣、苔鲜阶段→灌木阶段→草本阶段→森林阶段\r\n\r\nC．草本阶段→地衣、苔鲜阶段→灌木阶段→森林阶段\r\n\r\nD．地衣、苔鲜阶段→草本阶段→森林阶段→灌木阶段\r\n\r\n31．人类的下列活动中，有利于维持生态系统稳定性的是\r\n\r\nA．大量喷洒农药杀虫      B．大量引进外来物种\r\n\r\nC．围湖造田扩大耕地      D．建造防护林防风阻沙\r\n\r\n32．在生态系统中传递着多种多样的信息，下列属于化学信息的是\r\n\r\nA．丹顶鹤求偶时的双双起舞    B．雌蚕蛾释放的性外激素\r\n\r\nC．蜘蛛网的振动频率          D．春季鸟类的求偶鸣叫声\r\n\r\n33．生物多样性是人类赖以生存和发展的物质基础，通常所指的生物多样性不包括\r\n\r\nA．遗传（基因）的多样性      B．生态系统的多样性\r\n\r\nC．物种的多样性              D．细胞结构的多样性\r\n\r\n34．在观察植物细胞有丝分裂的实验中，将洋葱根尖染色的试剂是\r\n\r\nA．碘液     B．斐林试剂      C．龙胆紫溶液    D．苏丹Ⅲ染液\r\n\r\n35．有同学尝试设计生态瓶，在制定方案时，下列有关设计的方法步骤错误的是\r\n\r\nA．合理搭配瓶内生物与非生物的成分\r\n\r\nB．按合适的比例放入不同营养级的生物\r\n\r\nC．生态瓶摆放在光照适宜的位置\r\n\r\nD．定期向瓶内投放食物\r\n\r\n<strong><b>二、非选择题：（本题包括5小题，共30分）</b></strong>\r\n<ol start="36">\r\n 	<li>( 6分）下图为光照条件下一个叶肉细胞中两种细胞器之间的气体交换示意图，据图回答（在［   ］中填序号，在 <u></u>上填名称）:</li>\r\n</ol>\r\n&nbsp;\r\n\r\n(l）图中所示的细胞器A是<u>        </u> , B 是<u>         </u>。\r\n\r\n(2）图中物质a是<u>        </u>，它是在[    ]<u>        </u>部位产生的。\r\n\r\n(3）实验室中进行光合作用实验的植物，如果突然停止给予光照，那么在短时间内，该植物进行光合作用的细胞器中，三碳化合物和五碳化合物的含量变化分别是<u>                                        </u>。\r\n<ol start="37">\r\n 	<li>( 6分）某种自花传粉的豆科植物，同一植株能开很多花，不同品种植株所结种子的子叶有紫色也有白色。现用该豆科植物的甲、乙、丙三个品种的植株进行如下实验。</li>\r\n</ol>\r\n<table>\r\n<tbody>\r\n<tr>\r\n<td rowspan="2" width="91">实验组别</td>\r\n<td rowspan="2" width="296">亲本的处理方法</td>\r\n<td colspan="2" width="180">所结种子的性状及数量</td>\r\n</tr>\r\n<tr>\r\n<td width="87">紫色子叶</td>\r\n<td width="92">白色子叶</td>\r\n</tr>\r\n<tr>\r\n<td width="91">实验一</td>\r\n<td width="296">将甲植株进行自花传粉</td>\r\n<td width="87">409粒</td>\r\n<td width="92">0</td>\r\n</tr>\r\n<tr>\r\n<td width="91">实验二</td>\r\n<td width="296">将乙植株进行自花传粉</td>\r\n<td width="87">O</td>\r\n<td width="92">405粒</td>\r\n</tr>\r\n<tr>\r\n<td width="91">实验三</td>\r\n<td width="296">将甲植株的花除去未成熟的全部雄蕊，然后套上纸袋，待雌蕊成熟时，接受乙植株的花粉</td>\r\n<td width="87">396粒</td>\r\n<td width="92">0</td>\r\n</tr>\r\n<tr>\r\n<td width="91">实验四</td>\r\n<td width="296">将丙植株进行自花传粉</td>\r\n<td width="87">297粒</td>\r\n<td width="92">101粒</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n分析回答：\r\n\r\n(l）在该植物种子子叶的紫色和白色这一对相对性状中，显性性状是<u>         </u>。如果用A代表显性基因，a代表隐性基因，则甲植株的基因型为<u>       </u>，丙植株的基因型为<u>      </u>。\r\n\r\n(2）实验三所结的紫色子叶种子中，能稳定遗传的种子占<u>         </u>。\r\n\r\n(3）实验四所结的297粒紫色子叶种子中杂合子的理论值为<u>          </u>粒。\r\n\r\n(4）若将丙植株的花除去未成熟的全部雄蕊，然后套上纸袋，待雌蕊成熟时，接受乙植株的花粉，则预期的实验结果为紫色子叶种子：白色子叶种子＝<u>                  </u>。\r\n<ol start="38">\r\n 	<li>( 6分）下图表示反射弧和神经纤维局部放大的示意图，据图回答（在[    ]中填序号，在 <u></u>上填名称）:</li>\r\n</ol>\r\n&nbsp;\r\n\r\n(l）在A 图中，①所示的结构属于反射弧的<u>               </u>。\r\n\r\n(2) B图表示神经纤维受到刺激的瞬间膜内外电荷的分布情况，在a、b、c中兴奋部位是<u>             </u>。在兴奋部位和相邻的未兴奋部位之间，由于电位差的存在而发生电荷移动，这样就形成了<u>                    </u>。\r\n\r\n(3）兴奋在反射弧中按单一方向传导的原因是在A 图的[   ]<u>           </u>结构中，信号的传递是单一方向的，在此结构中信号的转换模式为<u>                       </u>。\r\n<ol start="39">\r\n 	<li>( 6分）某研究性学习小组的同学利用郊游的机会，对当地某一农田生态系统进行了调查。他们发现水稻田中有稗草等杂草和蝗虫等动物。蝗虫、田鼠以水稻、稗草为食，蛙以蝗虫为食，蛇既吃田鼠也吃蛙。分析回答：</li>\r\n</ol>\r\n(l）请将该农田生态系统的食物链（网）补充完整。\r\n\r\n&nbsp;\r\n\r\n(2）蛇在此生态系统中所处的营养级是<u>                    </u>。\r\n\r\n(3）如果想对田鼠这种活动能力强、活动范围大的动物进行种群密度的调查，常采用<u>     </u>法。\r\n\r\n(4）如果你是该研究小组的成员，为了使该生态系统中的能量尽可能多地流向水稻，同时又要保护生态环境，你会向农民提出哪些合理化建议？（至少提出两条）\r\n\r\n&nbsp;\r\n\r\n&nbsp;\r\n\r\n40.(6分）根据我国现行的食品质量标准，0～6个月的婴儿奶粉中蛋白质的含量应为12％～18％。现有一种待测婴儿奶粉，请你尝试完成鉴定实验。\r\n\r\n(l）实验目的\r\n\r\n鉴定该待测婴儿奶粉蛋白质的含量是否符合质量标准。\r\n\r\n(2）实验原理\r\n\r\n蛋白质与<u>          </u>试剂发生作用，产生紫色反应。\r\n\r\n(3）材料用具\r\n\r\n相同浓度的标准婴儿奶粉溶液和待测婴儿奶粉溶液、0.1g/mL的Na0H 溶液、0.01 g/mL 的CuSO<sub>4</sub>溶液、试管和滴管等。\r\n\r\n(4）实验步骤\r\n\r\n① 取两支试管分别加人2mL的标准婴儿奶粉溶液（编号甲）和2mL的待测婴儿奶粉溶液（编号乙）。标准婴儿奶粉溶液在本实验中起<u>               </u>作用。\r\n\r\n② 分别向两支试管中加入2mL的<u>          </u>溶液，振荡，摇匀。\r\n\r\n③ 再分别向两支试管中加人3～4滴<u>         </u>溶液，振荡，摇匀，比较颜色的变化。\r\n\r\n(5）结果预期\r\n\r\n<u>                                                                      </u>。\r\n\r\n&nbsp;', '绝密★-启用前', '', 'inherit', 'closed', 'closed', '', '163-revision-v1', '', '', '2017-05-03 10:50:04', '2017-05-03 02:50:04', '', 163, 'http://bm.yangyongquan.com/2017/05/03/163-revision-v1/', 0, 'revision', '', 0),
(165, 1, '2017-04-27 16:28:10', '2017-04-27 08:28:10', '<strong><b>2013年上期香花岭完小小学科学期末试卷分析</b></strong>\r\n\r\n一、总体情况\r\n\r\n本次检测全校3—6年级的全体学校参加考试。3-4年级整体成绩较好，及格率98%，优秀率50%；5-6年级成绩一般，及格率78%，优秀率30%。\r\n\r\n二、命题评价\r\n\r\n本次命题题量适度，难易适中,基本覆盖到所有应该掌握的知识点，同时突出了实验教学的内容,符合新课改的精神。\r\n\r\n本套试题考试时限为60分钟，满分100分，共分为五大题。第一题，填空题，目的在于考察学生对相关知识点的掌握情况；\r\n\r\n第二题，判断题，目的是考察学生对知识点的掌握程度和判断能力；\r\n\r\n第三题，选择题，要求学生准确把握所学内容，正确剔除那些似是而非的答案，做出自己的选择；\r\n\r\n第四题，简要回答问题，要求学生用自己的语言对书本上所涉及的知识加以正确的理解，重点考察学生的知识掌握与语言表述能力；\r\n\r\n第五题，完成实验方案，要求学生设计一个实验方案，测量出一个人的肺活量，旨在培养学生的实验操作能力。\r\n\r\n三、学生答题情况分析\r\n\r\n本次学生答题情况总体上看不错，学生能正确理解出题者的意图，准确答题，得分率较高，但也有个别题答题情况不是很好。现将学生的具体答题情况进行简要剖析：\r\n\r\n第一题，填空题，满分22分，学生一般得分在15分——18分左右，答错率较高的是第4小题。本题要求学生填出组成消化道的各个器官，而相当多的学生却忽视了“消化道”三字，误答成组成消化系统的各个器官，从而造成失分。此外，第6小题的差错率也较高，说明学生在平时的学习中对此题掌握得不是很好。\r\n\r\n第二题，判断题，满分24分，学生一般得分在20分左右，差错率较高的是第4小题，学生对肝、胆、胰脏的具体位置掌握不准，说明平时老师在讲解时没有很好的将理论与实践结合起来进行。第5小题也有相当多的同学答错，原因应该在于平时老师过于强调喝酒伤肝，却忽视了酒精对于胃等其它消化器官的伤害，而且肝脏本身就属于消化系统，肝脏的损害直接影响着消化系统的正常工作。。\r\n\r\n第三题，选择题，满分为24分，学生得分在15分左右。第1小题，要求选择说法正确的一项，而本题中有两个正确的答案，即“使用定滑轮不省力”和“使用轮轴不一定省力”，而不知是属于出题者的失误还是判郑老师的疏失，所有选择“使用轮轴不一定省力”的都没有得分，不能不让人遗憾。第8小题“世界上第三个把航天员送上太空的国家是中国。至今我国有多少名宇航员到太空去过”，按正常理解，从杨利伟开始，至少应该有6位宇航员到过太空，而本题却无此答案，学生失分在所难免。此外，第6小题学生的得分率也不是很高，应该缘于学生对青春期心理特点掌握得不全面、不准确。\r\n\r\n第四题，简要回答问题，总分24分，学生答题情况出现两极分化，较好的学生得分都在20分左右，较差的学生则只得了3、5分，甚至有几个学生得了0分，说明学生对知识的掌握还不牢固，对重要内容不能了然于胸。\r\n\r\n第五题，实验题，要求学生设计一个测量人的肺活量的实验方案,本题分值为6分。本题学生的得分率最低，相当多的学生只得了1、2分，而且还有个别学生没有得分，说明平时老师对实验教学重视的程度不够，从而使学生不知所云。\r\n\r\n针对本次答题情况，不难发现，教师在平常的教学过程中存在的最大失误就是对实验教学重视的程度远远不够，在以后的教学中要引以为诫，要引领学生通过各种手段、各种途径进行实验、探究，真正把知识学活、学透。此外，要采用各种措施，科学有效地抓好复习巩固环节，加强学生对基础知识的理解与掌握，使学生能够做到腹中有货、心里不慌。\r\n\r\n&nbsp;\r\n\r\n四、教学建议\r\n\r\n&nbsp;\r\n\r\n1、抓住双基，抓住教材重点，切实提高课堂教学效率。\r\n\r\n&nbsp;\r\n\r\n2、强化实验教学，引领学生通过各种手段、各种途径进行实验探究，真正把知识学活、学透。\r\n\r\n&nbsp;\r\n\r\n3、知识的复习巩固环节应引起足够的重视，使学生对相关知识点的掌握更牢固。\r\n\r\n&nbsp;\r\n\r\n4、对学生适当进行考试技巧训练，使他们在答题时能够发挥出正常的水平。\r\n\r\n&nbsp;', '科学试卷分析', '', 'publish', 'open', 'open', '', '%e7%a7%91%e5%ad%a6%e8%af%95%e5%8d%b7%e5%88%86%e6%9e%90', '', '', '2017-05-03 10:53:25', '2017-05-03 02:53:25', '', 0, 'http://bm.yangyongquan.com/?p=165', 0, 'post', '', 0),
