(247, 1, '2019-10-16 10:33:13', '2019-10-16 02:33:13', '<!-- wp:heading {"level":1} -->\n<h1><strong>普京访阿联酋获盛大欢迎：天上飞机拉线 地面骑兵护送</strong></h1>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>阿联酋出动特技飞行队和骑兵队护送普京（今日俄罗斯新闻网）</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>海外网10月16日电</strong>&nbsp;俄罗斯总统普京15日到访阿联酋，与阿联酋签下价值约14亿美元的新合同。而为了欢迎普京到访，阿联酋出动了特技飞行队和骑兵队，并在皇宫举行了盛大的欢迎仪式。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>据俄罗斯卫星通讯社15日报道，普京当天抵达阿布扎比后，在机场受到了阿联酋阿布扎比王储穆罕默德的欢迎。之后，他乘车穿过阿布扎比市中心，道路两旁挂满了俄罗斯国旗和阿联酋国旗。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:image -->\n<figure class="wp-block-image"><img src="https://himg2.huanqiucdn.cn/attachment2010/2019/1016/20191016072104858.jpg" alt="护送普京的骑兵队手持两国国旗（今日俄罗斯新闻网）"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p>护送普京的骑兵队手持两国国旗（今日俄罗斯新闻网）<br></p>\n<!-- /wp:paragraph -->', '普京访阿联酋获盛大欢迎：天上飞机拉线 地面骑兵护送', '', 'publish', 'open', 'open', '', '%e6%99%ae%e4%ba%ac%e8%ae%bf%e9%98%bf%e8%81%94%e9%85%8b%e8%8e%b7%e7%9b%9b%e5%a4%a7%e6%ac%a2%e8%bf%8e%ef%bc%9a%e5%a4%a9%e4%b8%8a%e9%a3%9e%e6%9c%ba%e6%8b%89%e7%ba%bf-%e5%9c%b0%e9%9d%a2%e9%aa%91%e5%85%b5', '', '', '2019-10-16 10:33:13', '2019-10-16 02:33:13', '', 0, 'http://bm.yangyongquan.com/?p=247', 0, 'post', '', 0);
INSERT INTO `wp_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES
(248, 1, '2019-10-16 10:33:13', '2019-10-16 02:33:13', '<!-- wp:heading {"level":1} -->\n<h1><strong>普京访阿联酋获盛大欢迎：天上飞机拉线 地面骑兵护送</strong></h1>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>阿联酋出动特技飞行队和骑兵队护送普京（今日俄罗斯新闻网）</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>海外网10月16日电</strong>&nbsp;俄罗斯总统普京15日到访阿联酋，与阿联酋签下价值约14亿美元的新合同。而为了欢迎普京到访，阿联酋出动了特技飞行队和骑兵队，并在皇宫举行了盛大的欢迎仪式。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>据俄罗斯卫星通讯社15日报道，普京当天抵达阿布扎比后，在机场受到了阿联酋阿布扎比王储穆罕默德的欢迎。之后，他乘车穿过阿布扎比市中心，道路两旁挂满了俄罗斯国旗和阿联酋国旗。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:image -->\n<figure class="wp-block-image"><img src="https://himg2.huanqiucdn.cn/attachment2010/2019/1016/20191016072104858.jpg" alt="护送普京的骑兵队手持两国国旗（今日俄罗斯新闻网）"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p>护送普京的骑兵队手持两国国旗（今日俄罗斯新闻网）<br></p>\n<!-- /wp:paragraph -->', '普京访阿联酋获盛大欢迎：天上飞机拉线 地面骑兵护送', '', 'inherit', 'closed', 'closed', '', '247-revision-v1', '', '', '2019-10-16 10:33:13', '2019-10-16 02:33:13', '', 247, 'http://bm.yangyongquan.com/2019/10/16/247-revision-v1/', 0, 'revision', '', 0);
